// Dedicated diagnostic-only question bank. Separate from concept-drills so the
// Diagnostic Review tab never repeats the same questions a user sees in drills.
// Tracks not present here fall back to the drill pool in page.tsx.

export type DiagTrack = { title: string; categories: string[]; questions: DrillQ[] };

const IB_DIAG: DrillQ[] = [
{q:"A firm reports net income of 200. Depreciation was 60, capex was 90, accounts receivable rose 25, inventory fell 15, and accounts payable fell 10. What is cash flow from operations?",options:["150","280","240","180"],correct:2,explanation:"CFO = NI 200 + D&A 60 - AR increase 25 + inventory decrease 15 - AP decrease 10 = 240. AR up is a use (subtract), inventory down is a source (add), AP down is a use (subtract). 150 wrongly subtracts the 90 capex, which is investing not CFO. 280 flips all working capital signs. 180 forgets to add back D&A.",difficulty:"hard",topic:"Accounting"},
{q:"Equipment costing 100 is bought for cash, depreciated straight-line over 10 years, tax rate 25%. Ignoring all else, what is the net change in cash in year 1?",options:["-92.5","-90.0","-97.5","-100.0"],correct:2,explanation:"Year 1 cash = -100 capex + depreciation tax shield. Depreciation = 10, shield = 10 x 25% = 2.5, so net = -97.5. -100.0 ignores the shield. -90.0 adds back the full 10 of depreciation as if it were cash. -92.5 adds back after-tax depreciation of 7.5 instead of just the 2.5 shield.",difficulty:"hard",topic:"Accounting"},
{q:"A company writes down inventory by 40 (pretax). Tax rate is 30%. What is the immediate impact on total cash across the cash flow statement?",options:["0","-28","-40","+12"],correct:0,explanation:"A writedown is non-cash. Net income falls by 40 x 0.70 = 28, but that plus the 12 tax effect are added back as non-cash, so total cash is unchanged at 0. -40 treats it as a cash outflow. -28 stops at the after-tax NI hit. +12 captures only the tax piece.",difficulty:"hard",topic:"Accounting"},
{q:"A firm has pretax income of 500 before a 120 goodwill impairment that is not tax deductible. The statutory rate is 25%. What is reported net income?",options:["375","275","255","285"],correct:2,explanation:"Tax is computed on the full 500 because the impairment is non-deductible: tax = 125. NI = 500 - 120 impairment - 125 tax = 255. 285 wrongly treats the impairment as deductible (taxes 380). 375 omits the impairment entirely. 275 applies a 21% rate instead of the stated 25%.",difficulty:"hard",topic:"Accounting"},
{q:"A company issues 100 of debt at 8% interest, tax rate 25%. What is the year-1 impact on net income and on cash flow from operations, respectively?",options:["-6 and -6","-8 and -6","-8 and -8","-6 and -8"],correct:0,explanation:"Interest = 8, after tax 8 x 0.75 = 6. Net income falls 6. CFO starts from net income and interest paid is operating, so CFO also falls 6. The -8 answers use pretax interest; the mixed answers split NI and CFO inconsistently.",difficulty:"hard",topic:"Accounting"},
{q:"Deferred revenue rises by 30 during the year, with the cash collected upfront. Tax rate 25%. All else equal, what is the impact on cash flow from operations?",options:["+22.5","-30","+7.5","+30"],correct:3,explanation:"Cash was collected but not yet recognized, so deferred revenue (a liability) rising 30 is a source: CFO +30. The full 30 hits CFO because the cash already arrived, regardless of tax. +22.5 wrongly tax-effects it. -30 flips the sign. +7.5 captures only a tax fragment.",difficulty:"hard",topic:"Accounting"},
{q:"A firm capitalizes 50 of software development that prior policy expensed. Tax rate 30%. In the year of the change, what happens to net income and to total cash flow?",options:["NI up 50, cash up 50","NI unchanged, cash up 15","NI up 35, cash up 35","NI up 35, cash unchanged"],correct:3,explanation:"Capitalizing removes 50 from the income statement, raising pretax income 50 and NI by 50 x 0.70 = 35. Total cash is unchanged: the 50 moves from operating expense to investing capex, netting to zero. NI up 50 ignores tax. The cash-up answers forget the offsetting capex outflow.",difficulty:"hard",topic:"Accounting"},
{q:"Beginning retained earnings 400, net income 120, dividends declared 30 (10 still unpaid at year end). What is ending retained earnings?",options:["510","490","500","520"],correct:1,explanation:"RE = 400 + 120 - 30 declared = 490. Dividends reduce RE when declared, not when paid, so all 30 counts. 500 subtracts only the 20 already paid. 510 subtracts only the 10 unpaid. 520 ignores dividends entirely.",difficulty:"hard",topic:"Accounting"},
{q:"A company has EBIT of 300, interest expense of 50, interest income of 20, tax rate 25%. What is net income?",options:["240.0","187.5","172.5","202.5"],correct:3,explanation:"Pretax = 300 - 50 + 20 = 270; NI = 270 x 0.75 = 202.5. 187.5 omits interest income (250 base). 172.5 wrongly treats interest income as an expense (230 base). 240.0 omits interest expense (320 base).",difficulty:"hard",topic:"Accounting"},
{q:"Gross PP&E rises from 800 to 950, accumulated depreciation rises from 300 to 360, and depreciation expense was 90. There were no asset sales. What was capex?",options:["90","60","240","150"],correct:3,explanation:"With no disposals, capex = change in gross PP&E = 950 - 800 = 150. 240 adds depreciation expense to the gross change. 90 uses depreciation expense (or the net PP&E change) instead of capex. 60 uses the accumulated depreciation change.",difficulty:"hard",topic:"Accounting"},
{q:"A firm prepays 24 of insurance covering 12 months. After 4 months, what is the prepaid asset balance and the cumulative expense recognized?",options:["Prepaid 8, expense 16","Prepaid 16, expense 8","Prepaid 20, expense 4","Prepaid 24, expense 0"],correct:1,explanation:"Monthly expense = 24/12 = 2. After 4 months expense = 8, prepaid = 24 - 8 = 16. The reversed answer swaps the two. Prepaid 20 expenses only one month. Prepaid 24 recognizes nothing.",difficulty:"hard",topic:"Accounting"},
{q:"Under LIFO with rising prices a firm reports COGS of 700 and ending inventory of 200. The LIFO reserve grew from 50 to 90. What would COGS be under FIFO?",options:["660","740","700","650"],correct:0,explanation:"FIFO COGS = LIFO COGS - increase in LIFO reserve = 700 - 40 = 660. Rising prices make LIFO COGS higher, so FIFO is lower. 740 adds the change. 650 subtracts the full ending reserve. 700 ignores the adjustment.",difficulty:"hard",topic:"Accounting"},
{q:"A company sells a machine with book value 40 for 55 cash. Tax rate 25%. What is the impact on net income and the cash inflow recorded from the sale?",options:["NI up 11.25, cash 51.25","NI up 15, cash 51.25","NI up 15, cash 55","NI up 11.25, cash 55"],correct:3,explanation:"Gain = 55 - 40 = 15 pretax, after tax 15 x 0.75 = 11.25 added to NI. The cash inflow from the sale is the full 55 (investing). NI up 15 ignores tax. The 51.25 answers wrongly net the tax against proceeds; tax is paid within the total tax line.",difficulty:"hard",topic:"Accounting"},
{q:"A firm has accounts receivable of 300 and an allowance for doubtful accounts of 20. It writes off 12 of specific bad debt. What is net AR after the writeoff?",options:["292","288","280","268"],correct:2,explanation:"A writeoff cuts both gross AR (to 288) and the allowance (to 8), so net AR = 280, unchanged from the prior net of 280. 288 forgets the allowance. 268 double counts the writeoff. 292 nets the wrong way.",difficulty:"hard",topic:"Accounting"},
{q:"A company records 60 of stock-based compensation expense, tax rate 25%. What is the impact on net income and on cash flow from operations?",options:["NI -60, CFO unchanged","NI -60, CFO -60","NI -45, CFO unchanged","NI -45, CFO -45"],correct:2,explanation:"SBC cuts pretax income 60, NI by 60 x 0.75 = 45. SBC is non-cash and added back, so CFO is unchanged. NI -60 ignores tax. The CFO -45 and -60 answers forget the add-back.",difficulty:"hard",topic:"Accounting"},
{q:"Year-end cash 120, short-term debt 80, current assets excluding cash 300, current liabilities excluding debt 150. What is the current ratio?",options:["1.30","1.83","2.80","2.00"],correct:1,explanation:"Current assets = 120 + 300 = 420; current liabilities = 80 + 150 = 230; ratio = 1.83. 1.30 omits cash from assets. 2.80 omits short-term debt from liabilities. 2.00 omits both.",difficulty:"hard",topic:"Accounting"},
{q:"Consolidated net income is 250, of which 30 is attributable to noncontrolling interest. What net income figure is used in the parent's diluted EPS?",options:["235","280","220","250"],correct:2,explanation:"EPS uses net income attributable to the parent = 250 - 30 = 220. 250 uses consolidated NI, which still includes NCI. 280 adds NCI back. 235 splits the NCI incorrectly.",difficulty:"hard",topic:"Accounting"},
{q:"A firm has foreign operations whose cumulative translation adjustment falls 15 this year. Where does the 15 appear, and does it hit net income?",options:["OCI in equity, not net income","Net income, reduces EPS","Cash flow from financing","Below the line as extraordinary"],correct:0,explanation:"Translation adjustments flow through other comprehensive income within equity and bypass net income, so EPS is unaffected. The other choices wrongly route it through the income statement, a removed classification, or financing cash flow.",difficulty:"hard",topic:"Accounting"},
{q:"EBITDA is 400, D&A is 120, interest is 60, tax rate 25%, the increase in net working capital is 40, and capex is 90. What is unlevered free cash flow?",options:["200","165","270","240"],correct:0,explanation:"Unlevered FCF ignores interest. EBIT = 400 - 120 = 280; NOPAT = 280 x 0.75 = 210; uFCF = 210 + 120 - 90 - 40 = 200. 240 forgets the NWC use. 270 forgets taxes. 165 wrongly subtracts interest, which gives a levered figure.",difficulty:"hard",topic:"Accounting"},
{q:"A firm buys back 10 shares at 50 each for cash, funded by drawing 500 of new debt at 6%, tax rate 25%. Pre-buyback net income was 300 on 100 shares. What is new EPS?",options:["3.00","3.08","3.33","2.77"],correct:1,explanation:"New interest = 500 x 6% = 30, after tax 22.5. New NI = 300 - 22.5 = 277.5; shares = 90; EPS = 3.08. 2.77 forgets the share reduction (277.5/100). 3.00 uses pretax interest (270/90). 3.33 ignores interest entirely (300/90).",difficulty:"hard",topic:"Accounting"},
{q:"Days sales outstanding is 45, days inventory outstanding is 60, days payable outstanding is 30. What is the cash conversion cycle?",options:["15 days","105 days","135 days","75 days"],correct:3,explanation:"CCC = DSO 45 + DIO 60 - DPO 30 = 75 days. 135 adds DPO instead of subtracting. 105 omits DPO entirely. 15 omits DIO.",difficulty:"hard",topic:"Accounting"},
{q:"A firm has a deferred tax liability that arose because tax depreciation exceeded book depreciation. As the assets fully depreciate and the gap reverses, what happens to cash taxes versus book taxes?",options:["Cash taxes exceed book taxes","Both fall to zero","Cash taxes below book taxes","No difference in reversal"],correct:0,explanation:"The DTL formed when tax depreciation was higher, deferring tax. On reversal, book depreciation exceeds tax depreciation, so taxable income exceeds book income and cash taxes are higher than book taxes as the DTL unwinds. The others misread the direction.",difficulty:"hard",topic:"Accounting"},
{q:"An operating lease of 12 per year is capitalized over 5 years at a 4% discount rate, payments at year end. What is the initial lease liability?",options:["60.0","53.4","55.0","47.9"],correct:1,explanation:"PV of 12 per year for 5 years at 4% = 12 x 4.4518 = 53.4. 60.0 ignores discounting. 55.0 uses a 3% rate. 47.9 uses an 8% rate.",difficulty:"hard",topic:"Accounting"},
{q:"A company has EBIT 200 including a one-time restructuring charge of 30, tax rate 25%. What is normalized (adjusted) net income excluding the charge?",options:["180.0","172.5","150.0","230.0"],correct:1,explanation:"Adjusted EBIT = 200 + 30 = 230, after tax 230 x 0.75 = 172.5. 150.0 leaves the charge in (200 x 0.75). 180.0 adds the full pretax charge to after-tax NI without tax-effecting the add-back. 230.0 is adjusted EBIT with no tax applied.",difficulty:"hard",topic:"Accounting"},
{q:"Net income is 100, cash interest paid 90, D&A 40, working capital increased 20, and dividends paid 15. Under US GAAP, what is cash flow from operations?",options:["135","100","120","105"],correct:2,explanation:"CFO = NI 100 + D&A 40 - WC increase 20 = 120. Interest paid is already in NI under GAAP, and dividends are financing. 105 wrongly subtracts dividends. 135 wrongly adds dividends back as a source. 100 ignores both the D&A add-back and the WC change.",difficulty:"hard",topic:"Accounting"},
{q:"A company recognizes 200 of revenue but has collected only 130 in cash, with the rest in receivables. COGS is 120, all paid in cash. What is the gross margin and the pretax cash impact?",options:["40% margin, +80 cash","40% margin, +10 cash","35% margin, +10 cash","40% margin, -10 cash"],correct:1,explanation:"Gross margin = (200 - 120)/200 = 40%. Pretax cash = 130 collected - 120 paid = +10. +80 uses recognized revenue minus cash COGS. 35% miscomputes margin. -10 flips the cash sign.",difficulty:"hard",topic:"Accounting"},
{q:"A parent owns 80% of a sub that earns 50 net income. The parent's standalone net income is 200. What are consolidated net income and net income attributable to the parent?",options:["250 and 250","250 and 210","250 and 240","240 and 240"],correct:2,explanation:"Consolidation brings in 100% of the sub: consolidated NI = 250. NCI takes 20% x 50 = 10, so parent attribution = 240. The second answer ignores NCI. The third double counts. The fourth subtracts 80% rather than 20%.",difficulty:"hard",topic:"Accounting"},
{q:"A bond is issued at a discount: face 1000, proceeds 950, 5-year term, 4% annual coupon. Using straight-line amortization, what is year-1 interest expense?",options:["40","45","60","50"],correct:3,explanation:"Cash coupon = 40; discount amortization = 50/5 = 10; interest expense = 50. 40 ignores the discount. 60 amortizes 20 per year. 45 amortizes the discount over 10 years.",difficulty:"hard",topic:"Accounting"},
{q:"A firm has 100 shares and net income of 200. It has 20 options at a 30 strike; the current price is 50. Using the treasury stock method, what is diluted EPS?",options:["1.90","1.67","2.00","1.85"],correct:3,explanation:"TSM: proceeds = 20 x 30 = 600; shares repurchased = 600/50 = 12; net new = 8; diluted shares = 108; EPS = 200/108 = 1.85. 2.00 ignores the options. 1.67 counts all 20 as new shares. 1.90 repurchases at an average price of 40 instead of the market price of 50.",difficulty:"hard",topic:"Accounting"},
{q:"A company has total liabilities of 600 and equity of 400, with prior debt of 400. It repurchases 100 of stock funded entirely by new debt. What is the resulting debt-to-equity ratio?",options:["1.25","1.50","2.33","1.67"],correct:3,explanation:"Debt rises to 500, equity falls to 300, D/E = 500/300 = 1.67. 1.50 uses pre-deal total liabilities 600 over equity 400. 1.25 keeps equity at 400. 2.33 uses total liabilities after (700) over equity 300 rather than debt.",difficulty:"hard",topic:"Accounting"},
{q:"A company has enterprise value of 1200, total debt 400, cash 50, preferred stock 30, and noncontrolling interest 20. What is equity value?",options:["750","800","850","700"],correct:1,explanation:"Equity = EV - debt + cash - preferred - NCI = 1200 - 400 + 50 - 30 - 20 = 800. 750 uses gross debt and forgets to add cash. 850 adds cash but omits preferred and NCI. 700 subtracts cash instead of adding it.",difficulty:"hard",topic:"Valuation"},
{q:"A company has equity value of 900, total debt 250, cash 80, and noncontrolling interest 40. What is enterprise value?",options:["1110","1270","1070","1030"],correct:0,explanation:"EV = equity + debt - cash + NCI = 900 + 250 - 80 + 40 = 1110. 1030 subtracts NCI instead of adding. 1270 adds cash. 1070 omits NCI.",difficulty:"hard",topic:"Valuation"},
{q:"Risk-free rate 4%, equity risk premium 6%, levered beta 1.3. What is the cost of equity under CAPM?",options:["10.0%","11.8%","6.6%","13.0%"],correct:1,explanation:"ke = rf + beta x ERP = 4 + 1.3 x 6 = 11.8%. 13.0% applies beta to the whole 10% (rf plus ERP). 10.0% drops beta. 6.6% treats 6% as the market return and uses a 2% premium.",difficulty:"hard",topic:"Valuation"},
{q:"Equity 600 at a 12% cost, debt 400 at a 7% pretax cost, tax rate 25%. What is WACC?",options:["10.0%","9.3%","8.6%","7.5%"],correct:1,explanation:"Weights: E 0.6, D 0.4; after-tax kd = 7 x 0.75 = 5.25. WACC = 0.6 x 12 + 0.4 x 5.25 = 9.3%. 10.0% omits the tax shield. 8.6% uses equal 50/50 weights. 7.5% wrongly tax-affects the equity cost too.",difficulty:"hard",topic:"Valuation"},
{q:"A comparable has levered beta 1.5, debt-to-equity of 0.8, tax rate 25%. What is its unlevered (asset) beta?",options:["0.94","0.83","0.60","0.75"],correct:0,explanation:"Bu = BL / (1 + (1-t) x D/E) = 1.5 / (1 + 0.75 x 0.8) = 1.5/1.6 = 0.94. 0.83 ignores the (1-t) term. 0.75 uses (1+t) instead of (1-t). 0.60 multiplies by the factor instead of dividing.",difficulty:"hard",topic:"Valuation"},
{q:"Asset (unlevered) beta is 0.9, target debt-to-equity 1.0, tax rate 25%. What is the relevered equity beta?",options:["0.51","1.80","2.02","1.57"],correct:3,explanation:"BL = Bu x (1 + (1-t) x D/E) = 0.9 x (1 + 0.75) = 1.57. 1.80 ignores the tax term. 0.51 divides instead of multiplying. 2.02 uses (1+t) instead of (1-t).",difficulty:"hard",topic:"Valuation"},
{q:"Year-5 free cash flow is 100, terminal growth 3%, WACC 9%. What is the terminal value at the end of year 5 (undiscounted)?",options:["1666.7","1716.7","858.3","833.3"],correct:1,explanation:"TV = FCF5 x (1+g)/(WACC-g) = 100 x 1.03 / 0.06 = 1716.7. 1666.7 omits the (1+g) in the numerator. 858.3 uses WACC+g in the denominator. 833.3 makes both errors.",difficulty:"hard",topic:"Valuation"},
{q:"A terminal value of 1700 sits at the end of year 5. With a WACC of 9%, what is its present value today using end-of-period discounting?",options:["1204.3","1104.9","1172.4","1013.7"],correct:1,explanation:"PV = 1700 / 1.09^5 = 1104.9. 1204.3 discounts only 4 years (off by one). 1013.7 discounts 6 years. 1172.4 uses simple interest (divide by 1.45).",difficulty:"hard",topic:"Valuation"},
{q:"Year-5 EBITDA is 250 and the exit EV/EBITDA multiple is 8x. WACC 10%. What is the present value of the terminal value, discounting 5 years end-of-period?",options:["1366.0","2000.0","1241.8","1128.9"],correct:2,explanation:"TV = 250 x 8 = 2000; PV = 2000 / 1.1^5 = 1241.8. 1366.0 discounts only 4 years. 2000.0 forgets to discount. 1128.9 discounts 6 years.",difficulty:"hard",topic:"Valuation"},
{q:"EBIT 300, tax rate 25%, D&A 80, capex 90, increase in NWC 20. What is unlevered free cash flow?",options:["175","235","270","195"],correct:3,explanation:"uFCF = EBIT x (1-t) + D&A - capex - increase in NWC = 225 + 80 - 90 - 20 = 195. 175 tax-affects EBITDA by taxing (EBIT+D&A). 270 forgets taxes. 235 flips the NWC sign.",difficulty:"hard",topic:"Valuation"},
{q:"A single cash flow of 100 arrives in year 3. WACC 10%. Under the mid-year convention, what is its present value?",options:["78.8","82.6","75.1","71.6"],correct:0,explanation:"Mid-year discounts at 2.5 periods: 100 / 1.1^2.5 = 78.8. 75.1 uses the full year 3 (no mid-year). 82.6 discounts only 2 years. 71.6 over-discounts at 3.5 periods.",difficulty:"hard",topic:"Valuation"},
{q:"Equity value 1500, total debt 600, cash 200, LTM EBITDA 250. What is EV/EBITDA?",options:["8.4x","6.0x","4.4x","7.6x"],correct:3,explanation:"EV = 1500 + 600 - 200 = 1900; EV/EBITDA = 7.6x. 8.4x forgets to subtract cash. 6.0x uses equity value, not EV. 4.4x subtracts debt and adds cash.",difficulty:"hard",topic:"Valuation"},
{q:"A company has an EV of 1800. LTM EBITDA is 240; next-year EBITDA is 300. What are the trailing and forward EV/EBITDA?",options:["7.5x trailing, 7.5x forward","7.5x trailing, 6.0x forward","6.0x trailing, 6.0x forward","6.0x trailing, 7.5x forward"],correct:1,explanation:"Trailing = 1800/240 = 7.5x; forward = 1800/300 = 6.0x. The first wrong answer swaps the two. The others use one period for both.",difficulty:"hard",topic:"Valuation"},
{q:"A stock trades at 60. Trailing EPS is 3.00 and next-year EPS is 4.00. What are the trailing and forward P/E?",options:["15x trailing, 20x forward","20x trailing, 20x forward","15x trailing, 15x forward","20x trailing, 15x forward"],correct:3,explanation:"Trailing = 60/3 = 20x; forward = 60/4 = 15x. The first wrong answer swaps them. The others apply one EPS to both.",difficulty:"hard",topic:"Valuation"},
{q:"A stock will pay a 2.10 dividend next year, dividends grow 4%, cost of equity 9%. What is the implied price under the Gordon growth model?",options:["43.7","16.2","42.0","23.3"],correct:2,explanation:"P = D1/(r-g) = 2.10/0.05 = 42.0. 43.7 grows D1 again (treats it as D0). 16.2 uses r+g in the denominator. 23.3 omits growth and divides by r only.",difficulty:"hard",topic:"Valuation"},
{q:"Net income 150, D&A 60, capex 80, increase in NWC 15, mandatory net debt repayment 25. What is free cash flow to equity?",options:["115","140","90","105"],correct:2,explanation:"FCFE = NI + D&A - capex - increase in NWC - net debt repayment = 150 + 60 - 80 - 15 - 25 = 90. 140 adds the debt repayment. 115 omits it. 105 omits the NWC change.",difficulty:"hard",topic:"Valuation"},
{q:"Free cash flows are 100, 110, and 121 in years 1 to 3, then a terminal value of 1500 at the end of year 3. WACC 10%. What is enterprise value today?",options:["1512.4","1458.0","1772.7","1399.7"],correct:3,explanation:"PV of FCFs = 90.9 + 90.9 + 90.9 = 272.7; PV of TV = 1500/1.331 = 1127.0; EV = 1399.7. 1772.7 forgets to discount the TV. 1512.4 discounts the TV only 2 years. 1458.0 leaves the FCFs undiscounted.",difficulty:"hard",topic:"Valuation"},
{q:"A company is valued at 9.0x its EBITDA of 200. It has net debt of 350. What is the implied equity value?",options:["1800","1450","2150","1100"],correct:1,explanation:"EV = 9.0 x 200 = 1800; equity = EV - net debt = 1450. 2150 adds net debt. 1800 forgets net debt. 1100 subtracts net debt twice.",difficulty:"hard",topic:"Valuation"},
{q:"A firm's bonds yield 6.5%. The marginal tax rate is 25%. What is the after-tax cost of debt?",options:["6.50%","4.88%","1.62%","8.12%"],correct:1,explanation:"After-tax kd = 6.5 x (1 - 0.25) = 4.88%. 6.50% forgets the tax shield. 1.62% multiplies by the tax rate instead of one minus it. 8.12% grosses up by 1.25.",difficulty:"hard",topic:"Valuation"},
{q:"Capital structure: equity 500 (cost 13%), debt 300 (pretax cost 8%), preferred 200 (cost 9%), tax rate 25%. What is WACC?",options:["10.25%","10.1%","9.65%","10.7%"],correct:1,explanation:"Weights on 1000: E 0.5, D 0.3, P 0.2; after-tax kd = 6%. WACC = 0.5 x 13 + 0.3 x 6 + 0.2 x 9 = 10.1%. 10.7% omits the debt tax shield. 9.65% wrongly tax-affects preferred. 10.25% tax-affects preferred instead of debt.",difficulty:"hard",topic:"Valuation"},
{q:"Four comparable EV/EBITDA multiples are 6.0x, 7.5x, 9.0x, and 13.5x. Using the median multiple on the target's EBITDA of 200, what is implied EV?",options:["1700","1650","1500","1800"],correct:1,explanation:"Median = (7.5 + 9.0)/2 = 8.25x; EV = 8.25 x 200 = 1650. 1800 uses the mean (9.0x), which the 13.5x outlier inflates. 1500 uses only the lower middle multiple. 1700 mis-averages the middle pair to 8.5x.",difficulty:"hard",topic:"Valuation"},
{q:"A company issues 200 of new debt and holds the cash on its balance sheet, with no acquisition and no buyback. Ignoring tax and interest at the instant of issuance, what happens to enterprise value?",options:["Unchanged","Falls by 200","Rises by 150","Rises by 200"],correct:0,explanation:"Debt rises 200 and cash rises 200, so net debt and therefore EV are unchanged. Rises by 200 counts the debt but ignores the offsetting cash. Falls by 200 has the sign backward. Rises by 150 wrongly tax-affects a non-event.",difficulty:"hard",topic:"Valuation"},
{q:"During the year accounts receivable rises 30, inventory rises 10, and accounts payable rises 25. What is the change in net working capital and its effect on free cash flow?",options:["NWC up 15, FCF higher by 15","NWC up 15, FCF lower by 15","NWC up 65, FCF lower by 65","NWC down 15, FCF higher by 15"],correct:1,explanation:"NWC = current operating assets minus current operating liabilities. It rises (30 + 10) - 25 = 15, a use of cash, so FCF is 15 lower. The 65 answer treats rising AP as a use. The down-15 answer flips the AP sign. The last keeps the right NWC but the wrong cash sign.",difficulty:"hard",topic:"Valuation"},
{q:"A stock has a forward P/E of 18 and expected EPS growth of 12%. What is its PEG ratio?",options:["1.50","6.00","0.67","2.16"],correct:0,explanation:"PEG = P/E divided by the growth rate in percentage points = 18/12 = 1.50. 0.67 inverts it. 2.16 multiplies. 6.00 subtracts.",difficulty:"hard",topic:"Valuation"},
{q:"A stock trades at 50, pays a next-year dividend of 2.50, and dividends grow 5%. What is the implied cost of equity?",options:["5.0%","10.0%","0.0%","15.0%"],correct:1,explanation:"ke = D1/P + g = 2.50/50 + 5% = 5% + 5% = 10.0%. 5.0% forgets to add g. 0.0% subtracts g from the yield. 15.0% double-counts growth.",difficulty:"hard",topic:"Valuation"},
{q:"A holding company owns Segment A (EBITDA 100 at 8x) and Segment B (EBITDA 50 at 6x). Net debt is 200. What is the implied equity value?",options:["1300","1000","1100","900"],correct:3,explanation:"EV = 100 x 8 + 50 x 6 = 1100; equity = 1100 - 200 = 900. 1100 forgets net debt. 1300 adds net debt. 1000 applies 8x to both segments before subtracting debt.",difficulty:"hard",topic:"Valuation"},
{q:"EBITDA is 500, capex is 120, and the increase in net working capital is 30. What is pre-tax free cash flow as a percentage of EBITDA (FCF conversion)?",options:["70%","94%","76%","82%"],correct:0,explanation:"FCF = 500 - 120 - 30 = 350; conversion = 350/500 = 70%. 76% omits the NWC use. 94% omits capex. 82% flips the NWC sign.",difficulty:"hard",topic:"Valuation"},
{q:"Total debt 400, finance leases 60, cash 90, short-term investments 30. What is net debt?",options:["250","280","340","370"],correct:2,explanation:"Net debt = 400 + 60 leases - 90 cash - 30 investments = 340. 280 omits leases. 370 omits the short-term investments. 250 subtracts the leases instead of adding them.",difficulty:"hard",topic:"Valuation"},
{q:"For WACC, a company has book equity of 300 but a market capitalization of 900, and debt with book and market value of 400. Which weights are correct?",options:["Book equity with market debt at par","Book: 300 equity, 400 debt","Market: 900 equity, 400 debt","Equal 50/50 weights"],correct:2,explanation:"WACC uses market-value weights, so equity 900 and debt 400. Book equity understates the equity weight. Equal weights ignore the actual capital mix. Mixing book equity with market debt is internally inconsistent.",difficulty:"hard",topic:"Valuation"},
{q:"A DCF uses an exit EV/EBITDA of 9x on year-5 EBITDA with WACC 10%, and year-5 free cash flow equals 60% of year-5 EBITDA. Setting TV = FCF5 x (1+g)/(WACC-g) equal to 9x EBITDA, what perpetuity growth does 9x imply?",options:["3.1%","3.3%","-1.0%","-3.6%"],correct:0,explanation:"0.6(1+g)/(0.10-g) = 9 solves to g = 3.1%. 3.3% drops the (1+g) numerator. -3.6% uses WACC+g in the denominator. -1.0% sets FCF equal to EBITDA, ignoring the 60% conversion.",difficulty:"hard",topic:"Valuation"},
{q:"A company has EV of 1600, EBITDA of 200, and D&A of 40. What are EV/EBITDA and EV/EBIT?",options:["8.0x and 10.0x","10.0x and 8.0x","8.0x and 8.0x","8.0x and 6.7x"],correct:0,explanation:"EBIT = 200 - 40 = 160; EV/EBITDA = 1600/200 = 8.0x; EV/EBIT = 1600/160 = 10.0x. The first wrong answer swaps them. 6.7x adds D&A to EBITDA for the denominator. The last uses EBITDA for both.",difficulty:"hard",topic:"Valuation"},
{q:"Acquirer has net income 500 and 100 shares (EPS 5.00). It buys a target with net income 80 for 600 of cash that was earning 3% pretax interest, tax rate 25%. What is pro forma EPS?",options:["5.62","5.93","5.67","5.80"],correct:2,explanation:"Forgone after-tax interest = 600 x 3% x 0.75 = 13.5. PF NI = 500 + 80 - 13.5 = 566.5; shares 100; EPS = 5.67. 5.62 uses pretax forgone interest (18). 5.80 ignores forgone interest. 5.93 adds the interest as income instead of subtracting it.",difficulty:"hard",topic:"M&A"},
{q:"Acquirer net income 200 on 100 shares (EPS 2.00), stock at 40. It issues stock at 40 to fund a 600 all-stock purchase of a target with net income 60, no synergies. What is pro forma EPS?",options:["1.74","2.60","2.26","2.36"],correct:2,explanation:"New shares = 600/40 = 15; PF NI = 200 + 60 = 260; PF shares = 115; EPS = 2.26 (accretive vs 2.00). 2.60 forgets the new shares. 1.74 forgets the target's net income. 2.36 issues only 10 shares using a 60 price.",difficulty:"hard",topic:"M&A"},
{q:"An acquirer with a P/E of 18 acquires a target at an effective P/E of 14 in an all-stock deal at those multiples, no synergies. Is the deal accretive or dilutive to EPS?",options:["Neutral","Depends on the tax rate","Dilutive","Accretive"],correct:3,explanation:"In an all-stock deal, the acquirer is accretive when its P/E exceeds the target's P/E (18 vs 14), because it pays in expensive shares for cheaper earnings. Dilutive and neutral reverse or ignore the multiple relationship. The result here does not hinge on the tax rate.",difficulty:"hard",topic:"M&A"},
{q:"An all-cash deal acquires a target at a 12.5x P/E (an 8% earnings yield). The acquirer funds it with debt at a 5% pretax rate, tax rate 20%. Is the deal accretive?",options:["Dilutive","Neutral","Accretive","Cannot tell without EPS"],correct:2,explanation:"After-tax cost of debt = 5% x 0.80 = 4%. The target's earnings yield of 8% exceeds the 4% after-tax financing cost, so the deal is accretive. The other answers ignore the yield-versus-cost comparison.",difficulty:"hard",topic:"M&A"},
{q:"An acquirer pays 1000 for a target with book equity 300. Intangibles are written up 120 and PP&E 80, and a 50 deferred tax liability is created on the write-ups. What goodwill is recorded?",options:["700","450","550","500"],correct:2,explanation:"Goodwill = price - (book equity + write-ups - DTL) = 1000 - (300 + 200 - 50) = 550. 500 ignores the DTL. 700 ignores the write-ups. 450 adds the DTL instead of subtracting it.",difficulty:"hard",topic:"M&A"},
{q:"A write-up creates 200 of new intangibles amortized over 10 years and 100 of PP&E write-up depreciated over 5 years, tax rate 25%. What is the annual after-tax hit to pro forma net income from the incremental D&A?",options:["40","37.5","30","15"],correct:2,explanation:"Incremental D&A = 200/10 + 100/5 = 40; after tax 40 x 0.75 = 30. 40 forgets the tax shield. 15 counts only the intangibles. 37.5 swaps the two useful lives.",difficulty:"hard",topic:"M&A"},
{q:"An all-stock deal: acquirer net income 400 on 100 shares (EPS 4.00) issues 20 new shares to buy a target contributing 30 of net income. What after-tax synergies are needed to keep pro forma EPS at 4.00?",options:["70","50","20","30"],correct:1,explanation:"PF shares = 120; EPS-neutral NI = 4.00 x 120 = 480; standalone + target = 430; synergies = 50. 30 solves against the old 100 shares. 70 uses 125 shares. 20 double counts part of the target's NI.",difficulty:"hard",topic:"M&A"},
{q:"A target trades at 30 per share. The acquirer offers 37.50 per share. What is the premium?",options:["7.5%","30%","20%","25%"],correct:3,explanation:"Premium = (37.50 - 30)/30 = 25%. 20% divides the spread by the offer price. 30% reads the spread as a percent of 25. 7.5% reports the absolute spread.",difficulty:"hard",topic:"M&A"},
{q:"An all-stock deal offers target holders 38 per share in acquirer stock. The acquirer trades at 95. What is the exchange ratio (acquirer shares per target share)?",options:["0.38","0.40","2.50","0.50"],correct:1,explanation:"Exchange ratio = 38/95 = 0.40. 2.50 inverts it. 0.50 rounds incorrectly. 0.38 uses the offer value as if the acquirer traded at 100.",difficulty:"hard",topic:"M&A"},
{q:"An acquirer offers an exchange ratio of 0.5 for each of the target's 80 million shares; the acquirer has 200 million shares. What percentage of the pro forma company will former target holders own?",options:["16.7%","20.0%","14.3%","33.3%"],correct:0,explanation:"New shares = 0.5 x 80 = 40M; PF shares = 240M; target holders = 40/240 = 16.7%. 20.0% uses the acquirer base of 200M only. 33.3% ignores the exchange ratio (uses 80M). 14.3% adds 80M new shares instead of 40M.",difficulty:"hard",topic:"M&A"},
{q:"In a merger sized by net income contribution, Company A contributes 120 and Company B contributes 80. If the combined entity has 200 million shares, how many should Company A's holders receive?",options:["133M","100M","120M","80M"],correct:2,explanation:"A's share = 120/(120+80) = 60%; shares = 0.60 x 200 = 120M. 80M uses B's contribution. 100M assumes a 50/50 split. 133M applies a 2:1 ratio.",difficulty:"hard",topic:"M&A"},
{q:"Acquirer net income 600 on 150 shares (EPS 4.00) buys a target with 90 net income for cash, financed with 800 of debt at 6% pretax, tax rate 25%, plus 40 of pretax synergies. What is pro forma EPS?",options:["4.63","4.56","4.36","4.48"],correct:1,explanation:"After-tax interest = 800 x 6% x 0.75 = 36; after-tax synergies = 40 x 0.75 = 30. PF NI = 600 + 90 - 36 + 30 = 684; shares 150; EPS = 4.56. 4.63 forgets to tax the synergies. 4.48 forgets to tax the interest. 4.36 omits synergies.",difficulty:"hard",topic:"M&A"},
{q:"In a taxable asset acquisition versus a stock acquisition, what is the buyer's key tax advantage?",options:["Stepped-up basis gives extra tax-deductible D&A","Net operating losses always carry over","No goodwill is created","A lower control premium is required"],correct:0,explanation:"An asset deal steps up the basis of acquired assets, creating incremental tax-deductible depreciation and amortization. NOLs generally do not transfer in an asset deal, goodwill can still arise, and the premium is unrelated to deal structure.",difficulty:"hard",topic:"M&A"},
{q:"A target has 200 of net operating losses usable against income taxed at 25%. Ignoring Section 382 limits and time value, what is the cash tax value of the NOLs?",options:["200","40","150","50"],correct:3,explanation:"Value = 200 x 25% = 50 of tax saved. 200 is the face amount, not the cash benefit. 150 multiplies by (1-t). 40 uses a 20% rate.",difficulty:"hard",topic:"M&A"},
{q:"Standalone EPS is 3.00 and pro forma EPS is 3.30. What is the accretion?",options:["9.1%","10.0%","30.0%","11.1%"],correct:1,explanation:"Accretion = (3.30 - 3.00)/3.00 = 10.0%. 9.1% divides by the pro forma EPS. 30.0% reads the 0.30 change as a percent. 11.1% divides by the wrong base of 2.70.",difficulty:"hard",topic:"M&A"},
{q:"An acquirer needs 1000 to buy a target plus 30 of fees. It funds 700 with new debt and the rest with balance-sheet cash. How much cash is used?",options:["300","270","360","330"],correct:3,explanation:"Uses = 1000 + 30 = 1030; cash = 1030 - 700 = 330. 300 omits the fees. 270 subtracts the fees a second time. 360 counts the fees twice.",difficulty:"hard",topic:"M&A"},
{q:"Acquirer EBITDA 300 and net debt 600 buys a target with EBITDA 100, funding the entire 800 purchase with new debt. What is pro forma net debt to EBITDA?",options:["3.5x","4.67x","2.0x","1.5x"],correct:0,explanation:"PF net debt = 1400; PF EBITDA = 400; ratio = 3.5x. 4.67x forgets the target's EBITDA. 1.5x ignores the new acquisition debt. 2.0x counts only the new debt against combined EBITDA.",difficulty:"hard",topic:"M&A"},
{q:"Under US GAAP, how is acquired goodwill treated after a business combination for a public company?",options:["Expensed immediately at close","Amortized over 15 years","Not amortized; tested for impairment","Never tested or written down"],correct:2,explanation:"Public-company goodwill is not amortized; it is tested for impairment at least annually. The 15-year figure is a US tax convention, not GAAP book treatment. It is neither expensed at close nor exempt from testing.",difficulty:"hard",topic:"M&A"},
{q:"Acquirer at 50 with 200 shares and net income 600 (EPS 3.00) buys a target (100 shares at 20) at a 25% stock premium; target net income 90. What is pro forma EPS, no synergies?",options:["2.76","2.40","2.30","2.88"],correct:0,explanation:"Offer = 20 x 1.25 = 25; equity value = 2500; new shares = 2500/50 = 50; PF NI = 690; PF shares = 250; EPS = 2.76. 2.88 ignores the premium (40 new shares). 2.40 forgets the target's NI. 2.30 uses the target's 100 shares as new shares.",difficulty:"hard",topic:"M&A"},
{q:"A 1000 purchase is funded 60% with stock at a 50 share price and 40% with debt at 5% pretax, tax rate 25%. Acquirer net income 400 on 100 shares; target net income 70. What is pro forma EPS?",options:["4.55","4.20","4.02","4.06"],correct:3,explanation:"Stock = 600 gives 12 new shares; debt = 400 gives after-tax interest 400 x 5% x 0.75 = 15. PF NI = 400 + 70 - 15 = 455; shares 112; EPS = 4.06. 4.02 forgets to tax the interest. 4.55 forgets the new shares. 4.20 omits interest.",difficulty:"hard",topic:"M&A"},
{q:"An acquirer pays an equity value of 900 for a target with net income 60 and expects 15 of synergies accruing to the combined entity. What effective P/E does it pay on synergy-adjusted earnings?",options:["13.3x","15.0x","12.0x","10.0x"],correct:2,explanation:"Synergy-adjusted earnings = 60 + 15 = 75; P/E = 900/75 = 12.0x. 15.0x ignores synergies. 10.0x double counts synergies (uses 90). 13.3x uses only half the synergies.",difficulty:"hard",topic:"M&A"},
{q:"For an acquisition to qualify as a tax-free reorganization for target shareholders, what is generally required?",options:["The target must be larger than the acquirer","All-cash consideration","Significant stock consideration (continuity of interest)","No goodwill can be recorded"],correct:2,explanation:"Tax-free reorganizations require continuity of interest, meaning a substantial portion of consideration in acquirer stock. All cash is taxable, relative size is irrelevant, and goodwill treatment does not drive qualification.",difficulty:"hard",topic:"M&A"},
{q:"Pro forma EBITDA is 400, D&A is 40, and interest expense is 90. What is the EBIT interest coverage ratio?",options:["4.9x","4.4x","4.0x","0.25x"],correct:2,explanation:"EBIT = 400 - 40 = 360; coverage = 360/90 = 4.0x. 4.4x uses EBITDA in the numerator. 0.25x inverts the ratio. 4.9x adds D&A back instead of subtracting it.",difficulty:"hard",topic:"M&A"},
{q:"An acquirer pays 1200 for a target. Fair values: net tangible assets 400, identifiable intangibles 300, and an assumed off-book liability of 100. What goodwill is recorded?",options:["500","400","600","900"],correct:2,explanation:"Net identifiable = 400 + 300 - 100 = 600; goodwill = 1200 - 600 = 600. 500 ignores the assumed liability. 900 ignores the intangibles. 400 adds the liability instead of subtracting it.",difficulty:"hard",topic:"M&A"},
{q:"All else equal, an acquirer whose stock has a high P/E relative to a target maximizes EPS accretion by funding a deal with:",options:["New debt","Cash on hand","An equal cash and stock mix","Stock"],correct:3,explanation:"When the acquirer's shares are richly valued relative to the target's earnings, paying in those expensive shares is the most accretive financing. Cash and debt would forgo that advantage; a mix dilutes it.",difficulty:"hard",topic:"M&A"},
{q:"Acquirer net income 300 on 100 shares (EPS 3.00) makes an all-stock acquisition, issuing 25 shares for a target with net income 60. Accretive or dilutive, and what is pro forma EPS?",options:["Neutral, 3.00","Accretive, 3.60","Dilutive, 2.40","Dilutive, 2.88"],correct:3,explanation:"PF NI = 360; PF shares = 125; EPS = 2.88, below 3.00, so dilutive. Accretive 3.60 forgets the new shares. Dilutive 2.40 forgets the target's NI. Neutral 3.00 issues only 20 shares.",difficulty:"hard",topic:"M&A"},
{q:"In a stock acquisition where goodwill is not tax-deductible, how do the acquirer's cash taxes compare with a deal where goodwill is deductible?",options:["Higher cash taxes (no amortization deduction)","Lower cash taxes","Depends only on the premium paid","No difference"],correct:0,explanation:"Non-deductible goodwill provides no amortization shield, so taxable income and cash taxes are higher than in a deal with deductible goodwill. The other answers misstate the direction or relevance.",difficulty:"hard",topic:"M&A"},
{q:"Acquirer net income 800 on 200 shares (EPS 4.00) buys a target with net income 120 for 1500, half in stock at 50 and half in debt at 6% pretax, tax rate 25%. What is pro forma EPS, no synergies?",options:["4.12","4.43","4.07","4.28"],correct:0,explanation:"Stock 750 gives 15 new shares; debt 750 gives after-tax interest 750 x 6% x 0.75 = 33.75. PF NI = 800 + 120 - 33.75 = 886.25; shares 215; EPS = 4.12. 4.07 forgets to tax the interest. 4.43 forgets the new shares. 4.28 omits interest.",difficulty:"hard",topic:"M&A"},
{q:"A write-up of 400 of intangibles (10-year life) is non-deductible because the deal is a stock purchase, tax rate 25%. What is the annual hit to GAAP net income and the cash tax effect?",options:["NI down 40, no cash tax effect","NI down 30, cash taxes down 10","NI down 30, no cash tax effect","NI down 40, cash taxes down 10"],correct:0,explanation:"Amortization = 40; because it is non-deductible there is no tax shield, so GAAP NI falls the full 40 and cash taxes are unchanged. The 30 answers wrongly tax-effect a non-deductible item; the cash-down-10 answers grant a shield that does not exist.",difficulty:"hard",topic:"M&A"},
{q:"An acquirer funds an all-cash deal entirely with cash earning 4% pretax, tax rate 25%. At what target P/E is the deal exactly EPS-neutral?",options:["50.0x","25.0x","16.7x","33.3x"],correct:3,explanation:"After-tax foregone yield = 4% x 0.75 = 3%; neutral when target earnings yield equals 3%, so P/E = 1/0.03 = 33.3x. 25.0x uses the pretax 4%. 50.0x halves the rate to 2%. 16.7x grosses the rate up to 6%.",difficulty:"hard",topic:"M&A"},
{q:"A sponsor invests 400 of equity and exits 5 years later with 1200 of equity proceeds. What are the MOIC and approximate IRR?",options:["2.0x and about 24.6%","3.0x and about 24.6%","3.0x and about 20.0%","3.0x and about 14.9%"],correct:1,explanation:"MOIC = 1200/400 = 3.0x; IRR = 3.0^(1/5) - 1 = 24.6%. The 20.0% answer uses a rough rule of thumb. The 2.0x answer miscomputes MOIC. The 14.9% answer pairs 3.0x with a 2.0x IRR.",difficulty:"hard",topic:"LBO"},
{q:"A target is bought for an EV of 1000 (8x EBITDA of 125). Debt funds 5.0x EBITDA; fees are 30; the target has no excess cash. What sponsor equity is required at entry?",options:["280","405","375","435"],correct:1,explanation:"Debt = 5.0 x 125 = 625; uses = 1000 + 30 fees = 1030; equity = 1030 - 625 = 405. 375 omits the fees. 280 uses 6.0x leverage. 435 double counts the fees.",difficulty:"hard",topic:"LBO"},
{q:"Entry EV 1000 at 8x EBITDA 125, with 600 debt and 400 equity. Over 5 years EBITDA grows to 150, the exit multiple is 8x, and 250 of debt is repaid. What is the MOIC?",options:["3.00x","2.12x","1.50x","1.62x"],correct:1,explanation:"Exit EV = 8 x 150 = 1200; exit net debt = 600 - 250 = 350; exit equity = 850; MOIC = 850/400 = 2.12x. 1.50x forgets the debt paydown. 1.62x forgets the EBITDA growth. 3.00x divides exit EV by entry equity.",difficulty:"hard",topic:"LBO"},
{q:"A sponsor doubles its money (2.0x MOIC) over 4 years. What is the approximate IRR?",options:["26.0%","25.0%","14.9%","18.9%"],correct:3,explanation:"IRR = 2.0^(1/4) - 1 = 18.9%. 25.0% divides total return by years (simple). 26.0% uses a 3-year hold. 14.9% uses a 5-year hold.",difficulty:"hard",topic:"LBO"},
{q:"A company with EBITDA of 200 is levered at 5.5x total debt and 3.5x senior debt. How much junior (subordinated) debt is there?",options:["700","1100","200","400"],correct:3,explanation:"Junior = (5.5 - 3.5) x 200 = 400. 1100 is total debt. 700 is senior debt. 200 uses a 1.0x gap.",difficulty:"hard",topic:"LBO"},
{q:"EBITDA 250, cash interest 60, capex 40, taxes 30, and an increase in NWC of 10. How much cash is available to repay debt this year?",options:["120","110","140","130"],correct:1,explanation:"Cash for paydown = 250 - 60 - 40 - 30 - 10 = 110. 120 omits the NWC use. 130 adds NWC instead of subtracting. 140 omits taxes.",difficulty:"hard",topic:"LBO"},
{q:"A deal entered at 8x exits at 9x, EBITDA flat at 100, net debt falling from 500 to 350, entry equity 300. What is the MOIC?",options:["3.00x","1.33x","1.83x","1.50x"],correct:2,explanation:"Exit EV = 9 x 100 = 900; exit equity = 900 - 350 = 550; MOIC = 550/300 = 1.83x. 1.50x uses the entry 8x. 1.33x forgets the debt paydown. 3.00x divides exit EV by entry equity.",difficulty:"hard",topic:"LBO"},
{q:"At entry, net debt is 600 on EBITDA of 100. At exit in year 5, net debt is 300 and EBITDA is 150. What is the exit net leverage?",options:["3.0x","4.0x","6.0x","2.0x"],correct:3,explanation:"Exit net leverage = 300/150 = 2.0x. 3.0x uses entry EBITDA. 4.0x forgets the paydown. 6.0x is the entry leverage.",difficulty:"hard",topic:"LBO"},
{q:"Buy at 7x EBITDA 100 (EV 700) with 4x debt (400) and 300 equity, no fees. Over 5 years EBITDA grows to 130, 200 of debt is repaid, and the exit multiple is 7x. What is the approximate IRR?",options:["about 11.2%","about 14.9%","about 24.8%","about 18.8%"],correct:3,explanation:"Exit EV = 7 x 130 = 910; exit net debt = 200; exit equity = 710; MOIC = 2.37x; IRR = 2.37^(1/5) - 1 = 18.8%. 11.2% forgets the paydown. 24.8% divides exit EV by entry equity. 14.9% applies a 2.0x rule over 5 years.",difficulty:"hard",topic:"LBO"},
{q:"A sponsor invested 300, took a 180 dividend recap in year 3, and the remaining equity is worth 360 at exit in year 5. What is the total MOIC?",options:["3.0x","0.6x","1.8x","1.2x"],correct:2,explanation:"Total returned = 180 + 360 = 540; MOIC = 540/300 = 1.8x. 1.2x omits the recap. 0.6x counts only the recap. 3.0x nets the recap against invested capital first.",difficulty:"hard",topic:"LBO"},
{q:"A 200 PIK note accrues at 10% annually and compounds. What is its balance after 3 years?",options:["220.0","242.0","260.0","266.2"],correct:3,explanation:"Balance = 200 x 1.10^3 = 266.2. 260.0 uses simple interest (30%). 242.0 stops at year 2. 220.0 stops at year 1.",difficulty:"hard",topic:"LBO"},
{q:"A company generates 120 of free cash flow (already after interest) with a 100% cash sweep. Beginning debt is 500 at 8% cash interest. How much debt remains at year end?",options:["380","420","460","340"],correct:0,explanation:"The 120 is post-interest, so ending debt = 500 - 120 = 380. 340 subtracts interest a second time. 420 adds interest back. 460 repays only the interest.",difficulty:"hard",topic:"LBO"},
{q:"Entry: EV 800 at 8x EBITDA 100, net debt 500, equity 300. Exit: EBITDA 120, multiple 8x, net debt 350. How does the equity gain split between EBITDA growth (constant multiple) and debt paydown?",options:["160 from growth, 150 from paydown","150 from growth, 160 from paydown","120 from growth, 150 from paydown","160 from growth, 110 from paydown"],correct:0,explanation:"EBITDA growth at a constant 8x = (120-100) x 8 = 160; debt paydown = 500 - 350 = 150; total gain = 310. The swap answer reverses the two. 120 values growth at 6x. 110 mis-measures the paydown.",difficulty:"hard",topic:"LBO"},
{q:"Entry equity 300, entry EV 800 (8x EBITDA 100), net debt 500. At exit EBITDA is 150 and net debt is 300. What exit EV/EBITDA is needed for a 2.0x MOIC?",options:["6.0x","7.3x","8.0x","4.0x"],correct:0,explanation:"Target exit equity = 600; exit EV = 600 + 300 = 900; multiple = 900/150 = 6.0x. 4.0x forgets to add net debt. 7.3x uses the entry net debt of 500. 8.0x just assumes the entry multiple.",difficulty:"hard",topic:"LBO"},
{q:"A sponsor will realize 1000 of exit equity value. Management holds a 10% option pool struck at zero that vests at exit. How much does the sponsor receive after the pool?",options:["900","1000","990","800"],correct:0,explanation:"Sponsor proceeds = 1000 x (1 - 0.10) = 900. 1000 ignores the pool. 990 dilutes by 10 rather than 10%. 800 uses a 20% pool.",difficulty:"hard",topic:"LBO"},
{q:"A sponsor invests 100, receives a 50 dividend at the end of year 2, and 150 at exit in year 4. Versus a deal returning 200 only at year 4, the IRR is:",options:["The same, because MOIC is identical","Lower, because of the lost dividend","Lower, because total proceeds are smaller","Higher, because cash comes back earlier"],correct:3,explanation:"Both deals return 200 on 100 (2.0x MOIC), but receiving 50 in year 2 pulls cash forward, raising IRR. Proceeds are not smaller, MOIC being equal does not make IRR equal, and no dividend is lost.",difficulty:"hard",topic:"LBO"},
{q:"A sponsor will write a 360 equity check for a deal with an EV of 900 (no fees, no cash). Target EBITDA is 100. What entry net leverage does this imply?",options:["8.0x","5.4x","9.0x","3.6x"],correct:1,explanation:"Debt = 900 - 360 = 540; leverage = 540/100 = 5.4x. 9.0x uses EV and forgets the equity. 3.6x uses equity/EBITDA. 8.0x assumes a generic 8x.",difficulty:"hard",topic:"LBO"},
{q:"Holding the exit multiple, exit EBITDA, and debt paydown constant, paying a higher entry multiple does what to the sponsor's IRR?",options:["Leaves it unchanged","Raises it only if leverage rises","Raises it","Lowers it"],correct:3,explanation:"A higher entry multiple means a bigger equity check for the same exit proceeds, lowering MOIC and IRR. The other answers misstate the direction.",difficulty:"hard",topic:"LBO"},
{q:"A company has 500 of debt at 9%. It refinances to 6%, tax rate 25%. What is the annual after-tax cash interest savings?",options:["22.50","3.75","15.00","11.25"],correct:3,explanation:"Pretax savings = 500 x (9% - 6%) = 15; after tax 15 x 0.75 = 11.25. 15.00 forgets the tax shield. 22.50 tax-affects the full new interest. 3.75 tax-affects the savings by the rate instead of one minus it.",difficulty:"hard",topic:"LBO"},
{q:"An LBO is done at 9x EBITDA of 100 with 6.0x of debt. What is equity as a percentage of total entry capitalization (ignore fees and cash)?",options:["42.9%","37.5%","66.7%","33.3%"],correct:3,explanation:"EV = 900; debt = 600; equity = 300; equity/cap = 300/900 = 33.3%. 66.7% is the debt share. 37.5% divides by an 8x EV. 42.9% divides by a 7x EV.",difficulty:"hard",topic:"LBO"},
{q:"A deal will return a 2.5x MOIC. What are the IRRs for a year-4 versus a year-5 exit?",options:["about 25.7% in both years","about 37.5% (yr4) vs 30.0% (yr5)","about 25.7% (yr4) vs 20.1% (yr5)","about 20.1% (yr4) vs 25.7% (yr5)"],correct:2,explanation:"IRR = 2.5^(1/4) - 1 = 25.7% and 2.5^(1/5) - 1 = 20.1%. The first wrong answer swaps the years. The 37.5%/30.0% answer divides the total return by years. The last ignores that a longer hold lowers IRR.",difficulty:"hard",topic:"LBO"},
{q:"Beginning debt 600. Year 1 free cash flow (after interest) 80, year 2 free cash flow 100, with a full cash sweep. What is debt at the end of year 2?",options:["520","420","500","380"],correct:1,explanation:"Ending debt = 600 - 80 - 100 = 420. 520 counts only year 1. 500 counts only year 2. 380 sweeps an extra 40.",difficulty:"hard",topic:"LBO"},
{q:"Entry debt is 600 at a blended 8% cash rate; EBITDA is 130. What is the entry EBITDA-to-interest coverage?",options:["0.37x","16.25x","2.71x","2.17x"],correct:2,explanation:"Interest = 600 x 8% = 48; coverage = 130/48 = 2.71x. 2.17x uses a 10% rate. 16.25x divides EBITDA by 8 (treating the rate as dollars). 0.37x inverts the ratio.",difficulty:"hard",topic:"LBO"},
{q:"Entry at 10x EBITDA 100 (EV 1000), net debt 700, equity 300. Exit: EBITDA 140, multiple 8x, net debt 500. What is the MOIC?",options:["2.07x","3.73x","3.00x","1.40x"],correct:0,explanation:"Exit EV = 8 x 140 = 1120; exit equity = 1120 - 500 = 620; MOIC = 620/300 = 2.07x. 3.00x holds the entry 10x. 1.40x forgets the paydown. 3.73x divides exit EV by entry equity.",difficulty:"hard",topic:"LBO"},
{q:"Exit equity value is 800. The sponsor holds preferred with a 200 liquidation preference plus 80% of the common; management holds 20% of the common. How much does the sponsor receive?",options:["840","640","600","680"],correct:3,explanation:"Preference 200 to the sponsor; remaining 600 of common split 80/20 gives the sponsor 480; total = 680. 640 ignores the preference and takes 80% of 800. 840 takes the preference plus 80% of the full 800. 600 forgets the sponsor's own preference.",difficulty:"hard",topic:"LBO"},
{q:"A target holds 50 of cash at close, which the buyer keeps and uses to reduce funding. Purchase EV is 1000 and debt funds 600. Ignoring fees, how much sponsor equity is needed?",options:["300","450","350","400"],correct:2,explanation:"Equity = EV 1000 - debt 600 - cash 50 = 350. 400 ignores the cash. 450 adds the cash to the need. 300 counts the cash twice.",difficulty:"hard",topic:"LBO"},
{q:"A sponsor triples its investment in exactly 3 years. What is the IRR?",options:["73.2%","33.3%","44.2%","31.6%"],correct:2,explanation:"IRR = 3.0^(1/3) - 1 = 44.2%. 33.3% divides total return by years. 31.6% uses a 4-year hold. 73.2% uses a 2-year hold.",difficulty:"hard",topic:"LBO"},
{q:"A company has revenue 1000, COGS 600, SG&A 150, D&A 90, interest expense 40, tax rate 25%. What is net income?",options:["120","157.5","67.5","90"],correct:3,explanation:"EBIT = 1000 - 600 - 150 - 90 = 160; pretax = 160 - 40 = 120; NI = 120 x 0.75 = 90. 157.5 omits D&A. 120 omits interest (and is also the pretax figure). 67.5 applies the tax twice.",difficulty:"hard",topic:"Accounting"},
{q:"A company has EBITDA 200, an 8x EV/EBITDA multiple, net debt 400, and 50 million shares. What is the implied equity value per share?",options:["16.0","32.0","40.0","24.0"],correct:3,explanation:"EV = 8 x 200 = 1600; equity = 1600 - 400 = 1200; per share = 1200/50 = 24.0. 32.0 forgets net debt. 40.0 adds net debt instead of subtracting. 16.0 subtracts net debt twice.",difficulty:"hard",topic:"Valuation"}
];

const PE_DIAG: DrillQ[] = [
{q:"Purchase EV 1200 funded partly with 700 of debt. Fees are 40, management rolls 60 of equity, and the target's 30 of cash funds the deal. What new sponsor cash equity is needed?",options:["450","480","410","510"],correct:0,explanation:"Uses = 1200 + 40 = 1240; sources = 700 debt + 60 rollover + 30 cash = 790; sponsor equity = 1240 - 790 = 450. 510 omits the rollover. 480 omits the target cash. 410 omits the fees.",difficulty:"hard",topic:"LBO Mechanics"},
{q:"EBITDA 150. A term loan at 3.5x, senior notes at 1.5x, and a revolver drawn at 0.5x. What are total leverage and total debt?",options:["5.5x, 825","6.0x, 900","5.0x, 750","4.0x, 600"],correct:0,explanation:"Total = 3.5 + 1.5 + 0.5 = 5.5x; debt = 5.5 x 150 = 825. 5.0x/750 omits the revolver. 4.0x/600 omits the notes. 6.0x/900 overstates the stack.",difficulty:"hard",topic:"LBO Mechanics"},
{q:"Beginning term loan 700. Mandatory amortization is 5% of the original balance. Excess free cash flow for the sweep is 120, and the cash sweep is 75%. How much does the term loan decline this year?",options:["95","90","155","125"],correct:3,explanation:"Mandatory = 5% x 700 = 35; sweep = 75% x 120 = 90; total = 125. 155 assumes a 100% sweep. 90 forgets the mandatory amortization. 95 uses a 50% sweep.",difficulty:"hard",topic:"LBO Mechanics"},
{q:"Entry net debt 750 on EBITDA 150. In year 1, EBITDA rises to 165 and 90 of debt is repaid. What is year-1 end net leverage?",options:["4.55x","4.0x","4.4x","5.0x"],correct:1,explanation:"Net debt = 750 - 90 = 660; leverage = 660/165 = 4.0x. 4.4x uses entry EBITDA. 4.55x forgets the paydown. 5.0x is the entry leverage.",difficulty:"hard",topic:"LBO Mechanics"},
{q:"Debt stack: 400 term loan at 7%, 200 senior notes at 9%, and 100 of PIK at 12% that accrues rather than paying cash. What is annual cash interest?",options:["28","58","40","46"],correct:3,explanation:"Cash interest = 400 x 7% + 200 x 9% = 46; the PIK is non-cash. 58 wrongly adds the 12 PIK as cash. 28 counts only the term loan. 40 applies a flat 8% to the 500 of cash-pay debt.",difficulty:"hard",topic:"LBO Mechanics"},
{q:"An LBO at 11x EBITDA with 6.5x of debt. What is the sponsor equity contribution as a percentage of purchase EV (ignore fees)?",options:["40.9%","59.1%","36.4%","45.0%"],correct:0,explanation:"Equity = 11 - 6.5 = 4.5x; share = 4.5/11 = 40.9%. 59.1% is the debt share. 36.4% uses 7.0x debt. 45.0% divides by a 10x EV.",difficulty:"hard",topic:"LBO Mechanics"},
{q:"EBITDA 200, cash interest 70, mandatory amortization 30, maintenance capex 25. What is the (EBITDA - capex)/(interest + amortization) coverage?",options:["2.50x","1.75x","2.00x","5.83x"],correct:1,explanation:"(200 - 25)/(70 + 30) = 175/100 = 1.75x. 2.50x omits the amortization. 2.00x omits capex. 5.83x omits interest from the denominator.",difficulty:"hard",topic:"LBO Mechanics"},
{q:"Uses: 1000 purchase plus 50 fees. Sources: 600 term loan, 150 sub debt, and 80 rollover. What sponsor cash equity balances the table?",options:["370","220","300","170"],correct:1,explanation:"Uses = 1050; sponsor equity = 1050 - (600 + 150 + 80) = 220. 170 omits the fees. 300 omits the rollover. 370 omits the sub debt.",difficulty:"hard",topic:"LBO Mechanics"},
{q:"A credit agreement caps net leverage at 5.0x. EBITDA is 180 and current net debt is 720. Holding EBITDA constant, how much additional debt can be raised before breaching?",options:["90","180","900","270"],correct:1,explanation:"Max debt = 5.0 x 180 = 900; headroom = 900 - 720 = 180. 900 reports the cap, not the headroom. 90 uses a 4.5x cap. 270 uses a 5.5x cap.",difficulty:"hard",topic:"LBO Mechanics"},
{q:"EV 1000. Debt of 650 face is raised at a 2% original issue discount (net proceeds 98% of face), and 20 of financing fees are paid in cash. The target has no cash. What sponsor equity is needed?",options:["363","383","370","350"],correct:1,explanation:"Net debt proceeds = 0.98 x 650 = 637; uses = 1000 + 20 = 1020; equity = 1020 - 637 = 383. 370 uses face value of the debt. 363 omits the financing fees. 350 ignores both the OID and the fees.",difficulty:"hard",topic:"LBO Mechanics"},
{q:"Year 1: EBITDA 150, cash interest 60, taxes 20, capex 30, increase in NWC 5. All free cash flow sweeps debt; beginning debt 600. What is ending debt?",options:["560","545","565","535"],correct:2,explanation:"FCF = 150 - 60 - 20 - 30 - 5 = 35; ending debt = 600 - 35 = 565. 560 omits the NWC use. 535 omits capex. 545 omits taxes.",difficulty:"hard",topic:"LBO Mechanics"},
{q:"A founder rolls 80 of equity into a deal with a total equity check of 400, including that rollover. At exit the equity is worth 1000. What is the founder's pro rata exit value, no preference?",options:["80","250","160","200"],correct:3,explanation:"Ownership = 80/400 = 20%; exit value = 0.20 x 1000 = 200. 80 returns only the rollover with no gain. 250 excludes the rollover from the base (80/320). 160 uses an 80/500 base.",difficulty:"hard",topic:"LBO Mechanics"},
{q:"Gross exit equity is 900 on a 300 sponsor investment. A management promote takes 15% of the exit equity. What is the sponsor's net MOIC?",options:["2.95x","3.00x","2.55x","2.70x"],correct:2,explanation:"Sponsor net = 900 x 0.85 = 765; MOIC = 765/300 = 2.55x. 3.00x ignores the promote. 2.70x applies the promote to the gain only. 2.95x subtracts 15 instead of 15%.",difficulty:"hard",topic:"LBO Mechanics"},
{q:"Beginning debt 500 at 8% cash interest, charged on the beginning-of-year balance. In year 1, 100 is repaid at year end. What is year-2 cash interest?",options:["24","32","40","36"],correct:1,explanation:"Year-2 balance = 400; interest = 400 x 8% = 32. 40 uses the original 500. 36 uses the average balance of 450. 24 uses a 300 balance.",difficulty:"hard",topic:"LBO Mechanics"},
{q:"Reported EBITDA 200 includes a 15 one-time legal settlement expense and excludes 10 of contractually committed run-rate cost synergies. What is adjusted EBITDA for leverage purposes?",options:["225","175","210","215"],correct:0,explanation:"Adjusted EBITDA = 200 + 15 add-back + 10 synergies = 225. 215 adds back only the settlement. 210 adds only the synergies. 175 subtracts both.",difficulty:"hard",topic:"LBO Mechanics"},
{q:"A sponsor funds 40% of EV with equity and the rest with 6.0x EBITDA of debt. What entry EV/EBITDA does this imply?",options:["6.0x","15.0x","12.0x","10.0x"],correct:3,explanation:"Debt of 6.0x is 60% of EV, so EV = 6.0x / 0.60 = 10.0x EBITDA. 6.0x reports only the debt. 15.0x divides by 0.4 (treats debt as 40%). 12.0x doubles the debt multiple.",difficulty:"hard",topic:"LBO Mechanics"},
{q:"A company has 100 of subordinated debt with a PIK toggle. If it elects PIK at 12% rather than paying 10% cash, what is the year-1 effect on cash flow and on the debt balance?",options:["Cash interest 10 lower, debt up 12","No cash effect, debt up 12","Cash interest 2 lower, debt up 12","Cash interest 12 lower, debt up 10"],correct:0,explanation:"Electing PIK avoids the 10 of cash interest and instead accrues 12 onto the balance. The first wrong answer swaps the rates. The third nets the two rates. The fourth forgets the cash interest is avoided.",difficulty:"hard",topic:"LBO Mechanics"},
{q:"Gross debt 800, balance-sheet cash 120, EBITDA 160. What are gross and net leverage?",options:["5.0x gross, 4.25x net","4.25x gross, 5.0x net","5.0x gross, 4.5x net","5.0x gross, 5.75x net"],correct:0,explanation:"Gross = 800/160 = 5.0x; net = (800-120)/160 = 4.25x. The 5.75x answer adds cash instead of subtracting. The third swaps gross and net. The 4.5x answer nets only 80 of cash.",difficulty:"hard",topic:"LBO Mechanics"},
{q:"Uses 1100 including 40 fees. Sources: 600 senior debt, 100 seller note, 50 rollover. What sponsor cash equity is needed?",options:["400","350","450","500"],correct:1,explanation:"Sponsor equity = 1100 - (600 + 100 + 50) = 350. 450 omits the seller note. 400 omits the rollover. 500 omits both.",difficulty:"hard",topic:"LBO Mechanics"},
{q:"A 600 term loan amortizes 1% of the original balance per quarter. What is the annual mandatory amortization?",options:["60","24","12","6"],correct:1,explanation:"Annual = 4 x 1% x 600 = 24. 6 is a single quarter. 60 uses 10%. 12 uses 2%.",difficulty:"hard",topic:"LBO Mechanics"},
{q:"At close, total debt is 900 at a blended 7.5% cash rate, EBITDA is 150, and maintenance capex is 20. What is the (EBITDA - capex)/cash-interest coverage?",options:["0.52x","1.93x","2.22x","1.81x"],correct:1,explanation:"Interest = 900 x 7.5% = 67.5; coverage = (150 - 20)/67.5 = 1.93x. 2.22x forgets capex. 1.81x uses an 8% rate. 0.52x inverts the ratio.",difficulty:"hard",topic:"LBO Mechanics"},
{q:"A portfolio company is about to breach a leverage covenant. The sponsor injects fresh equity that is used to pay down debt (an equity cure). What is the direct effect on net leverage?",options:["No effect until the next test date","Lowers net debt and thus leverage","Raises EBITDA and thus lowers leverage","Raises leverage by adding capital"],correct:1,explanation:"An equity cure reduces net debt directly, lowering the leverage ratio back into compliance. It does not change EBITDA, takes effect on injection, and does not raise leverage.",difficulty:"hard",topic:"LBO Mechanics"},
{q:"A fund invests 250 and returns 875 after 6 years. What are the MOIC and approximate IRR?",options:["3.5x and about 23.2%","3.5x and about 20.0%","2.5x and about 23.2%","3.5x and about 28.5%"],correct:0,explanation:"MOIC = 875/250 = 3.5x; IRR = 3.5^(1/6) - 1 = 23.2%. 20.0% uses a rough rule of thumb. 2.5x miscomputes MOIC. 28.5% uses a 5-year hold.",difficulty:"hard",topic:"Returns"},
{q:"Entry equity 400 (EV 800 = 8x EBITDA 100, net debt 400). Exit: EBITDA 140, multiple 9x, net debt 280. Decompose the equity gain into EBITDA growth, multiple expansion, and deleveraging.",options:["320 growth, 140 multiple, 280 deleveraging","320 growth, 140 multiple, 120 deleveraging","360 growth, 100 multiple, 120 deleveraging","280 growth, 140 multiple, 120 deleveraging"],correct:1,explanation:"Growth at the entry 8x = (140-100) x 8 = 320; expansion on exit EBITDA = (9-8) x 140 = 140; deleveraging = 400 - 280 = 120; total = 580 = the equity gain. The 360/100 answer crosses up the multiples. 280 deleveraging uses exit net debt as the paydown. 280 growth values the growth at 7x.",difficulty:"hard",topic:"Returns"},
{q:"A fund invests 100, takes a 40 distribution at the end of year 2, and exits for 120 at the end of year 4. Which is closest to the gross IRR?",options:["15.0%","12.5%","14.6%","20.0%"],correct:2,explanation:"Solving the cash flows -100, 0, 40, 0, 120 gives about 14.6%. 12.5% applies a 1.6x MOIC over 4 years and ignores the early distribution. 15.0% is the simple annualized profit. 20.0% overstates the annualization.",difficulty:"hard",topic:"Returns"},
{q:"Deal A returns 2.0x over 3 years; Deal B returns 2.0x over 5 years. Which has the higher IRR, and what do they share?",options:["Deal B has both higher","Same MOIC and same IRR","Same IRR; Deal A has the higher MOIC","Same MOIC; Deal A has the higher IRR"],correct:3,explanation:"Both have a 2.0x MOIC, but the shorter hold compounds faster, so Deal A has the higher IRR. The other answers confuse MOIC with IRR or ignore the time effect.",difficulty:"hard",topic:"Returns"},
{q:"A deal returns 3.0x gross on 100 invested. Carry is 20% of profit above a 1.0x return of capital. What is the LP net MOIC, ignoring fees?",options:["2.8x","2.6x","2.4x","3.0x"],correct:1,explanation:"Profit = 200; carry = 20% x 200 = 40; LP gets 300 - 40 = 260; net MOIC = 2.6x. 2.4x applies carry to all proceeds. 3.0x ignores carry. 2.8x applies carry only above a 2.0x hurdle.",difficulty:"hard",topic:"Returns"},
{q:"A fund makes two equal 100 investments; one returns 3.0x and one returns 0.5x. What is the fund's gross MOIC?",options:["2.0x","3.5x","1.75x","1.5x"],correct:2,explanation:"Total in = 200; total out = 300 + 50 = 350; MOIC = 1.75x. 3.5x sums the two multiples. 1.5x nets the loss incorrectly. 2.0x adds the loss back as capital.",difficulty:"hard",topic:"Returns"},
{q:"Early in a fund's life, net IRR is often negative even when the underlying companies perform. Why?",options:["Carry is paid upfront","LPs withdraw capital early","Fees are paid before gains are realized (J-curve)","Companies always lose money in year 1"],correct:2,explanation:"Management fees and costs are drawn before investments are marked up or exited, producing the J-curve. Carry is not paid upfront, LPs cannot freely withdraw, and early losses are not universal.",difficulty:"hard",topic:"Returns"},
{q:"A fund has called 500, distributed 300, and holds a remaining NAV of 450. What are DPI and TVPI?",options:["0.6x DPI, 0.9x TVPI","0.6x DPI, 1.5x TVPI","1.5x DPI, 0.6x TVPI","0.9x DPI, 1.5x TVPI"],correct:1,explanation:"DPI = 300/500 = 0.6x; TVPI = (300 + 450)/500 = 1.5x. The 0.9x TVPI omits distributions or NAV. The third swaps DPI and TVPI. The fourth puts the NAV into DPI.",difficulty:"hard",topic:"Returns"},
{q:"A fund called 400, holds NAV 300, and has distributed 200. What is RVPI (residual value to paid-in)?",options:["1.25x","0.43x","0.50x","0.75x"],correct:3,explanation:"RVPI = NAV/paid-in = 300/400 = 0.75x. 0.50x is DPI. 1.25x is TVPI. 0.43x divides NAV by 700.",difficulty:"hard",topic:"Returns"},
{q:"Buy at 9x EBITDA 120 (EV 1080), debt 700, equity 380, no fees. Exit year 5: EBITDA 160, multiple 9x, debt repaid to 400. What is the MOIC?",options:["1.79x","2.74x","3.79x","1.95x"],correct:1,explanation:"Exit EV = 9 x 160 = 1440; exit equity = 1440 - 400 = 1040; MOIC = 1040/380 = 2.74x. 1.95x forgets the paydown. 3.79x divides exit EV by entry equity. 1.79x uses entry EBITDA.",difficulty:"hard",topic:"Returns"},
{q:"A fund invests 200, receives 100 at the end of year 3 and 250 at the end of year 6. Closest gross IRR?",options:["12.5%","15.0%","9.8%","11.8%"],correct:3,explanation:"Solving -200, then +100 in year 3 and +250 in year 6 gives about 11.8%. 9.8% applies a 1.75x MOIC over 6 years and ignores the year-3 cash. 12.5% is the simple annualized profit. 15.0% overstates it.",difficulty:"hard",topic:"Returns"},
{q:"A company exits with an EV of 300 (entry EV 200). Scenario 1: 200 equity, no debt. Scenario 2: 120 debt and 80 equity, debt unchanged at exit. What are the equity MOICs?",options:["1.5x unlevered, 1.5x levered","2.25x unlevered, 1.5x levered","1.5x unlevered, 1.8x levered","1.5x unlevered, 2.25x levered"],correct:3,explanation:"Unlevered: 300/200 = 1.5x. Levered: exit equity = 300 - 120 = 180 on 80 invested = 2.25x. The second answer ignores leverage. The third swaps them. The fourth uses a 100 equity check.",difficulty:"hard",topic:"Returns"},
{q:"A deal will return a 4.0x MOIC. What are the IRRs for a year-5 versus a year-7 exit?",options:["about 60.0% (yr5) vs 42.9% (yr7)","about 32.0% in both years","about 21.9% (yr5) vs 32.0% (yr7)","about 32.0% (yr5) vs 21.9% (yr7)"],correct:3,explanation:"IRR = 4.0^(1/5) - 1 = 32.0% and 4.0^(1/7) - 1 = 21.9%. The first wrong answer swaps the years. The 60.0%/42.9% answer divides total return by years. The last ignores the hold-period effect.",difficulty:"hard",topic:"Returns"},
{q:"An LP commits 100; the deal returns 250. The GP earns 20% carry, but only after the LP receives its capital back (no preferred return). How is the 250 split?",options:["LP 226, GP 24","LP 210, GP 40","LP 200, GP 50","LP 220, GP 30"],correct:3,explanation:"Return capital 100; profit 150; carry = 20% x 150 = 30 to the GP; LP gets 100 + 120 = 220. LP 200/GP 50 applies carry to the full 250. LP 210/GP 40 uses a wrong profit base. LP 226/GP 24 uses a 120 profit.",difficulty:"hard",topic:"Returns"},
{q:"A fund targets a 25% IRR over a 5-year hold. What MOIC must it achieve?",options:["2.44x","3.05x","3.81x","2.25x"],correct:1,explanation:"MOIC = 1.25^5 = 3.05x. 2.25x adds 25% five times (simple). 2.44x uses a 4-year hold. 3.81x uses a 6-year hold.",difficulty:"hard",topic:"Returns"},
{q:"Cash flows: invest 150 at year 0, then distributions of 80 in year 2, 90 in year 4, and 60 in year 5. Closest gross IRR?",options:["13.1%","10.6%","8.9%","16.0%"],correct:0,explanation:"Solving the cash flows gives about 13.1% (MOIC 1.53x with mid-life distributions). 8.9% applies the MOIC over 5 years ignoring timing. 10.6% is the simple annualized profit. 16.0% overstates it.",difficulty:"hard",topic:"Returns"},
{q:"A fund reports a 28% gross IRR but a 19% net IRR. The 9-point spread mostly reflects:",options:["Management fees and carry","Unrealized markdowns only","Leverage at the deal level","Currency hedging costs"],correct:0,explanation:"The gross-to-net gap is driven by management fees and carried interest. Deal leverage is already in gross returns; hedging and markdowns are not the main structural drivers.",difficulty:"hard",topic:"Returns"},
{q:"Equity value rose from 300 to 820. EBITDA went from 100 to 150 at a constant 8x, and entry net debt was 500. How much of the gain came from deleveraging?",options:["520","220","400","120"],correct:3,explanation:"Exit EV = 8 x 150 = 1200; exit net debt = 1200 - 820 = 380; deleveraging = 500 - 380 = 120. 400 is the EBITDA-growth piece. 520 is the total gain. 220 mis-measures the paydown.",difficulty:"hard",topic:"Returns"},
{q:"An LP commits 100 to a deal returning 180. With an 8% preferred return, a full GP catch-up, and an 80/20 split, the structure resolves to the GP earning 20% of total profit. What carry does the GP earn?",options:["36","16","32","9.6"],correct:1,explanation:"Profit = 80; carry = 20% x 80 = 16. 36 applies carry to the full 180. 9.6 applies carry only to profit above the 32 preferred. 32 is the preferred amount, not carry.",difficulty:"hard",topic:"Returns"},
{q:"Why is a fund's reported net IRR usually different from the simple average of its deals' IRRs?",options:["Fees raise each deal's IRR","Deal IRRs are always understated","Carry is added to every deal equally","IRR is cash-flow-weighted, not a simple average"],correct:3,explanation:"IRR weights by the size and timing of cash flows, so large or early winners dominate and fund fees shift the timing; it is not the arithmetic mean of deal IRRs. The other statements are simply false.",difficulty:"hard",topic:"Returns"},
{q:"Exit equity = exit EV - 400 net debt; exit EBITDA is 150. Compare the MOIC on a 300 entry equity at an 8x versus a 10x exit multiple.",options:["4.00x at 8x, 5.00x at 10x","3.67x at 8x, 2.67x at 10x","2.67x at 8x, 3.33x at 10x","2.67x at 8x, 3.67x at 10x"],correct:3,explanation:"8x: EV 1200, equity 800, MOIC 2.67x. 10x: EV 1500, equity 1100, MOIC 3.67x. 3.33x mishandles net debt at 10x. The 4.00x/5.00x answer forgets net debt entirely. The last swaps the multiples.",difficulty:"hard",topic:"Returns"},
{q:"A sponsor invests 200. A year-2 dividend recap returns 120; a year-5 exit returns 280. What are the total MOIC and approximate IRR?",options:["2.0x and about 24.0%","1.4x and about 19.3%","2.0x and about 19.3%","2.0x and about 14.9%"],correct:2,explanation:"Total returned = 400; MOIC = 2.0x; solving -200, +120 in year 2, +280 in year 5 gives about 19.3%. 14.9% ignores the early recap (2.0x over 5 years). 24.0% overstates it. 1.4x miscomputes MOIC.",difficulty:"hard",topic:"Returns"},
{q:"Entry: EV 1000 at 10x EBITDA 100, debt 700, equity 300. Exit: EBITDA 80, multiple 7x, debt unchanged at 700. What is the equity MOIC?",options:["1.87x","0.33x","-0.47x","0x (equity wiped out)"],correct:3,explanation:"Exit EV = 7 x 80 = 560, which is below the 700 of debt, so equity is wiped out (0x, floored at zero). 1.87x forgets the debt. -0.47x fails to floor the negative equity. 0.33x values exit EBITDA at the entry 10x.",difficulty:"hard",topic:"Returns"},
{q:"After LPs receive their preferred return, a 100% GP catch-up provision does what?",options:["Caps the GP's carry at the preferred return","Splits the catch-up 80/20","Sends 100% to the GP until it reaches its carry share of profits","Returns LP capital a second time"],correct:2,explanation:"The catch-up directs distributions entirely to the GP until it has received its carry percentage of total profits, restoring the agreed split. The other answers misdescribe the mechanic.",difficulty:"hard",topic:"Returns"},
{q:"A 2.0x MOIC over 5 years is often quoted as roughly a 15% IRR. What is the precise IRR?",options:["12.2%","20.0%","14.9%","18.9%"],correct:2,explanation:"IRR = 2.0^(1/5) - 1 = 14.9%. 20.0% divides total return by years. 12.2% uses a 6-year hold. 18.9% uses a 4-year hold.",difficulty:"hard",topic:"Returns"},
{q:"In a standard European (whole-fund) waterfall, in what order are distributions made?",options:["Preferred, capital, carry, catch-up","Carry, capital, preferred, catch-up","Capital, carry, preferred, catch-up","Capital, preferred return, catch-up, then carry"],correct:3,explanation:"The European waterfall pays return of capital, then the preferred return, then the GP catch-up, then the carried-interest split. The other sequences scramble these steps.",difficulty:"hard",topic:"Returns"},
{q:"A 1000 fund charges a 2% annual management fee on committed capital for a 10-year life. What is total lifetime management fees, ignoring step-downs?",options:["180","100","20","200"],correct:3,explanation:"Total = 2% x 1000 x 10 = 200. 20 is a single year. 100 uses a 1% rate. 180 counts only 9 years.",difficulty:"hard",topic:"Fund Economics"},
{q:"A 1000 fund charges 2% on committed capital for a 5-year investment period, then 2% on invested capital (800) for the remaining 5 years. What is total lifetime fees?",options:["190","160","200","180"],correct:3,explanation:"Period 1 = 2% x 1000 x 5 = 100; period 2 = 2% x 800 x 5 = 80; total = 180. 200 ignores the step-down. 160 applies the invested-capital base to all 10 years. 190 uses a 900 invested base in period 2.",difficulty:"hard",topic:"Fund Economics"},
{q:"A 500 fund returns 1500. Carry is 20% over an 8% compound preferred return, and the fund clears the pref with a full catch-up so the GP nets 20% of total profit. What is the carry?",options:["100","200","160","300"],correct:1,explanation:"Profit = 1500 - 500 = 1000; carry = 20% x 1000 = 200. 300 applies carry to the full 1500. 160 applies it only to profit above a 200 pref. 100 uses a 10% rate.",difficulty:"hard",topic:"Fund Economics"},
{q:"A 2000 fund requires the GP to commit 2% of the fund. How much does the GP invest, and what is the LP commitment?",options:["GP 200, LP 1800","GP 20, LP 1980","GP 40, LP 2000","GP 40, LP 1960"],correct:3,explanation:"GP commit = 2% x 2000 = 40; the remaining 1960 is the LP commitment. GP 40/LP 2000 forgets the GP share reduces LP capital. GP 20 uses 1%. GP 200 uses 10%.",difficulty:"hard",topic:"Fund Economics"},
{q:"A fund earns 30 of transaction and monitoring fees from portfolio companies with a 100% management fee offset. The gross management fee for the year is 20. What net fee do LPs pay?",options:["30 (fees add to the management fee)","0 (offset exceeds the fee)","10 (only a partial offset)","20 (no offset applies)"],correct:1,explanation:"A 100% offset reduces the 20 fee by the 30 of fees, flooring it at 0 (with excess often carried forward). 20 ignores the offset. 10 applies only a partial offset. 30 wrongly adds the fees on top.",difficulty:"hard",topic:"Fund Economics"},
{q:"Over a fund's life, LPs pay 200 of fees and 250 of carry on 1000 of committed capital that grows to a 2500 gross value. Roughly what fraction of gross profit goes to the GP in fees and carry combined?",options:["18.0%","13.3%","16.7%","30.0%"],correct:3,explanation:"Gross profit = 1500; GP take = (200 + 250)/1500 = 30.0%. 16.7% counts carry only. 18.0% divides by the 2500 gross value. 13.3% counts fees only.",difficulty:"hard",topic:"Fund Economics"},
{q:"LPs are entitled to an 8% compounded preferred return on 100 of drawn capital over 4 years before the GP earns carry. What is the cumulative preferred return amount?",options:["36","26","32","47"],correct:0,explanation:"Cumulative pref = 100 x (1.08^4 - 1) = 36. 32 uses simple interest. 26 uses 3 years. 47 uses 5 years.",difficulty:"hard",topic:"Fund Economics"},
{q:"A GP took 50 of carry on early winners, but the fund's final results entitle the GP to only 35 of carry over the whole life. What does the clawback require?",options:["No action, carry is final","GP returns 15 to LPs","LPs pay the GP 15 more","GP returns 50"],correct:1,explanation:"The clawback forces the GP to return the 15 of over-distributed carry (50 taken minus 35 earned). The other answers reverse the flow, ignore the provision, or return the full amount.",difficulty:"hard",topic:"Fund Economics"},
{q:"Compared with a whole-fund (European) waterfall, an American (deal-by-deal) waterfall generally:",options:["Removes the preferred return","Eliminates carry entirely","Pays GP carry sooner, raising clawback risk","Pays GP carry later"],correct:2,explanation:"Deal-by-deal lets the GP take carry as individual deals exit, accelerating GP cash and increasing the chance a clawback is later needed. The other answers misstate the structure.",difficulty:"hard",topic:"Fund Economics"},
{q:"A GP runs Fund III (2000 at a 2% fee) and Fund IV (3000 at a 2% fee), both in their investment periods. What is annual management fee revenue?",options:["60","100","40","50"],correct:1,explanation:"Revenue = 2% x (2000 + 3000) = 100. 60 counts only Fund IV. 50 uses a 1% rate. 40 counts only Fund III.",difficulty:"hard",topic:"Fund Economics"},
{q:"After LPs receive 100 of capital and 20 of preferred return, a 100% GP catch-up to a 20/80 split applies. How much does the GP receive in the catch-up before the 80/20 split begins?",options:["20","25","5","4"],correct:2,explanation:"The GP catches up to 20% of profit distributed so far: C = 0.20 x (20 + C), so C = 5. 4 takes 20% of the 20 pref and ignores that the catch-up is itself profit. 20 sets it equal to the pref. 25 catches up to a 25% share.",difficulty:"hard",topic:"Fund Economics"},
{q:"As a PE firm raises much larger funds, its economics shift such that:",options:["Carry becomes its only income","Fee income grows large in absolute terms relative to carry","LPs pay higher fee rates","Fees fall to zero"],correct:1,explanation:"On a much larger asset base, the management fee becomes a substantial standalone income stream, which can dilute the carry-driven incentive. The other answers are simply false.",difficulty:"hard",topic:"Fund Economics"},
{q:"A deal grosses a 2.25x MOIC over 5 years; net of a 0.45x fee-and-carry drag, net MOIC is 1.80x. What is the net IRR?",options:["14.9%","16.0%","17.6%","12.5%"],correct:3,explanation:"Net IRR = 1.80^(1/5) - 1 = 12.5%. 17.6% is the gross IRR (2.25x). 16.0% overstates it. 14.9% corresponds to a 2.0x net.",difficulty:"hard",topic:"Fund Economics"},
{q:"A fund recycles early distributions back into new investments rather than returning them to LPs. The main effect is to:",options:["Reduce total fees paid","Guarantee a higher net IRR","Put more than committed capital to work","Return capital to LPs faster"],correct:2,explanation:"Recycling redeploys proceeds, so cumulative invested capital can exceed commitments, raising gross-return potential (and the fee base). It does not cut fees, guarantee returns, or speed distributions.",difficulty:"hard",topic:"Fund Economics"},
{q:"A deal returns 160 on 100 over 4 years. With an 8% simple preferred return (32 total) and a hard hurdle (carry only on profit above the pref, no catch-up), what carry does the GP earn at 20%?",options:["2.8","6.4","12.0","5.6"],correct:3,explanation:"Profit = 60; profit above the 32 pref = 28; carry = 20% x 28 = 5.6. 12.0 ignores the hurdle (20% of 60). 2.8 uses a 10% rate. 6.4 uses a 28 pref from a 7% rate.",difficulty:"hard",topic:"Fund Economics"},
{q:"An LP commits 50 to a 1000 fund charging 2% on commitments. What annual fee does this LP pay, and what share of the fund's total fee is it?",options:["2 per year, 5% of total","0.5 per year, 5% of total","1 per year, 5% of total","1 per year, 2% of total"],correct:2,explanation:"Fee = 2% x 50 = 1; share = 50/1000 = 5%. The 2-per-year answer doubles the rate. The 2%-of-total answer confuses the fee rate with the share. The 0.5 answer uses a 1% fee.",difficulty:"hard",topic:"Fund Economics"},
{q:"A 1000 fund returns 2200, with carry of 20% of the 1200 profit. As a percentage of committed capital, how large is the GP's carry?",options:["12%","48%","24%","20%"],correct:2,explanation:"Carry = 20% x 1200 = 240; as a share of the 1000 committed that is 24%. 20% is the carry rate, not the amount. 12% divides by 2000. 48% divides by 500.",difficulty:"hard",topic:"Fund Economics"},
{q:"A fund charges 2% per year for 10 years on 100 of committed capital, paid from LP capital. Ignoring time value and returns on the fee dollars, by how much do cumulative fees reduce a gross 2.0x outcome to net?",options:["0.2x (to 2.2x net)","0.4x (to 1.6x net)","0.1x (to 1.9x net)","0.2x (to 1.8x net)"],correct:3,explanation:"Fees = 2% x 100 x 10 = 20; net = 200 - 20 = 180, a 1.8x, so a 0.2x drag. 0.4x doubles the fee. 0.1x halves it. 2.2x adds the fees instead of subtracting.",difficulty:"hard",topic:"Fund Economics"},
{q:"A GP typically raises its next fund once the current fund's investment period is largely complete primarily because it:",options:["Is guaranteed returns by then","Avoids charging fees on two actively-investing funds at once","Must fully exit the current fund first","Must pay carry first"],correct:1,explanation:"Raising sooner would mean charging management fees on two funds deploying the same strategy simultaneously, which LPs resist. Full exit is not required, carry timing is separate, and returns are never guaranteed.",difficulty:"hard",topic:"Fund Economics"},
{q:"Gross MOIC is 2.8x on 100 (280 back). Lifetime fees are 18 and carry is 20% of profit above a 1.0x return of capital. What is the net MOIC to LPs?",options:["2.62x","2.06x","2.26x","2.44x"],correct:2,explanation:"Carry = 20% x (280 - 100) = 36; net to LPs = 280 - 36 - 18 = 226; net MOIC = 2.26x. 2.44x omits the fees. 2.62x omits the carry. 2.06x applies carry to the full 280.",difficulty:"hard",topic:"Fund Economics"},
{q:"The bulk of a PE firm's wealth creation for its partners, in a successful fund, typically comes from:",options:["Management fee income","Carried interest on gains","Transaction fees","GP commitment returns alone"],correct:1,explanation:"Carry on investment gains is the primary driver of partner wealth in a strong fund. Fees cover operations, transaction fees are usually offset, and the GP commitment is small relative to carry.",difficulty:"hard",topic:"Fund Economics"},
{q:"An 8% preferred return acts as a hurdle, meaning the GP earns carry only if:",options:["Every single deal returns at least 8%","LP returns clear 8% first","The GP commits 8% of the fund","Fees are kept below 8%"],correct:1,explanation:"The preferred return is a return hurdle: LPs must first receive an 8% return, after which catch-up and carry apply. It is unrelated to the GP commitment size, the fee level, or per-deal returns.",difficulty:"hard",topic:"Fund Economics"},
{q:"A term loan is priced at SOFR plus 450 basis points with a 0.50% SOFR floor. If SOFR is 0.25%, what is the cash coupon?",options:["5.50%","4.50%","4.75%","5.00%"],correct:3,explanation:"SOFR is floored at 0.50%, so coupon = 0.50% + 4.50% = 5.00%. 4.75% uses the actual 0.25% SOFR. 4.50% ignores SOFR entirely. 5.50% applies a 1.00% floor.",difficulty:"hard",topic:"Capital Structure"},
{q:"In a liquidation, a company has 100 of value. Claims: 60 first-lien debt, 50 second-lien debt, 30 unsecured. How much do second-lien holders recover?",options:["40 (80% recovery)","20 (pro rata with unsecured)","50 (paid in full)","0 (nothing)"],correct:0,explanation:"First lien takes its 60; the remaining 40 goes to second lien (claim 50), an 80% recovery; unsecured gets 0. 50 ignores the value shortfall. 20 wrongly shares pro rata with unsecured. 0 ignores second lien's priority over unsecured.",difficulty:"hard",topic:"Capital Structure"},
{q:"What is the key difference between a maintenance covenant and an incurrence covenant?",options:["Incurrence is tested each period; maintenance only on actions","Maintenance is tested each period; incurrence only on a specific action","Both are tested only at maturity","Maintenance applies only to equity"],correct:1,explanation:"Maintenance covenants are tested every reporting period regardless of activity; incurrence covenants are tested only when the company takes a defined action such as raising debt or paying a dividend. The other statements reverse or misstate this.",difficulty:"hard",topic:"Capital Structure"},
{q:"A lender will provide up to 5.5x of total leverage. EBITDA is 200 and the company keeps 30 of minimum cash. What is the maximum gross debt?",options:["1070","1100","1130","1000"],correct:1,explanation:"Gross debt cap = 5.5 x 200 = 1100. 1130 adds the minimum cash (a net-leverage confusion). 1070 subtracts it. 1000 uses a 5.0x cap.",difficulty:"hard",topic:"Capital Structure"},
{q:"Replacing 100 of cash-pay debt at 8% with 100 of PIK debt at 10% changes year-1 free cash flow and the debt balance how?",options:["FCF down 2, debt up 10","FCF up 10, debt up 8","No FCF change, debt up 10","FCF up 8, debt up 10"],correct:3,explanation:"Avoiding the 8 of cash interest raises FCF by 8, while the 10 of PIK accrues onto the balance. The first wrong answer swaps the figures. The second nets the rates. The third forgets the cash interest is saved.",difficulty:"hard",topic:"Capital Structure"},
{q:"A term loan with a 6% coupon is issued at 98 (2 points of OID) and matures in 4 years. Roughly how much does the OID add to the annual yield?",options:["about 0% (OID does not affect yield)","about 2% per year (yield 8%)","about 0.25% per year (yield 6.25%)","about 0.5% per year (yield about 6.5%)"],correct:3,explanation:"The 2 points of discount accrete over 4 years, roughly 0.5% per year, lifting the yield to about 6.5%. The 2% answer ignores the maturity. The 0% answer ignores the discount. The 0.25% answer uses an 8-year amortization.",difficulty:"hard",topic:"Capital Structure"},
{q:"Relative to second-lien term debt, mezzanine financing typically:",options:["Has a first-priority claim","Is more senior and cheaper","Carries no equity upside","Is more junior and costlier, often with PIK and warrants"],correct:3,explanation:"Mezzanine sits below second lien, prices higher, and frequently includes PIK interest and an equity kicker such as warrants. The other answers describe more senior debt.",difficulty:"hard",topic:"Capital Structure"},
{q:"A revolving credit facility differs from a term loan in that it:",options:["Can be drawn and repaid repeatedly, with a fee on the undrawn portion","Has no fees","Cannot be repaid until maturity","Always carries the highest interest rate"],correct:0,explanation:"A revolver can be drawn, repaid, and redrawn, and charges a commitment fee on the undrawn balance. The other answers describe term debt or are simply false.",difficulty:"hard",topic:"Capital Structure"},
{q:"Two structures buy the same 1000 EV asset that exits at 1400 in one year. Structure A: 1000 equity. Structure B: 600 debt and 400 equity, debt unchanged. Ignoring interest and taxes, what are the equity returns?",options:["40% unlevered, 40% levered","40% unlevered, 100% levered","40% unlevered, 60% levered","100% unlevered, 40% levered"],correct:1,explanation:"A: (1400-1000)/1000 = 40%. B: exit equity = 1400 - 600 = 800 on 400 invested = 100%. Leverage amplifies the equity return. The other answers understate or swap the figures.",difficulty:"hard",topic:"Capital Structure"},
{q:"High-yield bonds often carry call protection (for example, non-call 3). For a sponsor planning an early refinancing or sale, this:",options:["Allows free early repayment","Lowers the coupon to zero","Adds a prepayment premium to early redemption","Has no cost to the issuer"],correct:2,explanation:"Call protection requires paying a make-whole or call premium to redeem early, raising the cost of an early refinancing or exit. The other answers ignore that cost.",difficulty:"hard",topic:"Capital Structure"},
{q:"A leveraged loan is usually floating rate (SOFR-based) while high-yield bonds are usually fixed rate. In a rising-rate environment, the loan borrower:",options:["Pays less as rates rise","Is unaffected by rates","Pays more as rates rise","Pays a fixed coupon regardless"],correct:2,explanation:"Floating-rate loan coupons reset higher as SOFR rises, increasing cash interest, unlike fixed-rate bonds. The other answers describe fixed-rate behavior.",difficulty:"hard",topic:"Capital Structure"},
{q:"A unitranche facility is best described as:",options:["A revolver only","Pure equity financing","Government-guaranteed debt","A single blended senior-plus-sub facility at one rate"],correct:3,explanation:"A unitranche combines what would be senior and subordinated debt into one facility at a single blended rate, common in middle-market deals. The other answers are unrelated instruments.",difficulty:"hard",topic:"Capital Structure"},
{q:"A maintenance covenant requires interest coverage of at least 2.0x. EBITDA is 180 and interest is 75. What is the coverage cushion above the minimum?",options:["2.4x","0.4x","0.2x","4.4x"],correct:1,explanation:"Actual coverage = 180/75 = 2.4x; cushion above the 2.0x minimum = 0.4x. 0.2x miscomputes the ratio. 2.4x reports the level, not the cushion. 4.4x adds rather than subtracts.",difficulty:"hard",topic:"Capital Structure"},
{q:"Free cash flow swept under a credit agreement typically repays debt in what order?",options:["Senior tranches before junior","Pro rata across all tranches always","Equity before debt","Junior tranches first"],correct:0,explanation:"Mandatory and swept paydowns generally hit the most senior tranches first (revolver and term loan) before junior debt. The other orderings violate the priority of payments.",difficulty:"hard",topic:"Capital Structure"},
{q:"On a 1000 EV deal (EBITDA 125), raising leverage from 5.0x to 6.0x changes the required equity by how much (ignore fees)?",options:["Equity rises 125","Equity falls 62.5","Equity falls 100","Equity falls 125"],correct:3,explanation:"Debt rises from 625 to 750, so equity falls from 375 to 250, a 125 reduction. 100 uses a 0.8x increment. The rise answer has the sign backward. 62.5 halves the change.",difficulty:"hard",topic:"Capital Structure"},
{q:"Distressed value is 700. Claims in priority: 400 first lien, 300 second lien, 200 unsecured. What does each class recover?",options:["First 400, second 200, unsecured 100","First 400, second 300, unsecured 0","Pro rata 78% each","First 400, second 300, unsecured 200"],correct:1,explanation:"First lien takes 400, leaving 300 for second lien (paid in full), leaving 0 for unsecured. The 200/100 answer underpays second lien. Pro rata ignores priority. The last overpays unsecured beyond available value.",difficulty:"hard",topic:"Capital Structure"},
{q:"Before a recap: EBITDA 200, debt 600 at 7% (interest 42). The company raises 300 more debt at 9% to fund a dividend. What is the new EBITDA-to-interest coverage?",options:["2.90x","2.47x","3.17x","4.76x"],correct:0,explanation:"New interest = 42 + 300 x 9% = 69; coverage = 200/69 = 2.90x. 4.76x forgets the new interest. 3.17x prices the new debt at 7%. 2.47x reprices the entire 900 at 9%.",difficulty:"hard",topic:"Capital Structure"},
{q:"Pro forma EBITDA 250 (including 50 from an add-on bought for 300 of new debt). Existing net debt 800. What is pro forma net leverage?",options:["5.5x","4.4x","3.2x","4.0x"],correct:1,explanation:"PF net debt = 800 + 300 = 1100; leverage = 1100/250 = 4.4x. 5.5x forgets the add-on EBITDA. 3.2x forgets the new debt. 4.0x uses a 275 EBITDA.",difficulty:"hard",topic:"Capital Structure"},
{q:"A bond bought below par has a yield to maturity that is:",options:["Equal to the coupon rate","Always zero","Lower than its current yield","Higher than its current yield"],correct:3,explanation:"Buying below par adds a pull-to-par capital gain, so YTM exceeds the current yield (which exceeds the coupon). The other answers misorder these yields.",difficulty:"hard",topic:"Capital Structure"},
{q:"An LBO is done at 9x EBITDA (EBITDA 150, EV 1350) with 6.0x of debt. What are the loan-to-value and the equity cushion as a percentage of EV?",options:["33% LTV, 67% equity cushion","67% LTV, 33% equity cushion","60% LTV, 40% equity cushion","67% LTV, 67% equity cushion"],correct:1,explanation:"Debt = 900; LTV = 900/1350 = 66.7%; equity cushion = 33.3%. The first wrong answer swaps the two. 60/40 uses a 5.4x debt level. The last is internally inconsistent (sums above 100%).",difficulty:"hard",topic:"Capital Structure"},
{q:"A platform is bought at 10x EBITDA and acquires three add-ons at 6x each, each with 20 of EBITDA. Marking the add-ons at the platform's 10x, what value comes purely from the multiple difference?",options:["600","240","80","360"],correct:1,explanation:"Per add-on arbitrage = (10 - 6) x 20 = 80; three add-ons = 240. 80 counts one add-on. 360 is the purchase cost (6x x 60). 600 is the gross value at 10x, not the arbitrage.",difficulty:"hard",topic:"Value Creation"},
{q:"Revenue is 1000 at a 20% EBITDA margin. A cost program lifts the margin to 25% with revenue flat. At a constant 9x exit multiple, how much enterprise value is created?",options:["50","2250","450","405"],correct:2,explanation:"EBITDA rises from 200 to 250 (delta 50); EV created = 50 x 9 = 450. 50 is the EBITDA delta, not the EV. 2250 is the total exit EV. 405 uses a 4.5-point margin gain.",difficulty:"hard",topic:"Value Creation"},
{q:"EBITDA grows from 120 to 168 purely from revenue growth at a constant 25% margin and a constant 8x multiple. What enterprise value is created from the growth?",options:["960","48","384","1344"],correct:2,explanation:"EBITDA delta = 48; EV created = 48 x 8 = 384. 48 is the EBITDA delta only. 1344 is the total exit EV. 960 is the entry EV.",difficulty:"hard",topic:"Value Creation"},
{q:"Over a 5-year hold a company repays 300 of net debt from free cash flow with no change in EBITDA or multiple. The effect on value is:",options:["Equity value is unchanged","Equity value rises 300","Equity value falls 300","Enterprise value rises 300"],correct:1,explanation:"With EV constant, repaying 300 of net debt shifts 300 of value from creditors to equity, so equity value rises 300. EV does not change, and the equity effect is positive, not zero or negative.",difficulty:"hard",topic:"Value Creation"},
{q:"A platform at 8x buys an add-on (25 EBITDA) for 5x (125) with debt, and synergies add 5 of EBITDA. Marking the add-on plus synergies at 8x, what value is created net of the price?",options:["25","75","40","115"],correct:3,explanation:"Value at 8x = (25 + 5) x 8 = 240; net of 125 cost = 115. 75 ignores synergies. 25 marks at the 5x purchase multiple. 40 prices the cost at 8x.",difficulty:"hard",topic:"Value Creation"},
{q:"A company reduces net working capital by 40 through better receivables and inventory management. The immediate effect on exit equity value, all else equal, is roughly:",options:["Equity value down 40","Equity value up 40 times the multiple","No effect on equity value","Equity value up about 40 (one-time cash release)"],correct:3,explanation:"A working-capital release is a one-time cash inflow of about 40 that pays down debt or builds cash, raising equity value by roughly 40. It is not multiplied (it is not recurring EBITDA), and the sign is positive.",difficulty:"hard",topic:"Value Creation"},
{q:"Cutting growth capex raises near-term free cash flow, but the main risk to the value-creation thesis is that it:",options:["Reduces current free cash flow","Can impair future growth and the exit value","Has no downside","Always increases the exit multiple"],correct:1,explanation:"Starving the business of growth investment can hurt future revenue and the exit multiple, undermining the thesis even as near-term FCF rises. The other answers are false.",difficulty:"hard",topic:"Value Creation"},
{q:"EBITDA rose from 100 to 160. Price/volume added 35, cost savings added 15, and a bolt-on added 10. What share of the EBITDA growth was organic?",options:["58.3%","100.0%","83.3%","16.7%"],correct:2,explanation:"Organic = 35 + 15 = 50 of the 60 total growth = 83.3%. 100.0% counts the acquisition as organic. 58.3% counts only price/volume. 16.7% is the inorganic share.",difficulty:"hard",topic:"Value Creation"},
{q:"When a sponsor pays a high entry multiple, the most reliable lever for strong returns is usually:",options:["Dividend recaps","Multiple expansion","Maximum leverage","Operational EBITDA growth"],correct:3,explanation:"At a high entry multiple, further multiple expansion is unlikely and leverage is constrained, so operational EBITDA growth becomes the dependable return driver. The other levers are unreliable or risky here.",difficulty:"hard",topic:"Value Creation"},
{q:"A 2% price increase on 1000 of revenue flows fully to EBITDA with no volume loss. At a 10x exit multiple, the value created is:",options:["100","200","2","20"],correct:1,explanation:"Price adds 2% x 1000 = 20 to EBITDA; EV created = 20 x 10 = 200. 20 is the EBITDA delta only. 100 uses a 5x multiple. 2 uses a 1% price change without the multiple.",difficulty:"hard",topic:"Value Creation"},
{q:"A roll-up creates value beyond cost synergies primarily when:",options:["The larger combined entity re-rates to a higher multiple","Each target is sold separately","The platform pays a higher multiple for add-ons","Leverage is reduced to zero"],correct:0,explanation:"Beyond synergies, value comes from the combined, larger, more diversified business commanding a higher exit multiple than the small targets were bought at. The other answers describe the opposite or unrelated actions.",difficulty:"hard",topic:"Value Creation"},
{q:"Entry EBITDA 100 (1000 revenue at 10% margin). At exit, revenue is 1300 and the margin 14%, multiple constant at 9x. What is the enterprise value created versus entry?",options:["738","270","1638","360"],correct:0,explanation:"Exit EBITDA = 1300 x 14% = 182; delta 82; EV created = 82 x 9 = 738. 270 holds the margin at 10%. 360 holds revenue at 1000. 1638 is the total exit EV, not the value created.",difficulty:"hard",topic:"Value Creation"},
{q:"A common operational value-creation lever that does not appear directly in an EBITDA bridge is:",options:["Upgrading management and governance","Paying a dividend","Increasing leverage","Raising the entry multiple"],correct:0,explanation:"Professionalizing management and governance enables the other levers but is not itself a line in an EBITDA bridge. Raising the entry multiple, leverage, and dividends are financial, not operational value creation.",difficulty:"hard",topic:"Value Creation"},
{q:"The purpose of a sponsor's first-100-days plan is mainly to:",options:["Exit the investment quickly","Eliminate all debt immediately","Establish priorities and the value-creation roadmap early","Maximize the entry multiple"],correct:2,explanation:"The 100-day plan sets early priorities, quick wins, and the value-creation roadmap under new ownership. The other answers describe unrelated or counterproductive aims.",difficulty:"hard",topic:"Value Creation"},
{q:"A company generates 80 of free cash flow per year for 5 years, all used to pay down debt, with EBITDA and the multiple unchanged. By how much does equity value rise at exit from deleveraging alone?",options:["400","2000","80","320"],correct:0,explanation:"Cumulative paydown = 80 x 5 = 400, all of which accrues to equity since EV is unchanged. 80 is a single year. 320 counts only 4 years. 2000 wrongly multiplies the paydown.",difficulty:"hard",topic:"Value Creation"},
{q:"A platform trades at an implied 9x. It buys an add-on with 30 EBITDA at 6x (180), and the blended entity is immediately marked at 9x. What is the instantaneous value created?",options:["270","120","90","0"],correct:2,explanation:"Add-on marked at 9x = 270; net of the 180 cost = 90. 0 marks it at the 6x purchase price (no arbitrage). 270 is the gross value, not net. 120 uses a 10x platform multiple.",difficulty:"hard",topic:"Value Creation"},
{q:"A take-private targets 25 of annual cost synergies. At a 10x multiple, the value of fully realized synergies is:",options:["2500","125","250","25"],correct:2,explanation:"Value = 25 x 10 = 250. 25 is the annual amount only. 125 uses a 5x multiple. 2500 multiplies by 100 rather than 10.",difficulty:"hard",topic:"Value Creation"},
{q:"Investors generally regard value created through organic EBITDA growth versus through financial leverage as:",options:["Leverage is always preferable","Organic growth is higher quality than leverage","They are identical in quality","Organic growth destroys value"],correct:1,explanation:"Organic growth is seen as higher quality and more repeatable, whereas leverage amplifies returns and risk without creating fundamental value. The other answers are false.",difficulty:"hard",topic:"Value Creation"},
{q:"Using free cash flow to pay down debt rather than take a dividend recap during the hold primarily:",options:["Has no effect on returns","Builds equity value and lowers risk","Increases leverage","Reduces equity value"],correct:1,explanation:"Deleveraging shifts value to equity and reduces risk, though it forgoes the earlier cash return an IRR-boosting recap would provide. The other answers misstate the effect.",difficulty:"hard",topic:"Value Creation"},
{q:"EBITDA is held at 150. Selling at 11x instead of the 9x paid at entry creates how much value from re-rating alone?",options:["150","300","1650","1350"],correct:1,explanation:"Re-rating value = (11 - 9) x 150 = 300. 1350 is the entry EV. 1650 is the exit EV. 150 is the EBITDA.",difficulty:"hard",topic:"Value Creation"},
{q:"In a typical broad sell-side auction, what is the usual order of buyer steps?",options:["Exclusivity before any bid","CIM and IOI, then diligence, then binding LOI and exclusivity","Binding LOI first, then the CIM","Signing before due diligence"],correct:1,explanation:"Buyers sign an NDA and receive the CIM, submit non-binding IOIs, attend management presentations and access the data room, then submit binding LOIs, after which exclusivity and signing follow. The other sequences invert these stages.",difficulty:"hard",topic:"Deal Process"},
{q:"What distinguishes an indication of interest (IOI) from a letter of intent (LOI)?",options:["They are the same document","IOI is an early non-binding range; LOI is a later detailed proposal","LOI comes before the IOI","IOI is fully binding"],correct:1,explanation:"An IOI is a preliminary, non-binding valuation range submitted early; an LOI is a later, more detailed proposal often accompanied by exclusivity. The other answers reverse the order or confuse the two.",difficulty:"hard",topic:"Deal Process"},
{q:"A quality-of-earnings (QoE) report in buy-side diligence primarily aims to:",options:["Validate and normalize reported EBITDA","Replace the legal SPA","Audit the buyer's financing","Set the management option pool"],correct:0,explanation:"A QoE assesses the accuracy and sustainability of reported EBITDA, scrutinizing one-times, accruals, and accounting policies. It is unrelated to buyer financing, the option pool, or the legal agreement.",difficulty:"hard",topic:"Deal Process"},
{q:"Under a locked-box purchase price mechanism, the equity price is:",options:["Adjusted after closing via completion accounts","Always lower than completion-accounts pricing","Fixed at a prior date with no post-closing true-up","Set only at closing"],correct:2,explanation:"A locked box fixes the equity price at a past balance-sheet date, with economic risk and reward passing to the buyer from that date and no post-closing working-capital true-up. The other answers describe completion accounts or are false.",difficulty:"hard",topic:"Deal Process"},
{q:"A deal sets a net working capital peg of 100. At close, delivered NWC is 115. How does the purchase price adjust?",options:["No adjustment","Buyer pays 15 less","Buyer pays 15 more","Seller pays 15"],correct:2,explanation:"Delivering 15 of working capital above the peg increases the price, so the buyer pays 15 more. The other answers reverse the direction or ignore the true-up.",difficulty:"hard",topic:"Deal Process"},
{q:"A target is sold cash-free, debt-free at an enterprise value of 800. At close it has 60 of cash and 200 of debt. What equity proceeds does the seller receive?",options:["540","600","860","660"],correct:3,explanation:"Equity = EV - debt + cash = 800 - 200 + 60 = 660. 600 ignores the cash. 860 ignores the debt. 540 subtracts the cash instead of adding it.",difficulty:"hard",topic:"Deal Process"},
{q:"An earnout in an acquisition is used primarily to:",options:["Guarantee the seller a fixed price","Pay the banker's fee","Bridge a valuation gap via future performance","Replace due diligence"],correct:2,explanation:"An earnout ties part of the consideration to post-closing performance, bridging differing buyer and seller valuations. It is not a fee mechanism, a substitute for diligence, or a fixed-price guarantee.",difficulty:"hard",topic:"Deal Process"},
{q:"Representations and warranties insurance in a deal mainly:",options:["Replaces the QoE","Shifts breach risk to an insurer, reducing escrow needs","Guarantees the deal closes","Insures the buyer's debt"],correct:1,explanation:"R&W insurance transfers the risk of breaches of seller representations to an insurer, shrinking escrows and indemnities and easing a clean exit for sellers. It does not insure debt, replace diligence, or guarantee closing.",difficulty:"hard",topic:"Deal Process"},
{q:"A portion of the purchase price held in escrow at closing primarily:",options:["Secures the seller's indemnity obligations","Funds the buyer's equity","Is never returned to the seller","Pays ongoing management fees"],correct:0,explanation:"An escrow or holdback backstops the seller's indemnification for a defined period and is released if no valid claims arise. The other answers misstate its purpose.",difficulty:"hard",topic:"Deal Process"},
{q:"Granting a buyer exclusivity (a no-shop) during late-stage diligence:",options:["Forces an immediate signing","Stops the seller from shopping the deal for a set period","Guarantees a higher price","Is binding for the life of the target"],correct:1,explanation:"Exclusivity prevents the seller from soliciting other bidders for a set window so the buyer can commit to confirmatory diligence. It does not set price, last indefinitely, or force signing.",difficulty:"hard",topic:"Deal Process"},
{q:"Stapled financing offered by the sell-side advisor:",options:["Is a buyer-side advisory fee","Is equity provided by the seller","Eliminates the need for an SPA","Is a pre-arranged debt package offered to bidders"],correct:3,explanation:"Stapled financing is a pre-negotiated debt package the advisor offers bidders, setting a financing benchmark and accelerating the process. It is not seller equity, a substitute for the SPA, or a buyer fee.",difficulty:"hard",topic:"Deal Process"},
{q:"A material adverse change (MAC) clause in a purchase agreement:",options:["Forces the buyer to close regardless","Sets the management equity pool","Allows the buyer to exit on a defined adverse event","Applies only after closing"],correct:2,explanation:"A MAC clause lets the buyer terminate or renegotiate if a defined materially adverse event affects the target before closing. The other answers contradict its function.",difficulty:"hard",topic:"Deal Process"},
{q:"In a large US acquisition, an HSR filing is required to:",options:["Register the new debt","Obtain antitrust clearance before closing","Set the purchase price","Pay the seller's taxes"],correct:1,explanation:"An HSR filing initiates US antitrust review, a regulatory condition that must clear before closing. It has nothing to do with debt registration, pricing, or taxes.",difficulty:"hard",topic:"Deal Process"},
{q:"After signing an LOI with exclusivity, confirmatory due diligence focuses on:",options:["Marketing the company to other buyers","Negotiating the teaser","Raising the seller's price floor","Verifying the bid's assumptions before the definitive agreement"],correct:3,explanation:"Confirmatory diligence validates the financial, legal, commercial, and tax assumptions underlying the bid before the SPA is signed. The other answers describe earlier or unrelated steps.",difficulty:"hard",topic:"Deal Process"},
{q:"A reverse termination fee is paid by:",options:["The buyer, if it fails to close","The seller, if it accepts a higher bid","Neither party","The advisor, on a failed process"],correct:0,explanation:"A reverse termination fee compensates the seller when the buyer fails to close, for example due to a financing or regulatory failure. A break fee (the seller's version) covers a seller walking to a higher bid.",difficulty:"hard",topic:"Deal Process"},
{q:"Requiring management to roll over a portion of their proceeds into the new deal mainly:",options:["Reduces the purchase price for LPs","Is a regulatory requirement","Replaces the sponsor's equity check","Aligns management with the sponsor"],correct:3,explanation:"A management rollover keeps the team invested alongside the sponsor, aligning incentives for the value-creation plan. It is not a price reduction, a substitute for the sponsor's equity, or a regulatory mandate.",difficulty:"hard",topic:"Deal Process"},
{q:"Preliminary equity price was set with closing cash 50 and debt 180 on an 800 EV. Final figures are cash 40 and debt 200. How does final equity price compare with preliminary?",options:["Unchanged","Lower by 10","Higher by 30","Lower by 30"],correct:3,explanation:"Preliminary equity = 800 - 180 + 50 = 670; final = 800 - 200 + 40 = 640; the final price is lower by 30. The other answers get the direction or magnitude wrong.",difficulty:"hard",topic:"Deal Process"},
{q:"A confidential information memorandum (CIM) is:",options:["The buyer's financing commitment","A one-page anonymous teaser","A detailed marketing document sent after an NDA","The binding purchase agreement"],correct:2,explanation:"The CIM is the detailed marketing document shared with interested buyers once an NDA is signed. The teaser is the short anonymous precursor; the SPA and financing commitments are separate documents.",difficulty:"hard",topic:"Deal Process"},
{q:"A virtual data room in a sale process is used to:",options:["Execute the wire transfer","Store the buyer's fund documents","Replace management presentations","Securely share diligence materials with bidders"],correct:3,explanation:"A data room securely hosts diligence materials for vetted bidders to review. It does not store the buyer's fund documents, move money, or replace live management presentations.",difficulty:"hard",topic:"Deal Process"},
{q:"In an SPA, a deductible-style basket and a cap on indemnification:",options:["Apply only to the buyer's reps","Increase the purchase price","Limit the seller's post-closing liability","Eliminate all seller obligations"],correct:2,explanation:"A basket screens out small claims and a cap limits aggregate exposure, together bounding the seller's post-closing indemnity liability. They do not change price, apply only to buyer reps, or remove all obligations.",difficulty:"hard",topic:"Deal Process"}
];

const ACCT_DIAG: DrillQ[] = [
  {q:"A firm records $120,000 of additional depreciation this year at a 25% tax rate. All else equal, how does net income change?",options:["$90,000 decrease","$150,000 decrease","$120,000 decrease","$30,000 decrease"],correct:0,explanation:"Depreciation is pretax; net income falls by 120,000 x (1 - 0.25) = $90,000. Trap $120,000: forgot the tax shield and used the pretax amount. Trap $30,000: counted only the tax portion. Trap $150,000: added tax instead of subtracting it.",difficulty:"hard",topic:"Financial Reporting"},
  {q:"That same $120,000 of additional depreciation at a 25% tax rate: what is the net effect on cash flow from operations, all else equal?",options:["$30,000 increase","$120,000 increase","$0 change","$90,000 decrease"],correct:0,explanation:"Net income falls $90,000 but depreciation of $120,000 is added back, netting to the tax saving of $30,000 cash inflow. Trap $90,000 decrease: stopped at the net income hit. Trap $120,000 increase: added back depreciation but ignored the lower net income. Trap $0: assumed a non-cash item has no cash effect, ignoring taxes.",difficulty:"hard",topic:"Financial Reporting"},
  {q:"Book depreciation is $100,000 and tax depreciation is $160,000 in the same year at a 25% tax rate. What deferred tax balance arises?",options:["DTA of $15,000","DTL of $60,000","DTL of $15,000","DTL of $25,000"],correct:2,explanation:"Tax depreciation exceeds book by $60,000, a taxable temporary difference, so DTL = 60,000 x 0.25 = $15,000. Trap DTA: faster tax deductions create a liability, not an asset. Trap $60,000: used the pretax difference, not the tax effect. Trap $25,000: applied the rate to book depreciation alone.",difficulty:"hard",topic:"Financial Reporting"},
  {q:"A firm accrues $80,000 of warranty expense that is not deductible for tax until paid, at a 25% rate. What deferred tax item results?",options:["DTA of $20,000","DTA of $60,000","DTA of $80,000","DTL of $20,000"],correct:0,explanation:"The expense hits book now but tax later, a deductible temporary difference, so DTA = 80,000 x 0.25 = $20,000. Trap DTL: deferring a deduction creates an asset, not a liability. Trap $80,000: used the pretax accrual. Trap $60,000: applied the after-tax figure instead of the rate.",difficulty:"hard",topic:"Financial Reporting"},
  {q:"During the year accounts receivable rose $50,000, inventory rose $30,000, and accounts payable rose $20,000. What is the combined effect on operating cash flow?",options:["$60,000 increase","$100,000 decrease","$20,000 decrease","$60,000 decrease"],correct:3,explanation:"Higher AR and inventory use cash (-80,000); higher AP provides cash (+20,000); net $60,000 decrease. Trap $100,000: treated the AP increase as a use of cash. Trap increase: flipped the sign on the asset build. Trap $20,000: counted only the payables change.",difficulty:"hard",topic:"Financial Reporting"},
  {q:"A company writes down obsolete inventory by $40,000 at a 25% tax rate. How does net income change?",options:["$10,000 decrease","$40,000 decrease","$50,000 decrease","$30,000 decrease"],correct:3,explanation:"The write-down is pretax; net income falls 40,000 x 0.75 = $30,000. Trap $40,000: ignored the tax benefit. Trap $10,000: used only the tax portion. Trap $50,000: added tax rather than subtracting.",difficulty:"hard",topic:"Financial Reporting"},
  {q:"A $500,000 outlay could be expensed now or capitalized and depreciated straight-line over 5 years, tax rate 25%. By how much is year-1 net income higher if capitalized rather than expensed?",options:["$75,000 higher","$300,000 higher","$400,000 higher","$375,000 higher"],correct:1,explanation:"Expensing cuts NI by 500,000 x 0.75 = 375,000; capitalizing cuts it by 100,000 x 0.75 = 75,000; difference $300,000. Trap $400,000: used the pretax expense gap. Trap $375,000: gave the full expensing hit, not the difference. Trap $75,000: gave the capitalized hit alone.",difficulty:"hard",topic:"Financial Reporting"},
  {q:"A firm books a $200,000 asset impairment that is deductible for tax at a 25% rate. What is the effect on net income?",options:["$250,000 decrease","$200,000 decrease","$50,000 decrease","$150,000 decrease"],correct:3,explanation:"Net income falls 200,000 x 0.75 = $150,000. Trap $200,000: ignored the tax effect. Trap $50,000: used only the tax benefit. Trap $250,000: added tax instead of subtracting.",difficulty:"hard",topic:"Financial Reporting"},
  {q:"A firm records a $300,000 goodwill impairment that is not deductible for tax (rate 25%). What is the effect on net income?",options:["$375,000 decrease","$75,000 decrease","$225,000 decrease","$300,000 decrease"],correct:3,explanation:"With no tax deduction, the full $300,000 reduces net income; there is no tax shield. Trap $225,000: wrongly applied a 25% tax shield to a non-deductible charge. Trap $75,000: used only a tax portion that does not exist here. Trap $375,000: grossed it up by tax.",difficulty:"hard",topic:"Financial Reporting"},
  {q:"A firm pays $80,000 of interest at a 25% tax rate. What is the value of the interest tax shield?",options:["$20,000 increase","$80,000 increase","$80,000 decrease","$60,000 decrease"],correct:0,explanation:"The tax shield equals interest x rate = 80,000 x 0.25 = $20,000 of tax saved. Trap $80,000 decrease: that is the pretax cash interest, not the shield. Trap $60,000 decrease: the after-tax cost of the interest. Trap $80,000 increase: wrong sign and magnitude.",difficulty:"hard",topic:"Financial Reporting"},
  {q:"A firm buys 100 units at $10 then 100 units at $12, and sells 150 units. By how much does LIFO COGS exceed FIFO COGS?",options:["$300","$100","$1,700","$0"],correct:1,explanation:"FIFO COGS = 100x10 + 50x12 = 1,600; LIFO COGS = 100x12 + 50x10 = 1,700; difference $100. Trap $0: assumed flows are identical. Trap $300: applied the $2 price gap to all 150 units. Trap $1,700: gave total LIFO COGS, not the difference.",difficulty:"hard",topic:"Financial Reporting"},
  {q:"Credit sales are $2,000,000 and the firm estimates 1.5% uncollectible using the percentage-of-sales method. The allowance already has a $5,000 credit balance. What is bad debt expense?",options:["$35,000","$25,000","$30,000","$300,000"],correct:2,explanation:"Percentage-of-sales books expense directly: 2,000,000 x 1.5% = $30,000; the existing balance is not netted. Trap $25,000: netted the prior balance, which is the percentage-of-receivables method. Trap $35,000: added the balance. Trap $300,000: misplaced the decimal on the rate.",difficulty:"hard",topic:"Financial Reporting"},
  {q:"Pretax book income is $1,000,000 and includes $100,000 of non-deductible fines. The statutory rate is 21%. What is the effective tax rate?",options:["18.9%","25%","21%","23.1%"],correct:3,explanation:"Taxable income = 1,100,000; tax = 231,000; ETR = 231,000/1,000,000 = 23.1%. Trap 21%: ignored the permanent difference. Trap 18.9%: subtracted the fine instead of adding it back. Trap 25%: a guessed round rate.",difficulty:"hard",topic:"Financial Reporting"},
  {q:"A finance lease records a $500,000 right-of-use asset depreciated straight-line over 5 years, with a 6% rate on the $500,000 opening liability. What is total year-1 lease expense?",options:["$130,000","$100,000","$30,000","$115,000"],correct:0,explanation:"Depreciation 500,000/5 = 100,000 plus interest 500,000 x 6% = 30,000 totals $130,000. Trap $100,000: counted depreciation only. Trap $30,000: counted interest only. Trap $115,000: used half a year of interest.",difficulty:"hard",topic:"Financial Reporting"},
  {q:"Net income includes $60,000 of stock-based compensation expense. Using the indirect method, what is the adjustment in cash flow from operations?",options:["$60,000 decrease","$0 change","$45,000 increase","$60,000 increase"],correct:3,explanation:"Stock comp is non-cash, so it is added back: $60,000 increase to operating cash flow. Trap $0: treated it as if it had no statement effect. Trap $60,000 decrease: wrong sign on the add-back. Trap $45,000 increase: applied a tax adjustment that does not belong on the add-back.",difficulty:"hard",topic:"Financial Reporting"},
  {q:"A firm sells equipment with $100,000 net book value for $140,000 cash. What does it report in investing cash flow from the sale?",options:["$60,000 increase","$40,000 increase","$140,000 increase","$100,000 increase"],correct:2,explanation:"Investing shows the full cash proceeds of $140,000; the $40,000 gain is removed from operating cash flow, not added to investing. Trap $40,000: reported only the gain. Trap $100,000: used book value instead of cash received. Trap $60,000: double-subtracted the gain.",difficulty:"hard",topic:"Financial Reporting"},
  {q:"A firm accrues but does not yet pay $50,000 of expense at a 25% tax rate. What is the effect on net income this period?",options:["$50,000 decrease","$0 change","$12,500 decrease","$37,500 decrease"],correct:3,explanation:"Accrual recognizes the expense now; net income falls 50,000 x 0.75 = $37,500. Trap $50,000: ignored the tax effect. Trap $12,500: used only the tax portion. Trap $0: assumed no expense until cash is paid, which is cash-basis thinking.",difficulty:"hard",topic:"Financial Reporting"},
  {q:"A firm pays $120,000 on October 1 for a 12-month insurance policy. By December 31, how much insurance expense is recognized?",options:["$90,000","$10,000","$30,000","$120,000"],correct:2,explanation:"Three of twelve months are used: 120,000 x 3/12 = $30,000. Trap $120,000: expensed the whole payment immediately. Trap $90,000: reported the remaining prepaid asset, not the expense. Trap $10,000: recognized only one month.",difficulty:"hard",topic:"Financial Reporting"},
  {q:"Gross of disposals at net book value: beginning PP&E (net) is $800,000, capex is $200,000, depreciation is $120,000, and equipment with $50,000 net book value is sold. What is ending net PP&E?",options:["$930,000","$830,000","$1,070,000","$880,000"],correct:1,explanation:"800,000 + 200,000 capex - 120,000 depreciation - 50,000 disposal = $830,000. Trap $880,000: forgot the disposal. Trap $1,070,000: added depreciation instead of subtracting. Trap $930,000: added the disposal back.",difficulty:"hard",topic:"Financial Reporting"},
  {q:"Beginning retained earnings are $500,000, net income is $150,000, and dividends declared are $40,000. What are ending retained earnings?",options:["$460,000","$610,000","$650,000","$690,000"],correct:1,explanation:"500,000 + 150,000 - 40,000 = $610,000. Trap $650,000: forgot the dividends. Trap $690,000: added dividends instead of subtracting. Trap $460,000: omitted net income.",difficulty:"hard",topic:"Financial Reporting"},
  {q:"Net income is $5,000,000, preferred dividends are $500,000, weighted-average basic shares are 1,800,000, and diluted shares are 2,000,000. What is basic EPS?",options:["$2.78","$2.50","$2.25","$3.06"],correct:1,explanation:"(5,000,000 - 500,000)/1,800,000 = $2.50. Trap $2.78: forgot to subtract preferred dividends. Trap $3.06: added preferred instead of subtracting. Trap $2.25: used diluted shares for a basic figure.",difficulty:"hard",topic:"Financial Reporting"},
  {q:"A firm collects $240,000 upfront for a 2-year service contract and recognizes ratably. What is the deferred revenue liability at the end of year 1?",options:["$0","$60,000","$240,000","$120,000"],correct:3,explanation:"Half is earned in year 1, so deferred revenue = 240,000 - 120,000 = $120,000. Trap $240,000: recognized none of it. Trap $0: recognized all of it immediately. Trap $60,000: amortized over the wrong period.",difficulty:"hard",topic:"Financial Reporting"},
  {q:"A firm has an $80,000 unrealized gain on available-for-sale debt securities at a 25% tax rate. What is the effect on net income?",options:["$80,000 increase","$0 change","$20,000 increase","$60,000 increase"],correct:1,explanation:"Unrealized AFS gains go to other comprehensive income, not net income, so net income is unchanged. Trap $60,000 increase: ran the after-tax gain through net income. Trap $80,000 increase: ran the pretax gain through net income. Trap $20,000 increase: booked only the tax portion to net income.",difficulty:"hard",topic:"Financial Reporting"},
  {q:"A parent owns 80% of a subsidiary that earns $200,000 of net income. What net income is attributable to the noncontrolling interest?",options:["$200,000","$40,000","$160,000","$19,999"],correct:1,explanation:"NCI gets the 20% it owns: 200,000 x 20% = $40,000. Trap $160,000: gave the parent's 80% share. Trap $200,000: gave the whole subsidiary income. Trap $19,999: halved the minority share.",difficulty:"hard",topic:"Financial Reporting"},
  {q:"An investor holds 30% of an associate and uses the equity method. The associate earns $500,000 and pays $100,000 in dividends. What income does the investor recognize?",options:["$500,000","$150,000","$30,000","$120,000"],correct:1,explanation:"Equity method recognizes the investor's share of net income: 30% x 500,000 = $150,000; dividends reduce the carrying value, not income. Trap $30,000: recognized 30% of dividends only. Trap $120,000: netted dividends out of income first. Trap $500,000: took the full associate income.",difficulty:"hard",topic:"Financial Reporting"},
  {q:"A firm has a $100,000 gross deferred tax asset but concludes only $60,000 is more likely than not to be realized. What net DTA is reported?",options:["$140,000","$60,000","$100,000","$40,000"],correct:1,explanation:"A valuation allowance of $40,000 reduces the gross DTA to the realizable $60,000. Trap $100,000: ignored the valuation allowance. Trap $40,000: reported the allowance itself. Trap $140,000: added the allowance instead of subtracting.",difficulty:"hard",topic:"Financial Reporting"},
  {q:"Net income is $300,000. Depreciation is $80,000, AR rose $50,000, AP rose $30,000, and there was a $20,000 gain on an asset sale. What is operating cash flow (indirect method)?",options:["$300,000","$340,000","$440,000","$380,000"],correct:1,explanation:"300,000 + 80,000 dep - 50,000 AR + 30,000 AP - 20,000 gain = $340,000. Trap $440,000: added the AR build instead of subtracting. Trap $380,000: added the gain instead of removing it. Trap $300,000: used net income with no adjustments.",difficulty:"hard",topic:"Financial Reporting"},
  {q:"Annual revenue is $3,650,000 (use 365 days). The firm cuts days sales outstanding from 60 to 45. How much cash is freed from receivables?",options:["$150,000","$600,000","$300,000","$450,000"],correct:0,explanation:"Revenue per day = 10,000; cash freed = 10,000 x (60 - 45) = $150,000. Trap $600,000: gave the old receivables balance. Trap $450,000: gave the new balance, not the change. Trap $300,000: doubled the day reduction.",difficulty:"hard",topic:"Financial Reporting"},
  {q:"A lease liability opens at $400,000 with an 8% rate; the annual payment is $100,000. What portion of the first payment reduces principal?",options:["$84,000","$100,000","$32,000","$68,000"],correct:3,explanation:"Interest = 400,000 x 8% = 32,000; principal = 100,000 - 32,000 = $68,000. Trap $32,000: gave the interest portion. Trap $100,000: treated the full payment as principal. Trap $84,000: used half a year of interest.",difficulty:"hard",topic:"Financial Reporting"},
  {q:"A DTL sits on a $500,000 taxable temporary difference at a 30% rate. The enacted rate falls to 21%. What is the remeasured DTL?",options:["$45,000","$105,000","$255,000","$150,000"],correct:1,explanation:"Remeasure at the new rate: 500,000 x 21% = $105,000. Trap $150,000: left it at the old 30% rate. Trap $45,000: gave only the change in the DTL. Trap $255,000: added both rate balances.",difficulty:"hard",topic:"Financial Reporting"},
  {q:"A firm self-constructs an asset with $2,000,000 average accumulated expenditures and a 7% capitalization rate, and incurs $200,000 total interest in the period. How much interest is capitalized?",options:["$200,000","$60,000","$140,000","$280,000"],correct:2,explanation:"Capitalize avoidable interest = 2,000,000 x 7% = $140,000, limited to actual interest of 200,000. Trap $200,000: capitalized all interest incurred. Trap $60,000: capitalized the residual expensed portion. Trap $280,000: doubled the rate base.",difficulty:"hard",topic:"Financial Reporting"},
  {q:"A lawsuit loss is probable and reliably estimable at $300,000, with a reasonably possible additional $200,000. Under the loss-contingency rules, what is recognized as a liability?",options:["$500,000, the full possible exposure","$0, since the case is unresolved","$300,000, with the additional $200,000 only disclosed","$200,000, only the incremental possible amount"],correct:2,explanation:"Accrue the probable and estimable amount ($300,000); the reasonably possible extra is disclosed, not accrued. Trap $500,000: accrued the reasonably possible portion too. Trap $200,000: accrued only the disclosable increment. Trap $0: ignored a probable, estimable loss.",difficulty:"hard",topic:"Financial Reporting"},
  {q:"A long-term contract is priced at $1,000,000 with estimated total cost of $750,000. Costs to date are $300,000. Using cost-to-cost percentage of completion, what revenue is recognized to date?",options:["$250,000","$300,000","$100,000","$400,000"],correct:3,explanation:"Percent complete = 300,000/750,000 = 40%; revenue = 40% x 1,000,000 = $400,000. Trap $300,000: recognized costs incurred as revenue. Trap $100,000: recognized the gross profit slice, not revenue. Trap $250,000: recognized the entire contract margin ignoring percent complete.",difficulty:"hard",topic:"Revenue Recognition"},
  {q:"A customer prepays $1,200 for a 12-month subscription beginning November 1. How much revenue is recognized by December 31?",options:["$200","$0","$1,200","$100"],correct:0,explanation:"Two months earned: 1,200 x 2/12 = $200. Trap $1,200: recognized the full prepayment at sale. Trap $100: recognized only one month. Trap $0: deferred everything despite service being delivered.",difficulty:"hard",topic:"Revenue Recognition"},
  {q:"A bundle sells for $100,000. Standalone selling prices are $80,000 for hardware and $40,000 for service. How much is allocated to hardware?",options:["$50,000","$33,333","$66,666","$80,000"],correct:2,explanation:"Allocate on relative SSP: 100,000 x 80,000/120,000 = $66,666. Trap $80,000: used the standalone price directly. Trap $50,000: split the bundle evenly. Trap $33,333: assigned hardware the service share.",difficulty:"hard",topic:"Revenue Recognition"},
  {q:"A marketplace facilitates $500,000 of transactions and keeps a 15% commission, acting as an agent. What revenue should it recognize?",options:["$500,000","$150,000","$75,000","$425,000"],correct:2,explanation:"As agent it recognizes the net commission: 500,000 x 15% = $75,000. Trap $500,000: recognized gross as if principal. Trap $425,000: recognized the amount passed to the seller. Trap $150,000: doubled the commission rate.",difficulty:"hard",topic:"Revenue Recognition"},
  {q:"A firm sells 1,000 units at $50 each and expects 8% to be returned. How much revenue should it recognize at sale?",options:["$46,000","$4,000","$54,000","$50,000"],correct:0,explanation:"Recognize revenue net of expected returns: 50,000 x 0.92 = $46,000. Trap $50,000: ignored expected returns. Trap $4,000: booked only the return reserve. Trap $54,000: added returns instead of subtracting.",difficulty:"hard",topic:"Revenue Recognition"},
  {q:"A firm delivers a good today but the customer pays $121,000 in two years; the financing rate is 10%. What revenue is recognized at delivery?",options:["$109,999","$99,999","$121,000","$96,800"],correct:1,explanation:"Discount for the financing component: 121,000/1.21 = $99,999; the rest is interest income over time. Trap $121,000: recognized the gross future cash. Trap $109,999: discounted only one year. Trap $96,800: used simple instead of compound discounting.",difficulty:"hard",topic:"Revenue Recognition"},
  {q:"A customer pays $100 and earns loyalty points with a $10 standalone value representing a material right. How much revenue is recognized now?",options:["$90.91","$9.09","$100","$90"],correct:0,explanation:"Allocate on relative SSP: 100 x 100/110 = $90.91; the rest is deferred for the points. Trap $100: recognized the whole payment. Trap $90: subtracted the point value directly rather than allocating. Trap $9.09: gave the amount deferred to points.",difficulty:"hard",topic:"Revenue Recognition"},
  {q:"A retailer sells $50,000 of gift cards, expects 5% breakage, and $30,000 is redeemed this period. Using the proportional method, how much revenue is recognized?",options:["$31,579","$31,500","$32,500","$30,000"],correct:0,explanation:"Recognize redemptions plus proportional breakage: 30,000 + (30,000/47,500) x 2,500 = $31,579. Trap $30,000: ignored breakage. Trap $32,500: recognized all breakage at once. Trap $31,500: applied the breakage rate to redemptions directly.",difficulty:"hard",topic:"Revenue Recognition"},
  {q:"A fixed-price contract for $1,000,000 now has an estimated total cost of $1,100,000, with $440,000 incurred so far. How is the expected loss recognized?",options:["$40,000 recognized to date","$50,000 this period","$0, deferred until completion","$100,000 recognized immediately in full"],correct:3,explanation:"An expected loss on a contract is recognized immediately in full: 1,100,000 - 1,000,000 = $100,000. Trap percent-of-loss: prorated the loss by completion, which is not allowed. Trap defer: ignored the immediate recognition rule. Trap half: arbitrarily split the loss.",difficulty:"hard",topic:"Revenue Recognition"},
  {q:"A software firm grants a perpetual license to functional software that does not change after delivery, plus separate one-year support. How is the license revenue recognized?",options:["Only when the customer first uses the software","Ratably over the license's legal life","Ratably over the one-year support term","At a point in time when the software is delivered"],correct:3,explanation:"A functional license with no ongoing changes transfers control at delivery, so revenue is point-in-time. Trap support-term: that is the support obligation, a separate performance obligation. Trap legal-life: control transfers at delivery, not over the statutory term. Trap first-use: recognition follows transfer of control, not customer usage timing.",difficulty:"hard",topic:"Revenue Recognition"},
  {q:"A contract covers 600 identical units at $200 each, recognized over time by units delivered. After 240 units ship, what revenue is recognized?",options:["$72,000","$120,000","$48,000","$24,000"],correct:2,explanation:"Output method: 240 x 200 = $48,000. Trap $120,000: recognized the full contract. Trap $24,000: halved the delivered share. Trap $72,000: recognized the undelivered units.",difficulty:"hard",topic:"Revenue Recognition"},
  {q:"A contract pays a $400,000 base plus a $100,000 bonus the firm estimates a 70% chance of earning; the expected-value method best predicts the entitlement. What transaction price is used?",options:["$470,000","$430,000","$400,000","$500,000"],correct:0,explanation:"Expected value = 400,000 + 0.70 x 100,000 = $470,000. Trap $500,000: included the full bonus with certainty. Trap $400,000: excluded the bonus entirely. Trap $430,000: used the 30% failure probability.",difficulty:"hard",topic:"Revenue Recognition"},
  {q:"A $200,000 arrangement bundles a delivered license (SSP $150,000) and one year of support (SSP $100,000). How much revenue is recognized at delivery for the license?",options:["$80,000","$120,000","$100,000","$150,000"],correct:1,explanation:"Allocate on relative SSP: 200,000 x 150,000/250,000 = $120,000 for the license at delivery. Trap $150,000: used the standalone price. Trap $80,000: gave the support share. Trap $100,000: split evenly.",difficulty:"hard",topic:"Revenue Recognition"},
  {q:"A customer asks the seller to hold paid-for goods in the seller's warehouse. Which condition is required to recognize revenue under bill-and-hold?",options:["The goods are similar to other inventory on hand","The customer has been invoiced for the goods","The seller plans to ship within the next fiscal year","The goods are separately identified as the customer's and ready to transfer"],correct:3,explanation:"Bill-and-hold revenue requires the goods be identified as the customer's, ready for transfer, and not usable by the seller. Trap ship-next-year: a future shipment plan does not transfer control now. Trap invoiced: invoicing is not control transfer. Trap similar-inventory: fungible stock fails the separately-identified test.",difficulty:"hard",topic:"Revenue Recognition"},
  {q:"Which fact pattern requires revenue to be recognized over time rather than at a point in time?",options:["The customer pays a large nonrefundable deposit upfront","The contract spans more than twelve months","The asset built has no alternative use and the seller has an enforceable right to payment for work done","The seller retains legal title until final delivery"],correct:2,explanation:"No-alternative-use plus an enforceable right to payment for performance completed is an over-time criterion. Trap deposit: payment timing does not drive the over-time test. Trap duration: a long contract can still be point-in-time. Trap retains-title: retaining title points toward point-in-time, not over time.",difficulty:"hard",topic:"Revenue Recognition"},
  {q:"A manufacturer ships goods to a dealer on consignment. When does the manufacturer recognize revenue?",options:["When the goods leave the manufacturer's dock","When the dealer is invoiced for the shipment","When the goods arrive at the dealer's location","When the dealer sells the goods to an end customer"],correct:3,explanation:"On consignment, control does not pass to the dealer, so revenue waits until the end-customer sale. Trap arrival: delivery to a consignee is not a sale. Trap invoiced: consignment shipments are not billed as sales. Trap leaves-dock: shipping does not transfer control under consignment.",difficulty:"hard",topic:"Revenue Recognition"},
  {q:"A contract is modified to add distinct goods at their standalone selling prices. How is the modification accounted for?",options:["As a cumulative catch-up to the original contract","By blending the new price into the original prospectively","As a separate contract, with no effect on the original","By reversing and re-recognizing all prior revenue"],correct:2,explanation:"Added distinct goods priced at SSP are treated as a separate contract. Trap catch-up: cumulative catch-up applies when added goods are not distinct. Trap blend-prospective: blending applies when remaining goods are distinct but not at SSP. Trap reverse-all: modifications do not require reversing recognized revenue.",difficulty:"hard",topic:"Revenue Recognition"},
  {q:"A gym charges a nonrefundable $300 initiation fee that does not transfer any distinct good or service. How is it recognized?",options:["Over the expected period the customer benefits, such as the membership life","Spread evenly over the next twelve months regardless of membership length","Entirely in the month it is collected","Only if and when the member cancels"],correct:0,explanation:"A nonrefundable upfront fee with no distinct deliverable is recognized over the expected customer relationship period. Trap month-collected: upfront recognition ignores the service period. Trap on-cancel: nonrefundable fees are earned through service, not cancellation. Trap fixed-twelve: the period is the expected benefit period, not an arbitrary year.",difficulty:"hard",topic:"Revenue Recognition"},
  {q:"Under the revenue model, collectibility of the consideration is assessed at which point?",options:["At contract inception, as a gate to having a contract at all","Only after the goods or services are delivered","When the receivable becomes more than 90 days past due","At the end of each reporting period as an impairment test"],correct:0,explanation:"Collectibility being probable is a step-one criterion for a contract to exist. Trap after-delivery: it is assessed before recognition begins. Trap 90-days: aging is a later impairment matter, not the inception gate. Trap period-end: that conflates contract existence with subsequent impairment.",difficulty:"hard",topic:"Revenue Recognition"},
  {q:"A bundle includes three obligations, and observable evidence shows a discount relates only to two of them. How is the discount allocated?",options:["To the obligation delivered last","Proportionally across all three obligations","Only to the two obligations the evidence ties it to","Entirely to the largest obligation"],correct:2,explanation:"When evidence shows a discount belongs to specific obligations, it is allocated only to those. Trap proportional-all: that is the default only without such evidence. Trap largest: size does not determine discount allocation. Trap last-delivered: timing does not drive allocation.",difficulty:"hard",topic:"Revenue Recognition"},
  {q:"A firm ships extra product to distributors near quarter-end who can return anything unsold. What is the recognition concern?",options:["Revenue timing is fine since the goods physically left the warehouse","Revenue should be grossed up for the expected returns","Revenue may be overstated because control has not truly transferred given return rights","Revenue is understated because shipping costs are expensed early"],correct:2,explanation:"Broad return rights mean control may not have transferred, so recognizing full revenue overstates it. Trap understated: the risk is overstatement, not understatement. Trap shipping-fine: physical shipment is not control transfer here. Trap gross-up: returns reduce, not increase, recognized revenue.",difficulty:"hard",topic:"Revenue Recognition"},
  {q:"A product comes with a standard assurance warranty plus an optional extended warranty sold separately. How are these treated?",options:["Both are separate performance obligations","The extended warranty is expensed and the assurance warranty is deferred","Both are cost accruals with no deferred revenue","Assurance warranty is a cost accrual; the extended warranty is a separate performance obligation"],correct:3,explanation:"An assurance warranty is accrued as a cost; an optional, separately priced warranty is a distinct service obligation with deferred revenue. Trap both-obligations: the assurance piece is not a separate obligation. Trap both-accruals: the extended warranty earns deferred revenue. Trap reversed: the treatment is backwards.",difficulty:"hard",topic:"Revenue Recognition"},
  {q:"A firm has satisfied a performance obligation but its right to payment is still conditional on completing a second obligation. What does it record?",options:["A contract asset, not a receivable","Nothing until the second obligation is done","Deferred revenue, since cash is not yet due","A receivable, since revenue is earned"],correct:0,explanation:"An unconditional right to payment is a receivable; a conditional right is a contract asset. Trap receivable: payment is still conditional, so not yet a receivable. Trap deferred-revenue: that is a liability for unearned amounts, the opposite situation. Trap nothing: revenue earned must be recorded with the corresponding contract asset.",difficulty:"hard",topic:"Revenue Recognition"},
  {q:"A $90,000 contract has three equal, distinct performance obligations at equal standalone prices. Two are delivered by year-end. What contract liability remains?",options:["$90,000","$30,000","$60,000","$0"],correct:1,explanation:"Each obligation is one third; one remains, so deferred = 90,000/3 = $30,000. Trap $90,000: deferred everything. Trap $60,000: deferred the two delivered instead of the one remaining. Trap $0: recognized all three despite one being undelivered.",difficulty:"hard",topic:"Revenue Recognition"},
  {q:"A vendor installs custom equipment that the customer must formally accept after testing before it can be used. When is revenue recognized?",options:["On shipment from the vendor's factory","When the vendor issues the final invoice","On customer acceptance, when control transfers","Evenly across the installation period"],correct:2,explanation:"When acceptance is substantive and conditions control, revenue waits for acceptance. Trap shipment: control has not transferred at shipment given the acceptance condition. Trap evenly: there is no over-time criterion stated here. Trap invoice: billing does not determine control transfer.",difficulty:"hard",topic:"Revenue Recognition"},
  {q:"An auditor sets planning materiality at 5% of pretax income. Pretax income is $4,000,000 and revenue is $40,000,000. What is planning materiality?",options:["$2,000,000","$200,000","$20,000","$400,000"],correct:1,explanation:"5% x 4,000,000 pretax income = $200,000. Trap $2,000,000: applied 5% to revenue, the wrong benchmark. Trap $400,000: used a 1%-of-revenue benchmark instead of the stated one. Trap $20,000: misplaced a decimal, using 0.5%.",difficulty:"hard",topic:"Audit"},
  {q:"Using the audit risk model, target audit risk is 5%, inherent risk is 80%, and control risk is 50%. What detection risk is required?",options:["6.2%","12.5%","40%","10%"],correct:1,explanation:"Detection risk = AR/(IR x CR) = 0.05/(0.80 x 0.50) = 12.5%. Trap 6.2%: divided by inherent risk only. Trap 10%: divided by control risk only. Trap 40%: multiplied inherent and control risk, ignoring target risk.",difficulty:"hard",topic:"Audit"},
  {q:"An auditor mails confirmations to a sample of customers about their account balances. This procedure most directly tests which assertion for receivables?",options:["Rights and obligations of unrelated parties","Existence","Completeness","Valuation at net realizable value"],correct:1,explanation:"Confirmations test whether recorded receivables exist by corroborating them with the customer. Trap completeness: confirmations of recorded balances do not catch unrecorded receivables. Trap valuation: collectibility is tested by other procedures like aging. Trap rights: confirmation does not establish legal ownership versus factoring.",difficulty:"hard",topic:"Audit"},
  {q:"To test that recorded sales actually occurred (occurrence), in which direction should the auditor test?",options:["From the customer master file to recorded sales","From shipping documents forward to the journal entries","From the bank statement to the sales ledger","From the recorded journal entry back to the shipping document and order"],correct:3,explanation:"Occurrence is tested by vouching from the recorded entry back to source evidence. Trap forward-from-shipping: tracing forward tests completeness, not occurrence. Trap bank-to-ledger: cash testing does not establish that each recorded sale occurred. Trap master-file: starting from the customer list does not test recorded sales.",difficulty:"hard",topic:"Audit"},
  {q:"An auditor attends the year-end physical inventory count and observes the client's procedures. This primarily supports which assertion?",options:["Proper revenue cutoff","Classification of long-term debt","Existence of recorded inventory","Valuation of goodwill"],correct:2,explanation:"Observing the count provides evidence that the inventory recorded actually exists. Trap revenue-cutoff: that is a separate sales test, not the count. Trap goodwill: an intangible is unrelated to a physical count. Trap debt-classification: financing classification is not addressed by counting stock.",difficulty:"hard",topic:"Audit"},
  {q:"An auditor concludes the financial statements contain misstatements that are both material and pervasive. What opinion is appropriate?",options:["Adverse opinion","Qualified opinion","Unmodified opinion with an emphasis paragraph","Disclaimer of opinion"],correct:0,explanation:"Material and pervasive misstatement leads to an adverse opinion. Trap qualified: that fits material but not pervasive misstatement. Trap unmodified-emphasis: emphasis paragraphs do not modify the opinion for misstatement. Trap disclaimer: a disclaimer addresses a pervasive scope limitation, not a known misstatement.",difficulty:"hard",topic:"Audit"},
  {q:"An auditor cannot obtain sufficient evidence over an area, and the possible effects are material but not pervasive. What opinion fits?",options:["Qualified opinion due to a scope limitation","Adverse opinion","Disclaimer of opinion","Unmodified opinion"],correct:0,explanation:"A material but not pervasive scope limitation yields a qualified opinion. Trap adverse: adverse is for pervasive misstatement, not a scope issue. Trap disclaimer: that requires the limitation to be pervasive. Trap unmodified: an unresolved evidence gap requires modification.",difficulty:"hard",topic:"Audit"},
  {q:"Management's plans do not alleviate substantial doubt about the entity continuing as a going concern, but disclosures are adequate. What does the auditor do?",options:["Withdraw from the engagement automatically","Issue an adverse opinion","Issue an unmodified opinion with a going-concern section","Issue a qualified opinion for misstatement"],correct:2,explanation:"With adequate disclosure but unresolved doubt, the opinion stays unmodified and a going-concern section is added. Trap adverse: adverse requires a material pervasive misstatement, not mere doubt. Trap withdraw: withdrawal is not automatic. Trap qualified-misstatement: there is no misstatement if disclosure is adequate.",difficulty:"hard",topic:"Audit"},
  {q:"After year-end but before issuance, a customer that owed a large receivable at the balance-sheet date declares bankruptcy due to conditions existing at year-end. How is this handled?",options:["Adjust the financial statements, since the condition existed at year-end","Restate the prior year's statements","Disclose only, with no adjustment","Ignore it as a post-period event"],correct:0,explanation:"A recognized subsequent event reflects conditions existing at the balance-sheet date, so the statements are adjusted. Trap disclose-only: that fits new conditions arising after year-end. Trap ignore: a material event before issuance cannot be ignored. Trap restate-prior: this affects the current year, not a prior-period restatement.",difficulty:"hard",topic:"Audit"},
  {q:"After year-end, a fire destroys a major plant in an event unrelated to any year-end condition, and the effect is material. How is it treated?",options:["Disclosed in the notes, with no adjustment to the year-end balances","Ignored because it happened after year-end","Adjusted into the year-end financial statements","Both adjusted and disclosed as a correction of an error"],correct:0,explanation:"A new condition arising after year-end is a nonadjusting event, disclosed but not booked into the year-end numbers. Trap adjusted: the condition did not exist at year-end, so no adjustment. Trap error-correction: it is not an error. Trap ignore: a material event still requires disclosure.",difficulty:"hard",topic:"Audit"},
  {q:"A control deficiency creates a reasonable possibility that a material misstatement would not be prevented or detected on a timely basis. How is it classified?",options:["A significant deficiency","A material weakness","An immaterial control gap","A scope limitation"],correct:1,explanation:"Reasonable possibility of a material misstatement going undetected defines a material weakness. Trap significant-deficiency: that is less severe than a material weakness. Trap immaterial: the definition explicitly involves a material misstatement. Trap scope-limitation: that is an evidence issue, not a control classification.",difficulty:"hard",topic:"Audit"},
  {q:"An auditor concludes a control is effective based on a sample, but it is actually ineffective. What does this represent?",options:["Inherent risk in the account balance","Nonsampling risk from a clerical error","The risk of assessing control risk too high","The risk of assessing control risk too low"],correct:3,explanation:"Wrongly concluding a control works when it does not is the risk of assessing control risk too low, an efficiency-and-effectiveness concern. Trap too-high: that is wrongly rejecting an effective control. Trap nonsampling: this stems from the sample not representing the population, which is sampling risk. Trap inherent-risk: inherent risk is unrelated to the sample conclusion.",difficulty:"hard",topic:"Audit"},
  {q:"In the fraud triangle, an employee facing large personal debts who believes the company underpays them exhibits which two elements before acting?",options:["Pressure and rationalization","Detection risk and control risk","Materiality and pervasiveness","Opportunity and collusion"],correct:0,explanation:"Personal debt is pressure and the belief about underpayment is rationalization; opportunity is the missing third element. Trap opportunity-collusion: opportunity is not yet described and collusion is not part of the triangle. Trap materiality-pervasiveness: those are opinion concepts, not fraud-triangle elements. Trap detection-control-risk: those are audit-risk components, not motives.",difficulty:"hard",topic:"Audit"},
  {q:"Auditors are required to address the risk of management override of controls on every audit. Which procedure specifically targets it?",options:["Confirming bank balances with financial institutions","Observing the physical inventory count","Testing the appropriateness of journal entries and other adjustments","Recalculating depreciation schedules"],correct:2,explanation:"Examining journal entries and adjustments targets the override risk because overrides often run through manual entries. Trap bank-confirmations: those address existence of cash, not override. Trap inventory-observation: that supports existence of stock. Trap recompute-depreciation: that tests an estimate, not override.",difficulty:"hard",topic:"Audit"},
  {q:"Under fraud risk standards, auditors ordinarily presume which area carries a significant fraud risk?",options:["Prepaid expense amortization","Office supplies expense","Petty cash disbursements","Improper revenue recognition"],correct:3,explanation:"There is a rebuttable presumption that revenue recognition poses a fraud risk. Trap petty-cash: low-value and not a presumed fraud risk. Trap prepaid-amortization: a routine low-risk calculation. Trap office-supplies: immaterial and not presumed risky.",difficulty:"hard",topic:"Audit"},
  {q:"During final review, the auditor performs analytical procedures and finds gross margin jumped sharply with no business reason. What is the appropriate response?",options:["Disclose the improvement as a positive note","Conclude the statements are fairly stated since totals foot","Investigate the unexpected fluctuation with additional procedures","Reduce substantive testing because margin improved"],correct:2,explanation:"An unexpected, unexplained fluctuation is a red flag requiring further investigation. Trap totals-foot: arithmetic footing does not explain the anomaly. Trap reduce-testing: an anomaly calls for more, not less, work. Trap disclose-positive: the auditor must understand the cause before drawing comfort.",difficulty:"hard",topic:"Audit"},
  {q:"The auditor identifies a large sale to an entity owned by the CEO's spouse. What is the primary concern?",options:["Whether the customer paid by wire transfer","Whether the goods were delivered on time","Whether the transaction was at arm's length and properly disclosed","Whether the sale increased reported revenue"],correct:2,explanation:"Related-party transactions raise concerns about arm's-length terms and adequate disclosure. Trap increased-revenue: revenue rising is normal; the issue is the relationship and terms. Trap delivery-timing: logistics are not the core related-party risk. Trap payment-method: how it was paid does not address the relationship.",difficulty:"hard",topic:"Audit"},
  {q:"Why does an auditor set tolerable misstatement for an individual account below overall materiality?",options:["To increase the sample size for immaterial accounts","To leave room for undetected misstatements aggregating across accounts","Because tolerable misstatement and materiality are the same figure","Because each account must be perfectly stated"],correct:1,explanation:"Setting account-level tolerable misstatement below overall materiality provides a buffer so misstatements across accounts do not aggregate beyond materiality. Trap perfectly-stated: audits seek reasonable, not absolute, assurance. Trap same-figure: tolerable misstatement is deliberately lower. Trap immaterial-accounts: the purpose is aggregation risk, not inflating samples on trivial accounts.",difficulty:"hard",topic:"Audit"}
];

const CONSULTING_DIAG: DrillQ[] = [
  {q:"A company's revenue grew from $400M to $480M while net margin fell from 12% to 9%. What was the change in net profit?",options:["Up $7.2M","Down $14.4M","Down $12M","Down $4.8M"],correct:3,explanation:"Profit was 400 x 12% = $48M; now 480 x 9% = $43.2M; change = -$4.8M. Trap $14.4M: applied the 3pt drop to new revenue. Trap $12M: applied it to old revenue. Trap $7.2M: counted only growth at the new margin, ignoring compression on the base.",difficulty:"hard",topic:"Profitability"},
  {q:"A SaaS firm has $200M revenue, 80% gross margin, and operating costs of $50M sales and marketing, $30M R&D, and $20M G&A. What is operating margin?",options:["30%","40%","45%","50%"],correct:0,explanation:"Gross profit = 200 x 80% = $160M. Operating income = 160 - 50 - 30 - 20 = $60M. Margin = 60/200 = 30%. Trap 45%: dropped R&D. Trap 40%: dropped G&A. Trap 50%: ignored COGS and ran opex off revenue.",difficulty:"hard",topic:"Profitability"},
  {q:"A product sells for $50 with $30 variable cost per unit and $1,200,000 fixed costs. How many units break even?",options:["15,000 units","40,000 units","60,000 units","24,000 units"],correct:2,explanation:"Contribution per unit = 50 - 30 = $20. Breakeven = 1,200,000 / 20 = 60,000 units. Trap 24,000: divided by price. Trap 40,000: divided by variable cost. Trap 15,000: divided by price plus variable cost.",difficulty:"hard",topic:"Profitability"},
  {q:"A firm has $600,000 fixed costs, an $80 price, and $50 variable cost per unit. What revenue breaks even?",options:["$225K","$1.6M","$20K","$960K"],correct:1,explanation:"Contribution margin ratio = (80-50)/80 = 37.5%. Breakeven revenue = 600,000 / 0.375 = $1.6M. Trap $960K: divided by the variable-cost ratio 0.625. Trap $20K: divided by dollar contribution (gives units). Trap $225K: multiplied instead of divided.",difficulty:"hard",topic:"Profitability"},
  {q:"A firm sells units at $20 with $12 variable cost. Variable cost rises to $14. To preserve dollar profit at the same volume, the new price must be:",options:["$35","$15.20","$16.40","$22"],correct:3,explanation:"Hold unit contribution at 20-12 = $8. New price = 14 + 8 = $22, a $2 pass-through. Trap $35: held the 40% margin ratio (14/0.60). Traps $16.40 and $15.20: scaled the $2 by the margin instead of passing it through one-for-one.",difficulty:"hard",topic:"Profitability"},
  {q:"A company reports $50M revenue, $32M COGS, $12M operating expenses, and a 25% tax rate. What is net margin?",options:["12%","3%","36%","9%"],correct:3,explanation:"EBIT = 50-32-12 = $6M. Net income = 6 x 0.75 = $4.5M. Net margin = 4.5/50 = 9%. Trap 12%: stopped at operating margin, skipped tax. Trap 36%: reported gross margin. Trap 3%: divided the tax, not after-tax income, by revenue.",difficulty:"hard",topic:"Profitability"},
  {q:"A firm earns $30M at 60% gross margin (software) and $20M at 20% gross margin (hardware). What is blended gross margin?",options:["110%","44%","40%","73.3%"],correct:1,explanation:"Software GP $18M + hardware GP $4M = $22M on $50M = 44%. Trap 40%: simple average of margins, ignoring mix. Other traps divide total gross profit by a single segment's revenue.",difficulty:"hard",topic:"Profitability"},
  {q:"A firm has $100M revenue, variable costs of 55% of revenue, and $30M fixed costs. If revenue rises 10% with the same structure, by what percent does operating profit rise?",options:["15%","45%","10%","30%"],correct:3,explanation:"EBIT now = 100 x 45% - 30 = $15M. New EBIT = 110 x 45% - 30 = $19.5M. Change = 4.5/15 = 30%. Trap 10%: assumed profit scales with revenue. Trap 45%: used the contribution ratio as a growth rate. Trap 15%: divided the $4.5M contribution lift by fixed costs. Operating leverage turns a 10% sales move into a 30% profit move.",difficulty:"hard",topic:"Profitability"},
  {q:"A subscription product has $50 monthly ARPU, 70% gross margin, 5% monthly churn, and $250 CAC. What is the LTV/CAC ratio?",options:["4.0x","5.6x","2.0x","2.8x"],correct:3,explanation:"Average life = 1/0.05 = 20 months. LTV = 50 x 70% x 20 = $700. LTV/CAC = 700/250 = 2.8x. Trap 4.0x: skipped gross margin. Trap 2.0x: applied gross margin twice. Trap 5.6x: used 2.5% churn (40-month life).",difficulty:"hard",topic:"Profitability"},
  {q:"With $600 CAC, $80 monthly ARPU, and 75% gross margin, what is the CAC payback period in months?",options:["10.0 months","15.0 months","30.0 months","7.5 months"],correct:0,explanation:"Monthly gross profit per customer = 80 x 75% = $60. Payback = 600/60 = 10.0 months. Trap 7.5: ignored gross margin. Trap 30: used the 25% cost ratio. Trap 15: assumed a 50% margin.",difficulty:"hard",topic:"Profitability"},
  {q:"A SaaS firm starts the year at $10M ARR. Net revenue retention is 110% and gross logo churn is 8%. Excluding new logos, what is end-of-year ARR?",options:["$9.2M","$11M","$10.2M","$11.8M"],correct:1,explanation:"NRR already nets expansion against churn and downgrades, so end ARR = 10 x 1.10 = $11M. Trap $9.2M: applied logo churn only. Trap $10.2M: double-counted churn by subtracting it from NRR. Trap $11.8M: added churn back.",difficulty:"hard",topic:"Profitability"},
  {q:"A product has a 40% contribution margin. To offset a 10% price cut, by what percent must unit volume rise to hold total contribution constant?",options:["10%","33.3%","25%","11.1%"],correct:1,explanation:"On a $100 unit, contribution falls from $40 to $30 after the cut. Needed volume = 40/30 - 1 = 33.3%. Trap 10%: matched the discount. Trap 25%: used the inverse ratio (1 - 30/40). Trap 11.1%: divided the cut by (1 - cut).",difficulty:"hard",topic:"Profitability"},
  {q:"A retailer sells 1,000,000 units, currently 60% product A ($5 contribution) and 40% product B ($12). If mix shifts to 40% A and 60% B at the same total units, what is total contribution?",options:["$7.8M","$10.2M","$9.2M","$8.5M"],correct:2,explanation:"New total = 400,000 x 5 + 600,000 x 12 = $9.2M. Trap $7.8M: used the old mix. Trap $8.5M: simple average of contributions. Trap $10.2M: applied 60% to both lines (weights exceed 100%).",difficulty:"hard",topic:"Profitability"},
  {q:"A plant has $5M fixed cost and 500,000-unit capacity. At 90% utilization, what is fixed cost per unit?",options:["$10","$8.33","$16.67","$11.11"],correct:3,explanation:"Units at 90% = 450,000. Fixed cost per unit = 5,000,000/450,000 = $11.11. Trap $16.67: used 60% utilization. Trap $10: used full capacity. Trap $8.33: used 120% of capacity.",difficulty:"hard",topic:"Profitability"},
  {q:"A customer buys $200,000 per year at 30% gross margin. Cost to serve the account is $48,000. What is the net profit on this customer?",options:["$12,000","$152,000","$6,000","$60,000"],correct:0,explanation:"Gross profit = 200,000 x 30% = $60,000. Net = 60,000 - 48,000 = $12,000. Trap $60,000: ignored cost to serve. Trap $152,000: ignored COGS. Trap $6,000: halved the result.",difficulty:"hard",topic:"Profitability"},
  {q:"A factory's normal full cost is $32 per unit ($20 variable, $12 allocated fixed) and it has idle capacity. A one-time order is offered at $26 per unit. What is the incremental profit per unit?",options:["$6","$14","$-14","$-6"],correct:0,explanation:"With idle capacity, only variable cost is relevant: 26 - 20 = $6 per unit. Trap $-6: used full cost. Trap $14: subtracted only allocated fixed. Trap $-14: compared the special price to the $40 list price.",difficulty:"hard",topic:"Profitability"},
  {q:"An EBIT bridge shows: $20M revenue growth at 25% incremental margin, $3M cost inflation, and $1M favorable mix. What is the change in EBIT?",options:["$2M","$5M","$9M","$3M"],correct:3,explanation:"Volume effect = 20 x 25% = $5M; then -3 inflation +1 mix = $3M. Trap $5M: counted volume only. Trap $2M: dropped mix. Trap $9M: treated inflation as a benefit (sign error).",difficulty:"hard",topic:"Profitability"},
  {q:"A firm has $120M COGS. It negotiates a 4% price reduction on 60% of its spend. What is the annual savings?",options:["$1.92M","$2.4M","$2.88M","$4.8M"],correct:2,explanation:"Savings = 120 x 60% x 4% = $2.88M. Trap $4.8M: applied 4% to all spend. Trap $2.4M: used 50% scope. Trap $1.92M: applied it to the 40% that was not renegotiated.",difficulty:"hard",topic:"Profitability"},
  {q:"Price elasticity of demand is -1.5. The firm raises price 8%. Approximately what happens to revenue?",options:["Down 12%","Down 4%","Up 8%","Up 4%"],correct:1,explanation:"Quantity falls 1.5 x 8% = 12%. Revenue change is approximately +8% - 12% = -4% (a decline). Trap up 8%: counted price only. Trap down 12%: counted quantity only. Trap up 4%: right magnitude, wrong sign.",difficulty:"hard",topic:"Profitability"},
  {q:"A firm with $365M annual revenue improves days sales outstanding from 60 to 45 days. How much cash is freed from receivables?",options:["$45M","$7.5M","$60M","$15M"],correct:3,explanation:"Daily revenue = 365M/365 = $1M. Receivables fall from 60M to 45M, freeing $15M. Trap $45M: reported the new AR balance. Trap $60M: reported the old balance. Trap $7.5M: halved the day improvement.",difficulty:"hard",topic:"Profitability"},
  {q:"A retailer buys an item for $60 and prices it at a 50% markup on cost. What is the gross margin percentage?",options:["66.7%","33.3%","30%","50%"],correct:1,explanation:"Price = 60 x 1.5 = $90. Margin = (90-60)/90 = 33.3%. Trap 50%: mistook markup for margin. Trap 66.7%: computed cost as a percent of price. Trap 30%: divided $30 profit by a $100 base.",difficulty:"hard",topic:"Profitability"},
  {q:"A team has 12 reps, each with a $1.2M quota, averaging 85% attainment, at 40% gross margin. What gross profit do they generate?",options:["$12.24M","$4.08M","$5.76M","$4.9M"],correct:3,explanation:"Revenue = 12 x 1.2M x 85% = $12.24M; gross profit = x 40% = $4.9M. Trap $12.24M: stopped at revenue. Trap $5.76M: skipped attainment. Trap $4.08M: used 10 reps.",difficulty:"hard",topic:"Profitability"},
  {q:"A utility charges $0.20/kWh for the first 500 kWh and $0.30/kWh above that. A customer uses 900 kWh. What is the average price per kWh paid?",options:["$0.25","$0.30","$0.24","$0.20"],correct:2,explanation:"Bill = 500 x 0.20 + 400 x 0.30 = $220; average = 220/900 = $0.24. Trap $0.25: simple average of the two rates. Trap $0.30: used the marginal top rate. Trap $0.20: used the base rate.",difficulty:"hard",topic:"Profitability"},
  {q:"A cohort of 1,000 customers pays $100/month with 90% monthly retention. What is the cohort's MRR at the start of month 3 (after two monthly churns)?",options:["$70,000","$72,900","$81,000","$90,000"],correct:2,explanation:"Survivors = 1,000 x 0.9^2 = 810; MRR = 810 x 100 = $81,000. Trap $90,000: applied retention once. Trap $70,000: subtracted a flat 30%. Trap $72,900: applied retention three times.",difficulty:"hard",topic:"Profitability"},
  {q:"Making a part costs $18 variable plus $7 of allocated fixed overhead that is unavoidable. Buying it costs $22. Per unit, the firm should:",options:["Make, saving $4","Buy, saving $3","Buy, saving $4","Make, saving $11"],correct:0,explanation:"Unavoidable fixed cost is irrelevant; compare make variable $18 to buy $22. Make saves $4 per unit. Trap buy save $3: compared full cost $25 to $22. Trap make save $11: compared $7 fixed plus nothing. Trap buy save $4: reversed the direction.",difficulty:"hard",topic:"Profitability"},
  {q:"Machine hours are the binding constraint. Product A yields $30 contribution using 2 hours; product B yields $40 using 4 hours. To maximize profit, prioritize:",options:["B, at $10/hour","B, at $40/hour","A, at $15/hour","A, at $30/hour"],correct:2,explanation:"Per constraint hour, A = 30/2 = $15 and B = 40/4 = $10; prioritize A. Trap B $10/hour: picked B but it is lower per hour. Traps using $30 and $40: ranked by absolute contribution, ignoring hours.",difficulty:"hard",topic:"Profitability"},
  {q:"Revenue rose from $50M to $56M. Volume added 5% and price added 3% of the base; the rest is mix. What is the mix contribution?",options:["$1.5M","$2M","$6M","$2.5M"],correct:1,explanation:"Volume = 50 x 5% = $2.5M; price = 50 x 3% = $1.5M; total change = $6M; mix = 6 - 2.5 - 1.5 = $2M. Trap $6M: gave the total change. Trap $2.5M: gave volume. Trap $1.5M: gave price.",difficulty:"hard",topic:"Profitability"},
  {q:"Gross sales are $40M with 8% returns (refunded, goods scrapped). COGS on all units shipped is $24M. What is gross margin on net sales?",options:["40%","28.6%","34.8%","32%"],correct:2,explanation:"Net sales = 40 x 0.92 = $36.8M; gross profit = 36.8 - 24 = $12.8M; margin = 12.8/36.8 = 34.8%. Trap 40%: ignored returns. Trap 32%: divided gross profit by gross sales. Trap 28.6%: double-counted returns.",difficulty:"hard",topic:"Profitability"},
  {q:"A customer makes 4 purchases per year of $80 each at 25% gross margin and stays for 3 years. What is the customer lifetime value?",options:["$320","$80","$240","$960"],correct:2,explanation:"LTV = 4 x 80 x 25% x 3 = $240. Trap $960: skipped gross margin. Trap $320: used 4 years. Trap $80: used a single year.",difficulty:"hard",topic:"Profitability"},
  {q:"A $1,000 list item carries a 20% trade discount and then a 2% cash discount on the net amount. What is the final price?",options:["$800","$816","$780","$784"],correct:3,explanation:"1000 x 0.80 = $800; x 0.98 = $784. Trap $780: stacked the discounts additively (22% off). Trap $800: forgot the cash discount. Trap $816: added the 2% instead of subtracting.",difficulty:"hard",topic:"Profitability"},
  {q:"A city has 2,000,000 people. 40% drink coffee, averaging 1.5 cups per day. How many cups are consumed per day?",options:["1.2 million cups","600,000 cups","800,000 cups","3 million cups"],correct:0,explanation:"2,000,000 x 40% x 1.5 = 1.2 million cups. Trap 800,000: dropped the 1.5 cups/day. Trap 3 million: dropped the 40% penetration. Trap 600,000: halved the result.",difficulty:"hard",topic:"Market Sizing"},
  {q:"A country has 50,000,000 households. 30% own an electric toothbrush, replaced every 4 years, at $80 each. What is the annual market revenue?",options:["$150M","$4.8B","$300M","$1.2B"],correct:2,explanation:"Annual units = 50M x 30% / 4 = 3.75 million; revenue = x $80 = $300M. Trap $1.2B: ignored the replacement cycle. Trap $4.8B: multiplied by 4 instead of dividing. Trap $150M: used an 8-year cycle.",difficulty:"hard",topic:"Market Sizing"},
  {q:"In a country, 3,000,000 babies are in diapers, each using 6 diapers per day. How many diapers are used per year?",options:["540 million diapers","18 million diapers","1.09 billion diapers","6.57 billion diapers"],correct:3,explanation:"3,000,000 x 6 x 365 = 6.57 billion diapers. Trap 18 million: gave the daily total, not annual. Trap 540 million: annualized with 30 days. Trap 1.09 billion: used 1 diaper/day.",difficulty:"hard",topic:"Market Sizing"},
  {q:"A metro has 5,000,000 adults. 18% hold gym memberships at $40/month. What is the annual membership revenue?",options:["$2.4B","$432M","$540M","$36M"],correct:1,explanation:"Members = 5M x 18% = 900,000; annual = x $40 x 12 = $432M. Trap $36M: gave one month. Trap $2.4B: dropped the 18% penetration. Trap $540M: used 15 months.",difficulty:"hard",topic:"Market Sizing"},
  {q:"A city of 8,000,000 has 25% who use ride-hailing, taking 3 trips/month at a $15 average fare. What is monthly ride-hail revenue?",options:["$6M","$30M","$90M","$1.08B"],correct:2,explanation:"Riders = 2,000,000; trips = x 3 = 6,000,000; revenue = x $15 = $90M. Trap $30M: dropped trips/month. Trap $6M: gave trips, not revenue. Trap $1.08B: gave the annual figure.",difficulty:"hard",topic:"Market Sizing"},
  {q:"A country has 40,000,000 households, each with 20 light bulbs, replacing one fifth of them per year. How many bulbs are sold per year?",options:["160 million bulbs","8 million bulbs","800 million bulbs","4 billion bulbs"],correct:0,explanation:"40M x 20 x 0.2 = 160 million bulbs. Trap 800 million: gave the installed base, not annual replacement. Trap 8 million: dropped bulbs per home. Trap 4 billion: multiplied by 5 instead of by 0.2.",difficulty:"hard",topic:"Market Sizing"},
  {q:"A country of 300,000,000 has 80% smartphone ownership, with phones replaced every 3 years. How many phones are sold per year?",options:["100 million units","240 million units","80 million units","720 million units"],correct:2,explanation:"Installed base = 240M; annual = / 3 = 80 million units. Trap 240 million: gave the installed base. Trap 720 million: multiplied by 3. Trap 100 million: dropped the 80% penetration.",difficulty:"hard",topic:"Market Sizing"},
  {q:"A town has 1,000,000 households that order pizza twice a month at $25 per order. What is the annual pizza market revenue?",options:["$300M","$600M","$1.2B","$50M"],correct:1,explanation:"Monthly = 1M x 2 x $25 = $50M; annual = x 12 = $600M. Trap $50M: gave one month. Trap $300M: dropped the twice-a-month frequency. Trap $1.2B: double-counted months.",difficulty:"hard",topic:"Market Sizing"},
  {q:"A region has 200,000 companies averaging 50 employees, each needing one chair replaced every 7 years at $150. What is the annual chair market?",options:["$214.29M","$1.5B","$10.5B","$1.43M"],correct:0,explanation:"Installed chairs = 10,000,000; annual = / 7 = 1.43 million; revenue = x $150 = $214.29M. Trap $1.5B: ignored replacement. Trap $10.5B: multiplied by 7. Trap $1.43M: gave units, not revenue.",difficulty:"hard",topic:"Market Sizing"},
  {q:"A city of 1,000,000 supports one coffee shop per 2,500 residents. How many coffee shops are there?",options:["250","40","400","4,000"],correct:2,explanation:"1,000,000 / 2,500 = 400 shops. Trap 4,000: divided by 250 (off by 10x). Trap 40: divided by 25,000. Trap 250: used 1 per 4,000.",difficulty:"hard",topic:"Market Sizing"},
  {q:"A country has 150,000,000 cars driving 12,000 miles/year at 25 miles per gallon. How many gallons of fuel per year?",options:["1.8 trillion gallons","72 billion gallons","2.88 billion gallons","45 trillion gallons"],correct:1,explanation:"150M x 12,000 / 25 = 72 billion gallons. Trap 1.8 trillion: dropped the mpg division. Trap 45 trillion: multiplied by mpg. Trap 2.88 billion: divided by mpg twice.",difficulty:"hard",topic:"Market Sizing"},
  {q:"A town of 500,000 residents eats out 3 times per week. How many restaurant meals are eaten per year?",options:["18 million meals","1.5 million meals","78 million meals","547.5 million meals"],correct:2,explanation:"500,000 x 3 x 52 = 78 million meals. Trap 1.5 million: gave the weekly total. Trap 547.5 million: annualized a weekly rate with 365 days. Trap 18 million: used 12 instead of 52 weeks.",difficulty:"hard",topic:"Market Sizing"},
  {q:"A market has 300 hotels averaging 120 rooms at 70% occupancy. How many room-nights are sold per year?",options:["6.57 million","25,200","9.2 million","13.14 million"],correct:2,explanation:"300 x 120 x 0.70 = 25,200 occupied/night x 365 = 9.2 million. Trap 13.14 million: ignored occupancy. Trap 25,200: gave one night. Trap 6.57 million: used 50% occupancy.",difficulty:"hard",topic:"Market Sizing"},
  {q:"A region has 2,000,000 cars, 90% insured, with an average annual premium of $1,200. What is the annual premium market?",options:["$2.16B","$2.4B","$1.2B","$180M"],correct:0,explanation:"2M x 90% x $1,200 = $2.16B. Trap $2.4B: ignored the 90% insured rate. Trap $180M: gave a monthly figure. Trap $1.2B: used 50% insured.",difficulty:"hard",topic:"Market Sizing"},
  {q:"Total retail is $500B. Online penetration is 18%, and a given category is 8% of online sales. What is the category's online revenue?",options:["$90B","$7.2B","$3.6B","$40B"],correct:1,explanation:"500B x 18% x 8% = $7.2B. Trap $90B: stopped at total online. Trap $40B: applied 8% to total retail, skipping online penetration. Trap $3.6B: halved it.",difficulty:"hard",topic:"Market Sizing"},
  {q:"A subscription box targets 30,000,000 consumers with 5% adoption at $35/month. What is annual revenue at steady state?",options:["$12.6B","$315M","$52.5M","$630M"],correct:3,explanation:"Subscribers = 1,500,000; annual = x $35 x 12 = $630M. Trap $52.5M: gave one month. Trap $12.6B: dropped the 5% adoption. Trap $315M: used 6 months.",difficulty:"hard",topic:"Market Sizing"},
  {q:"An airline has 200 planes of 180 seats, each flying 5 flights/day at 80% load. How many passengers per year?",options:["144,000","52.56 million","10.51 million","65.7 million"],correct:1,explanation:"200 x 180 x 5 x 0.80 = 144,000/day x 365 = 52.56 million. Trap 65.7 million: ignored load factor. Trap 10.51 million: dropped flights/day. Trap 144,000: gave one day.",difficulty:"hard",topic:"Market Sizing"},
  {q:"A country has 40,000,000 adults, 60% of whom drink, averaging 2 drinks per week. How many drinks are consumed per year?",options:["2.5 billion","48 million","17.52 billion","4.16 billion"],correct:0,explanation:"40M x 60% x 2 x 52 = 2.5 billion. Trap 48 million: gave the weekly total. Trap 17.52 billion: annualized a weekly rate with 365. Trap 4.16 billion: dropped the 60% who drink.",difficulty:"hard",topic:"Market Sizing"},
  {q:"Of 80,000,000 homes, 6% will adopt solar over 10 years at $20,000 per install. What is the annual installation market?",options:["$9.6B","$4.8B","$96B","$960B"],correct:0,explanation:"Total adopters = 4,800,000; per year = / 10 = 480,000; revenue = x $20,000 = $9.6B. Trap $96B: ignored the 10-year spread. Trap $960B: multiplied by 10. Trap $4.8B: spread over 20 years.",difficulty:"hard",topic:"Market Sizing"},
  {q:"There are 18,000,000 college students; 70% buy textbooks, averaging 8 books/year at $60. What is the annual textbook market?",options:["$6.05B","$8.64B","$756M","$3.02B"],correct:0,explanation:"12,600,000 buyers x 8 x $60 = $6.05B. Trap $756M: dropped books per year. Trap $8.64B: dropped the 70% buyer rate. Trap $3.02B: halved it.",difficulty:"hard",topic:"Market Sizing"},
  {q:"A city has 50,000 parking spaces at 75% occupancy, charging $20/day over 300 operating days. What is annual parking revenue?",options:["$750K","$273.75M","$300M","$225M"],correct:3,explanation:"37,500 occupied x $20 x 300 = $225M. Trap $300M: ignored occupancy. Trap $273.75M: used 365 days. Trap $750K: gave one day.",difficulty:"hard",topic:"Market Sizing"},
  {q:"A country has 60,000,000 dogs, each eating $1.50 of food per day. What is the annual dog food market?",options:["$1.08B","$2.7B","$32.85B","$90M"],correct:2,explanation:"60M x $1.50 x 365 = $32.85B. Trap $90M: gave one day. Trap $1.08B: annualized with 12. Trap $2.7B: used 30 days.",difficulty:"hard",topic:"Market Sizing"},
  {q:"A platform has 100,000,000 users on their phones 4 hours/day, seeing 3 ads/hour, monetized at $0.01/ad. What is annual ad revenue?",options:["$4.38B","$12M","$360M","$1.46B"],correct:0,explanation:"100M x 4 x 3 x $0.01 = $12M/day x 365 = $4.38B. Trap $12M: gave one day. Trap $360M: used 30 days. Trap $1.46B: dropped 3 ads/hour.",difficulty:"hard",topic:"Market Sizing"},
  {q:"A country of 330,000,000 has a death rate of 9 per 1,000 per year, with average funeral spend of $9,000. What is the annual market?",options:["$2.67B","$267.3B","$2.97M","$26.73B"],correct:3,explanation:"Deaths = 330M x 0.009 = 2,970,000; market = x $9,000 = $26.73B. Trap $267.3B: used 9 per 100. Trap $2.67B: used 9 per 10,000. Trap $2.97M: gave deaths, not revenue.",difficulty:"hard",topic:"Market Sizing"},
  {q:"There are 2,000,000 office coffee machines installed, replaced every 5 years at $500 each. What is the annual replacement market?",options:["$1B","$5B","$200M","$400K"],correct:2,explanation:"Annual units = 2M / 5 = 400,000; revenue = x $500 = $200M. Trap $1B: ignored the replacement cycle. Trap $5B: multiplied by 5. Trap $400K: gave units, not revenue.",difficulty:"hard",topic:"Market Sizing"},
  {q:"A country has 2,000,000 weddings per year at an average spend of $30,000 each. What is the annual wedding market?",options:["$60B","$30B","$6B","$300B"],correct:0,explanation:"2M x $30,000 = $60B. Trap $30B: counted one side's spend. Trap $6B: used $3,000 (order-of-magnitude slip). Trap $300B: multiplied by 5 in error.",difficulty:"hard",topic:"Market Sizing"},
  {q:"A country of 300,000,000 has 40% who drink one bottle of water per day at $1.20 each. What is the annual bottled-water market?",options:["$131.4B","$144M","$52.56B","$43.8B"],correct:2,explanation:"Daily bottles = 120M; annual = x 365 = 43.8B; revenue = x $1.20 = $52.56B. Trap $43.8B: gave units, not revenue. Trap $144M: gave daily revenue. Trap $131.4B: used 100% penetration.",difficulty:"hard",topic:"Market Sizing"},
  {q:"There are 5,000,000 target companies averaging 80 employees; 30% are knowledge workers who would use a tool at $15/seat/month. What is the annual TAM?",options:["$10.8B","$72B","$1.8B","$21.6B"],correct:3,explanation:"Seats = 5M x 80 x 30% = 120M; annual = x $15 x 12 = $21.6B. Trap $1.8B: gave one month. Trap $72B: dropped the 30% knowledge-worker share. Trap $10.8B: halved it.",difficulty:"hard",topic:"Market Sizing"},
  {q:"Entering a market needs $50M upfront capex and returns $18M of free cash flow per year for 4 years. At a 10% discount rate, what is the NPV?",options:["$7.06M","$22M","$57.06M","$107.06M"],correct:0,explanation:"Discount the 4 inflows at 10% (0.909,0.826,0.751,0.683) = $57.06M, minus $50M capex = $7.06M. Trap $57.06M: forgot to subtract the upfront capex. Trap $22M: summed cash flows without discounting. Trap $107.06M: added capex as a positive inflow at t0.",difficulty:"hard",topic:"Market Entry"},
  {q:"A market sells 2,000,000 units/year. To enter you incur $6,000,000 fixed cost; you would sell at $40 with $25 variable cost. What market share do you need to break even?",options:["12%","7.5%","40%","20%"],correct:3,explanation:"Contribution = 40 - 25 = $15; breakeven units = 6,000,000/15 = 400,000; share = 400,000/2,000,000 = 20%. Trap 7.5%: divided fixed cost by price not contribution. Trap 12%: divided by variable cost. Trap 40%: doubled the share.",difficulty:"hard",topic:"Market Entry"},
  {q:"An entry requires $24,000,000 upfront and generates $9,000,000 in annual cash flow. What is the simple payback period?",options:["1.67 years","2.67 years","3.75 years","1.33 years"],correct:1,explanation:"Payback = 24,000,000/9,000,000 = 2.67 years. Trap 1.33: halved it. Trap 3.75: inverted the ratio then mis-scaled. Trap 1.67: subtracted one year of cash flow from capex first.",difficulty:"hard",topic:"Market Entry"},
  {q:"Entry has a 60% chance of a $80M NPV and a 40% chance of a -$30M NPV. What is the expected NPV?",options:["$36M","$48M","$25M","$60M"],correct:0,explanation:"EV = 0.6 x 80M + 0.4 x (-30M) = 48M - 12M = $36M. Trap $25M: simple average, ignored probabilities. Trap $48M: counted only the upside case. Trap $60M: treated the downside as a positive.",difficulty:"hard",topic:"Market Entry"},
  {q:"A new market is expected to throw off $5,000,000 of cash flow next year, growing 2% forever. At a 10% discount rate, what is its value today using a growing perpetuity?",options:["$51M","$63.75M","$62.5M","$50M"],correct:1,explanation:"Gordon: 5M x 1.02 / (0.10 - 0.02) = 5.1M/0.08 = $63.75M. Trap $50M: no growth and used this-year cash flow. Trap $62.5M: forgot to grow the numerator. Trap $51M: grew numerator but ignored growth in the denominator.",difficulty:"hard",topic:"Market Entry"},
  {q:"Entering costs $4,500,000 in fixed investment. Each unit sold contributes $30 of margin. How many units must you sell to break even on the investment?",options:["4,500,000","150,000","75,000","300,000"],correct:1,explanation:"Breakeven units = 4,500,000/30 = 150,000. Trap 75,000: doubled the contribution. Trap 300,000: halved the contribution. Trap 4,500,000: read fixed cost as units.",difficulty:"hard",topic:"Market Entry"},
  {q:"A new product would sell 200,000 units at $12 contribution each, but cannibalize 50,000 units of an existing line that earns $20 contribution each. What is the incremental annual contribution?",options:["$3M","$1.8M","$2.4M","$1.4M"],correct:3,explanation:"New = 200,000 x 12 = 2.4M; lost = 50,000 x 20 = 1.0M; incremental = $1.4M. Trap $2.4M: ignored cannibalization entirely. Trap $1.8M: costed the lost units at the new product margin, not the old. Trap $3M: netted units first then applied the old margin to everything.",difficulty:"hard",topic:"Market Entry"},
  {q:"An entry costs $40M today and returns $10M, $20M, then $30M over the next three years. At 10%, what is the NPV?",options:["$20M","$11.31M","$8.16M","$48.16M"],correct:2,explanation:"PV inflows = 10M/1.1 + 20M/1.21 + 30M/1.331 = 9.09M+16.53M+22.54M = 48.16M; minus 40M = $8.16M. Trap $20M: undiscounted net. Trap $48.16M: forgot the capex. Trap $11.31M: discounted the ramp in reverse, front-loading the $30M.",difficulty:"hard",topic:"Market Entry"},
  {q:"To justify entry you need a 40% contribution margin on price and your variable cost is $27/unit. What price must you set?",options:["$16.20","$45","$67.50","$37.80"],correct:1,explanation:"Price = variable cost / (1 - margin) = 27/0.60 = $45. Trap $37.80: marked cost up by 40% instead of grossing up. Trap $67.50: divided by the margin rather than one minus the margin. Trap $16.20: multiplied by 1 minus the margin, the discount direction.",difficulty:"hard",topic:"Market Entry"},
  {q:"Market A: $20M capex, $8M/yr for 3 years. Market B: $30M capex, $12M/yr for 3 years. At 10%, which has the higher NPV and by roughly how much?",options:["Market A, by about -$52.6K","Market B, by about -$52.6K","Market A, by about $10M","Market B, by about $12"],correct:1,explanation:"A NPV = -$105.2K; B NPV = -$157.8K; B - A = -$52.6K. Trap A-wins: picked the smaller-capex option by reflex. Trap B by $12M: used undiscounted cash-flow difference. Trap A by $10M: compared capex only, ignored returns.",difficulty:"hard",topic:"Market Entry"},
  {q:"Entry costs $30M and returns $12M/yr. Discounting at 10%, in which year does cumulative discounted cash flow first exceed the $30M outlay?",options:["Year 1","Year 2","Year 4","Year 3"],correct:3,explanation:"Discounted inflows: Y1 $10.91M, cumulative $10.91M; Y2 $9.92M, cumulative $20.83M; Y3 $9.02M, cumulative $29.84M which first passes $30M. Trap Year 2: used undiscounted cash (24M by Y2 looks under, 36M by Y3) but mis-stops early. Trap Year 4: over-discounted. Trap Year 1: ignored that one year is far short.",difficulty:"hard",topic:"Market Entry"},
  {q:"A new line generates $10M EBIT, faces a 25% tax rate, has $3M depreciation and needs $4M of capex. What is its unlevered free cash flow?",options:["$9M","$14.5M","$3.5M","$6.5M"],correct:3,explanation:"NOPAT = 10M x 0.75 = 7.5M; add back dep 3M; less capex 4M = $6.5M. Trap $3.5M: forgot to add back depreciation. Trap $9M: forgot the tax. Trap $14.5M: added capex instead of subtracting.",difficulty:"hard",topic:"Market Entry"},
  {q:"Entering costs $2,000,000 fixed plus $300 to acquire each customer; each customer delivers $800 of lifetime contribution. How many customers are needed to break even on entry?",options:["4,000","1,818","6,667","2,500"],correct:0,explanation:"Net per customer = 800 - 300 = 500; customers = 2,000,000/500 = 4,000. Trap 2,500: ignored CAC. Trap 6,667: divided by CAC alone. Trap 1,818: added CAC to LTV instead of subtracting.",difficulty:"hard",topic:"Market Entry"},
  {q:"Forecast demand is 5,000,000 units/year. Each production line runs at 1,000,000 units/year nameplate but only 80% effective uptime. How many lines are needed?",options:["4","7","6.2","5"],correct:1,explanation:"Effective per line = 1,000,000 x 0.80 = 800,000; lines = 5,000,000/800,000 = 6.25, round up to 7. Trap 5: ignored the 80% uptime. Trap 6.2: left it fractional, you cannot run 6.25 lines. Trap 4: multiplied demand by uptime instead of derating capacity.",difficulty:"hard",topic:"Market Entry"},
  {q:"Build: $15M now, $6M/yr for 3 years. License: $0 upfront, $3M/yr net for 3 years. At 10%, which has the higher NPV?",options:["License, by $15M","Build, they tie at $7.46M","License, NPV $7.46M vs -$78.9K","Build, NPV -$78.9K vs $7.46M"],correct:3,explanation:"Build NPV = -$78.9K; License NPV = $7.46M; build is higher. Trap License-wins: anchored on zero upfront cost. Trap tie: ignored the cash-flow gap. Trap License by $15M: compared only the upfront outlay.",difficulty:"hard",topic:"Market Entry"},
  {q:"You target $30M revenue. The segment has 400,000 customers each spending $500/year on the category. What share of category spend must you capture?",options:["1.5%","0.8%","15%","666.7%"],correct:2,explanation:"Category spend = 400,000 x 500 = $200M; share = 30M/200M = 15%. Trap 0.8%: divided revenue by customers, wrong base. Trap 1.5%: off by an order of magnitude. Trap 666.7%: inverted the ratio.",difficulty:"hard",topic:"Market Entry"},
  {q:"An entry has $0 outlay at t0, a $5M loss in year 1, then $7M/yr in years 2 to 4. At 10%, what is the NPV?",options:["$16M","$20.37M","$22.19M","$11.28M"],correct:3,explanation:"PV = -5M/1.1 + 7M/1.21 + 7M/1.331 + 7M/1.4641 = -4.55M+5.79M+5.26M+4.78M = $11.28M. Trap $16M: undiscounted. Trap year1-positive variant: treated the year-1 loss as a gain. Trap $22.19M: ignored the year-1 loss.",difficulty:"hard",topic:"Market Entry"},
  {q:"Unit cost starts at $100 and follows an 85% learning curve (cost falls to 85% per doubling of cumulative volume). After volume has doubled three times, what is the unit cost?",options:["$61.41","$72.25","$55","$52.20"],correct:0,explanation:"100 x 0.85^3 = 100 x 0.6141 = $61.41. Trap $55: subtracted 15% three times linearly instead of compounding. Trap $72.25: only two doublings. Trap $52.20: four doublings.",difficulty:"hard",topic:"Market Entry"},
  {q:"Buy a facility for $10M now, sell it for $6M in 5 years (PV of that resale at 10% is $3.73M). Or rent for $1.5M/yr for 5 years. Using a 10% rate, which is cheaper in PV terms?",options:["Buy, $10M vs rent $7.5M","Rent, $5.69M vs buy $6.27M","Buy, net PV cost $6.27M vs rent $5.69M","Rent, by $2.5M"],correct:2,explanation:"Buy net = 10M - 3.73M resale PV = $6.27M; rent PV = 1.5M annuity 5yr at 10% = $5.69M; buy is cheaper. Trap rent-wins: forgot the resale recovery. Trap buy $10M vs rent $7.5M: used undiscounted figures and ignored resale. Trap rent-by: subtracted undiscounted totals.",difficulty:"hard",topic:"Market Entry"},
  {q:"Entry costs $25M upfront over a 4-year horizon at 10%. The 4-year annuity factor is 3.17. What constant annual cash flow is needed to achieve a $5M NPV?",options:["$7.89M","$9.46M","$7.5M","$26.58M"],correct:1,explanation:"Required PV of inflows = 25M + 5M = 30M; annual CF = 30M/3.17 = $9.46M. Trap $7.5M: divided by 4 years instead of the annuity factor. Trap $26.58M: applied the factor only to the target and added full capex. Trap $7.89M: ignored the NPV target.",difficulty:"hard",topic:"Market Entry"},
  {q:"A market's total annual revenue pool is $400M. You expect to capture 5% in year one at a 30% operating margin. What is your year-one operating profit?",options:["$60M","$20M","$6M","$120M"],correct:2,explanation:"Revenue = 400M x 5% = 20M; profit = 20M x 30% = $6M. Trap $20M: gave revenue, not profit. Trap $120M: applied margin to the whole pool. Trap $60M: off by an order of magnitude.",difficulty:"hard",topic:"Market Entry"},
  {q:"An entry costs $20M and is expected to yield a level $1.8M perpetuity in cash flow. Your hurdle rate is 10%. Does the simple cash yield clear the hurdle, and what is it?",options:["Yes, yield is 9%","Yes, yield is 18%","No, yield is 9%","No, yield is 11.1%"],correct:2,explanation:"Yield = 1.8M/20M = 9%, which is below the 10% hurdle, so no. Trap Yes-9%: misread 9% as clearing 10%. Trap inverted-yield: divided capex by cash flow. Trap doubled-yield: multiplied the yield by two.",difficulty:"hard",topic:"Market Entry"},
  {q:"Doing nothing yields $4M/yr for 3 years. Entering costs $10M now and yields $9M/yr for 3 years. At 10%, what is the incremental NPV of entering versus staying?",options:["$5M","$2.43M","$12.43M","$12.38M"],correct:1,explanation:"Incremental cash flows: -10M then +5M/yr; NPV = $2.43M. Trap $12.38M: gave entry NPV alone, ignored the foregone status quo. Trap added-capex variant: double-counted the capex. Trap $5M: undiscounted incremental cash.",difficulty:"hard",topic:"Market Entry"},
  {q:"You will capture 10% of a 500,000-unit market. Variable cost is $18/unit and fixed entry cost is $3,000,000. What price just breaks even?",options:["$24","$78","$138","$60"],correct:1,explanation:"Units = 50,000; fixed per unit = 3,000,000/50,000 = $60; price = 18 + 60 = $78. Trap $24: spread fixed cost over the whole market, not your share. Trap $60: omitted variable cost. Trap $138: doubled the fixed-cost-per-unit.",difficulty:"hard",topic:"Market Entry"},
  {q:"Operating profit fell 12% year over year. Volume rose 4%, average price fell 9%, and total fixed and variable cost per unit were unchanged. Which single driver best explains the profit drop?",options:["Fixed costs rose because volume increased","Higher volume raised total variable cost above revenue","Demand fell, which is why profit dropped","Lower price more than offset higher volume on the margin line"],correct:3,explanation:"With unit costs flat, profit per unit moves with price; a 9% price cut outweighs the 4% volume gain, so the margin contraction from price is the driver. Trap variable-cost: variable cost per unit was stated unchanged. Trap fixed-rises: fixed cost does not scale with volume by definition. Trap demand-fell: volume actually rose, so demand did not fall.",difficulty:"hard",topic:"Frameworks"},
  {q:"A team splits a company's customers to analyze churn. Which segmentation is mutually exclusive and collectively exhaustive?",options:["By channel: online, retail, and frequent buyers","By tenure bucket: under 1 year, 1 to 3 years, over 3 years","By behavior: price-sensitive, loyal, and high-value customers","By age: under 30, 25 to 40, over 40"],correct:1,explanation:"Tenure buckets do not overlap and cover every customer, so they are MECE. Trap behavior: a customer can be both loyal and high-value, so not mutually exclusive. Trap channel: frequent buyers is a different dimension than channel and overlaps both. Trap age: 25 to 40 overlaps under 30 and over 40 at the boundaries.",difficulty:"hard",topic:"Frameworks"},
  {q:"You must structure why a retailer's revenue is falling. Which first-level breakdown is the cleanest driver tree?",options:["Revenue = price x cost x volume","Revenue = number of transactions x average transaction value","Revenue = same-store sales plus marketing spend","Revenue = foot traffic minus returns plus loyalty signups"],correct:1,explanation:"Transactions x average value multiplies to revenue and each branch decomposes further cleanly. Trap traffic-minus-returns: mixes units that do not multiply to revenue. Trap price-x-cost: cost is not a revenue component. Trap sales-plus-marketing: marketing spend is an input cost, not a revenue term.",difficulty:"hard",topic:"Frameworks"},
  {q:"A client is losing share in one region only. Working hypothesis-driven, what is the best immediate next step?",options:["Benchmark the client against the global market leader first","Interview the regional sales head to hear their explanation","Gather all available data on every region before forming any view","Form a hypothesis about that region and pull only the data that would confirm or kill it"],correct:3,explanation:"Hypothesis-driven work states a falsifiable hypothesis and targets the data that tests it, saving time. Trap gather-all: boiling the ocean is the opposite of hypothesis-driven. Trap benchmark-global: the issue is region-specific, so a global leader is the wrong comparison first. Trap interview-only: an anecdote is not a tested hypothesis and invites bias.",difficulty:"hard",topic:"Frameworks"},
  {q:"A profitable niche has low capital needs, no patents, and many equally capable suppliers of inputs. Using five-forces logic, what most threatens the incumbent's profit?",options:["Strong supplier power squeezing input costs","Low entry barriers inviting new entrants to compete the margin away","High buyer switching costs locking customers in","Intense substitute pressure from a different technology"],correct:1,explanation:"Low capital and no patents mean entry barriers are weak, so new entrants are the main threat to a fat margin. Trap supplier-power: many capable suppliers means supplier power is low, not high. Trap switching-costs: high switching costs would protect the incumbent, not threaten it. Trap substitutes: nothing in the prompt points to a substitute technology.",difficulty:"hard",topic:"Frameworks"},
  {q:"A bakery wants to model cost behavior. Which item is the clearest variable cost with respect to loaves produced?",options:["Salaried head baker's wage","Monthly oven lease payment","Flour and yeast consumed per loaf","Annual business insurance premium"],correct:2,explanation:"Ingredients scale directly with each loaf, so they are variable. Trap oven-lease: a fixed monthly payment regardless of output. Trap salaried-wage: a salary does not move with each loaf. Trap insurance: an annual premium is fixed for the period.",difficulty:"hard",topic:"Frameworks"},
  {q:"Customer complaints about late delivery spiked. Drilling down, on-time rate fell only at one warehouse after a new routing system launched. What is the root cause to test first?",options:["Overall rising customer expectations","The new routing system at that warehouse","A company-wide staffing shortage","Seasonal demand higher than last year"],correct:1,explanation:"The problem is isolated to one site and coincides with one change, so the routing system is the most specific testable cause. Trap expectations: a company-wide attitude would not isolate to one warehouse. Trap staffing: a company-wide shortage would hit all sites. Trap seasonality: seasonality would affect every warehouse, not one.",difficulty:"hard",topic:"Frameworks"},
  {q:"Three SKUs drive 78% of profit; the remaining 40 SKUs split the rest. With limited analyst time, where should the cost-to-serve deep dive start?",options:["The three SKUs that drive most of the profit","An equal-time review across all 43 SKUs","The 40 small SKUs because there are more of them","The single newest SKU regardless of profit"],correct:0,explanation:"The 80/20 principle says concentrate effort where most value sits, here the three SKUs. Trap equal-time: spreading time evenly ignores concentration. Trap 40-small: count is not the same as profit impact. Trap newest-SKU: recency is not a value criterion.",difficulty:"hard",topic:"Frameworks"},
  {q:"A manufacturer's gross margin is healthy but operating margin is thin. Where in the value chain should you look first?",options:["Factory direct labor efficiency","Operating expenses below gross profit, such as SG&A and distribution","Product mix at the point of sale","Raw material input prices"],correct:1,explanation:"A healthy gross margin but thin operating margin means the gap sits in costs below gross profit, like SG&A and distribution. Trap input-prices: those hit gross margin, which is fine. Trap direct-labor: also a cost of goods, already reflected in gross margin. Trap product-mix: mix would show up in gross margin too.",difficulty:"hard",topic:"Frameworks"},
  {q:"A team analyzing a pricing decision has studied the client's cost structure and customer willingness to pay. Using a 3C lens, what is the key missing piece?",options:["Competitor pricing and likely reaction","A larger customer survey sample","The client's historical financial statements","A deeper look at internal company costs"],correct:0,explanation:"The 3Cs are company, customer, and competitor; company and customer are covered, so competitor is missing. Trap company-costs: cost structure was already studied. Trap survey-sample: customer willingness was already assessed. Trap financials: company data is the covered leg, not the gap.",difficulty:"hard",topic:"Frameworks"},
  {q:"A chain reports $480M revenue across 200 stores. A manager claims average revenue per store is about $4.8M. What is the correct figure and the likely error?",options:["$2.4M; the manager dropped a factor and divided by 100 not 200","$4.8M; the manager is correct","$2.4M; the manager used profit not revenue","$24M; the manager divided by stores in the wrong unit"],correct:0,explanation:"480M/200 = $2.4M per store; $4.8M implies dividing by 100, an order-of-store error. Trap profit: the figure shown is revenue, and the error is the divisor, not the numerator. Trap correct: 4.8M is double the right answer. Trap 24M: that divides by 20, a different slip and far too high.",difficulty:"hard",topic:"Frameworks"},
  {q:"Four initiatives are scored on impact and ease. Which should the client tackle first under an impact-versus-ease lens?",options:["High impact, high ease","Low impact, high ease","High impact, low ease","Low impact, low ease"],correct:0,explanation:"The first move is the quick win that is both high impact and easy to do. Trap high-impact-low-ease: valuable but slow, a second-wave bet. Trap low-impact-high-ease: easy but not worth much. Trap low-low: deprioritize entirely.",difficulty:"hard",topic:"Frameworks"},
  {q:"A client's SG&A is 22% of sales versus a peer's 15%. Before concluding the client is inefficient, what is the most important check?",options:["Whether the peer operates in more countries","Whether the peer is larger by headcount","Whether the client's CEO was recently replaced","Whether the two firms classify the same costs inside SG&A"],correct:3,explanation:"Ratios are only comparable if the cost definitions match, so check classification consistency first. Trap headcount: size alone does not explain a ratio gap. Trap CEO: leadership change is unrelated to cost classification. Trap countries: footprint matters less than whether the same line items are being compared.",difficulty:"hard",topic:"Frameworks"},
  {q:"To structure why monthly churn rose, which decomposition isolates the cause most cleanly?",options:["Churn by cohort, by plan tier, and by reason code","Churn against the competitor's stock price","Churn compared to last year's headcount","Churn versus total marketing spend last quarter"],correct:0,explanation:"Splitting churn by cohort, tier, and stated reason isolates where and why it rose. Trap marketing-spend: spend is an input, not a churn dimension. Trap stock-price: a competitor's stock is not a churn driver. Trap headcount: internal headcount does not decompose customer churn.",difficulty:"hard",topic:"Frameworks"},
  {q:"A client already spent $3M on a pilot. Deciding whether to roll out, which costs belong in the go-forward analysis?",options:["Only the incremental rollout costs and benefits from here","Half the pilot cost plus rollout costs","The $3M pilot cost plus all rollout costs","The $3M pilot cost spread over future years"],correct:0,explanation:"The $3M is sunk and irrelevant; only incremental future cash flows matter. Trap full-pilot: including the sunk cost biases against rollout. Trap spread-pilot: amortizing a sunk cost still counts money already spent. Trap half-pilot: any portion of a sunk cost is still sunk.",difficulty:"hard",topic:"Frameworks"},
  {q:"Marketing proposes segmenting customers by zodiac sign. As a structuring critique, what is the core problem?",options:["The segments cannot be measured at all","The segments are not mutually exclusive","The segments are not tied to differences in behavior or value","There are too few segments to be useful"],correct:2,explanation:"A useful segmentation must map to differences in behavior or value to be actionable, which zodiac does not. Trap not-exclusive: zodiac signs are actually mutually exclusive, so that is not the flaw. Trap too-few: twelve signs is not too few. Trap not-measurable: birth date is easily measured, so measurability is not the issue.",difficulty:"hard",topic:"Frameworks"},
  {q:"An analyst estimates the US has 3,000,000 coffee shops. With about 330,000,000 people, what quick sanity check flags this as too high?",options:["That implies about 1,100 people per shop, clearly too sparse","That implies about 11 people per shop, which is reasonable","That implies about 110 people per shop, far too dense","That implies about 33 people per shop, which is reasonable"],correct:2,explanation:"330M/3M is about 110 people per shop, implausibly dense for a real economy. Trap 1,100: that would be 330M/300K, a different number. Trap 11: that would need 30M shops. Trap 33: that would need 10M shops; none match 3M shops.",difficulty:"hard",topic:"Frameworks"},
  {q:"A firm debates making a component in-house versus buying it. Which factor most directly decides the financial case, holding quality equal?",options:["Whether the in-house all-in unit cost is below the purchase price at expected volume","Whether the supplier has a nicer sales team","Whether competitors make or buy it","Whether the firm has spare office space"],correct:0,explanation:"With quality equal, the decision turns on total in-house unit cost versus purchase price at the relevant volume. Trap sales-team: relationship warmth is not the financial case. Trap office-space: production space, not office space, and only if it changes cost. Trap competitors: their choice does not set the client's cost curve.",difficulty:"hard",topic:"Frameworks"},
  {q:"After a merger, the combined firm cross-sells each company's product to the other's customers. How should this synergy be classified?",options:["A tax synergy","A financing synergy","A revenue synergy","A cost synergy"],correct:2,explanation:"Cross-selling raises sales, so it is a revenue synergy. Trap cost: no cost is being eliminated here. Trap tax: nothing about tax structure changed. Trap financing: this is not about cheaper capital.",difficulty:"hard",topic:"Frameworks"},
  {q:"A factory misses orders during peak season but sits idle off-peak. What framing best structures the fix?",options:["Match capacity strategy to the demand profile across the year, not the average","Cut total annual capacity to the yearly average","Add permanent capacity sized to the single peak day","Smooth nothing and accept lost peak orders as fixed"],correct:0,explanation:"The issue is the shape of demand over time, so the structure is matching capacity strategy to that profile, for example flexing or pre-building. Trap average-cap: sizing to the average guarantees peak shortfalls. Trap peak-day: permanent peak capacity wastes money off-peak. Trap accept-loss: treats a solvable mismatch as fixed.",difficulty:"hard",topic:"Frameworks"},
  {q:"Two options are scored 1 to 10 on growth (weight 60%) and risk-adjusted return (weight 40%). Option A: growth 8, return 5. Option B: growth 6, return 9. Which wins on the weighted score?",options:["A wins on raw growth, 8 versus 6","B wins, 7.2 versus 6.8","They tie at 7.0","A wins, 6.8 versus 7.2"],correct:1,explanation:"A = 0.6x8 + 0.4x5 = 4.8 + 2.0 = 6.8; B = 0.6x6 + 0.4x9 = 3.6 + 3.6 = 7.2, so B wins. Trap raw-growth: compared growth only and ignored the weights. Trap A-wins: applied the scores to the wrong options. Trap tie: averaged without weights.",difficulty:"hard",topic:"Frameworks"},
  {q:"An analyst's hypothesis is that a price cut will lift profit. To structure the test rigorously, what must the analysis include?",options:["A survey asking customers if they like lower prices","Only past cases where price cuts raised profit","The competitor's marketing budget","The volume increase needed just to offset the lower margin per unit"],correct:3,explanation:"A rigorous test computes the breakeven volume lift required to offset the thinner per-unit margin, the falsifiable bar. Trap only-success-cases: cherry-picking confirming cases is confirmation bias. Trap like-lower-prices: everyone likes lower prices; it does not test profit. Trap competitor-budget: not the mechanism linking price to this firm's profit.",difficulty:"hard",topic:"Frameworks"},
  {q:"A CEO asks for your recommendation on whether to enter Brazil. What is the best way to open your answer?",options:["Describe the data sources and methodology you used","Walk through your full analysis chronologically, then conclude","Ask the CEO what they are hoping to hear before answering","State the recommendation first, then give the two or three reasons"],correct:3,explanation:"Executive communication is answer-first: lead with the recommendation, then support it. Trap chronological: burying the answer makes a busy executive wait. Trap methodology-first: process is supporting detail, not the headline. Trap ask-back: that signals you lack a view and invites bias.",difficulty:"hard",topic:"Communication"},
  {q:"Which slide title is a proper action title rather than a topic label?",options:["Cutting the bottom three SKUs lifts margin 4 points with no volume loss","Overview of product portfolio","SKU profitability analysis","Margins by product line"],correct:0,explanation:"An action title states the insight and the so-what in a full sentence. Trap SKU-analysis: a topic label with no message. Trap overview: a label, not a takeaway. Trap margins-by-line: describes the chart, not the conclusion.",difficulty:"hard",topic:"Communication"},
  {q:"A manager asks you to synthesize five interviews, not summarize them. What does that require?",options:["Report the average sentiment across the five","List each interview's main points in order","Quote the most senior interviewee at length","Draw the cross-cutting implication the interviews point to together"],correct:3,explanation:"Synthesis means combining inputs into a single higher-order insight, not restating them. Trap list-each: that is a summary, not a synthesis. Trap quote-senior: privileging one voice is neither. Trap average-sentiment: a sentiment score is not an implication.",difficulty:"hard",topic:"Communication"},
  {q:"You show a chart where Region A's cost-to-serve is double the others. A partner asks 'so what?' What is the strongest response?",options:["Reallocating service spend away from Region A could free margin to redeploy","Region A has always been our largest region","The chart uses last quarter's actuals","We can make the bars a clearer color"],correct:0,explanation:"The so-what links the data point to an action or implication for the client. Trap actuals: that describes the data, not its meaning. Trap always-largest: context without an implication. Trap bar-color: a formatting comment, not an answer.",difficulty:"hard",topic:"Communication"},
  {q:"Your recommendation rests on one estimate you are only moderately confident in. How should you present it?",options:["Bury the weak assumption in an appendix footnote","Withhold the recommendation until the estimate is certain","Present it as a certainty to project confidence","Give the recommendation, then state the key assumption and how sensitive the call is to it"],correct:3,explanation:"Honest executive communication states the call plus the assumption it hinges on and the sensitivity. Trap false-certainty: overstating confidence erodes trust when it breaks. Trap bury-it: hiding the load-bearing assumption is misleading. Trap withhold: decisions rarely wait for certainty, and a caveated view is more useful.",difficulty:"hard",topic:"Communication"},
  {q:"The same finding goes to a CFO and to a frontline operations lead. How should the message differ?",options:["Use more charts for the CFO and more text for ops","Give the CFO more slides and the ops lead fewer","Frame the CFO version around financial impact and the ops version around process changes","Send both audiences the identical full deck"],correct:2,explanation:"Tailoring means matching the cut of the message to each audience's decisions: dollars for the CFO, workflow for ops. Trap identical: ignores that they act on different levers. Trap slide-count: volume is not relevance. Trap charts-vs-text: format is secondary to which implication each cares about.",difficulty:"hard",topic:"Communication"},
  {q:"A skeptical executive challenges your number mid-presentation. What is the most effective immediate move?",options:["Concede the point and drop the recommendation","Defend the number firmly and move on to the next slide","Acknowledge the concern, restate the assumption behind the number, and offer to verify the input","Tell the executive the model is too complex to explain"],correct:2,explanation:"Engaging the substance, naming the assumption, and offering to check it preserves both credibility and the relationship. Trap defend-and-move: dismissing the concern reads as defensive. Trap concede-all: caving on a sound number is overcorrection. Trap too-complex: signals you cannot stand behind your own work.",difficulty:"hard",topic:"Communication"},
  {q:"In a well-built deck, what should be true of the slide titles read in sequence on their own?",options:["They should tell the complete storyline without the bodies","They should repeat the section header","They should each name the chart type used","They should pose a question answered on the next slide"],correct:0,explanation:"Strong action titles read top to bottom should narrate the full argument by themselves. Trap chart-type: titles carry the message, not the format. Trap repeat-header: redundant titles add nothing. Trap pose-questions: titles assert conclusions, they do not defer them.",difficulty:"hard",topic:"Communication"},
  {q:"You email a partner an update on a stalled workstream. Where should the key ask go?",options:["In the first line, stated as a specific request with a deadline","In a closing paragraph after the full background","Split across several sentences so it feels collaborative","Implied through context so you do not seem pushy"],correct:0,explanation:"Bottom line up front: the ask leads so a busy reader sees it immediately. Trap closing: a buried ask is often missed. Trap implied: vague asks do not get actioned. Trap split-up: scattering the request weakens it.",difficulty:"hard",topic:"Communication"},
  {q:"Which recommendation statement is strongest for an executive audience?",options:["Consider whether exiting some segments might help margins","Exit the low-margin segment to recover about $12M in operating profit within a year","The low-margin segment is something to think about exiting","We should probably exit the segment that is not doing well"],correct:1,explanation:"A strong recommendation is specific, quantified, and time-bound. Trap probably: vague and hedged. Trap consider-whether: poses a question instead of recommending. Trap think-about: noncommittal and unquantified.",difficulty:"hard",topic:"Communication"},
  {q:"A draft slide makes four separate arguments with four charts. What is the cleanest fix?",options:["Add a long caption explaining all four at once","Split it so each slide carries one message tied to one chart","Keep all four but bold the most important one","Shrink all four charts to fit them more neatly"],correct:1,explanation:"One message per slide keeps the storyline crisp and scannable. Trap shrink: cramming hurts readability without fixing the overload. Trap long-caption: dense text does not resolve four competing messages. Trap bold-one: still leaves three distractions on the slide.",difficulty:"hard",topic:"Communication"},
  {q:"A partner asks 'Should we raise prices, yes or no?' How should you respond?",options:["Turn it back and ask what the partner prefers","Explain the full pricing analysis before committing either way","Give the yes or no first, then the one or two conditions behind it","Say it depends and list every factor you considered"],correct:2,explanation:"A direct question gets a direct answer first, with the key conditions attached. Trap full-analysis-first: makes the partner wait for the answer they asked for. Trap it-depends-list: dodges the question. Trap turn-it-back: avoids taking a position.",difficulty:"hard",topic:"Communication"},
  {q:"In a steering meeting the client keeps raising an off-topic complaint. What is the best facilitation move?",options:["Tell the client the topic is not important right now","Ignore the complaint and continue your slides","Let the discussion run wherever the client takes it","Acknowledge it, park it on a visible list, and steer back to the agenda"],correct:3,explanation:"Acknowledging and parking the item respects the client while protecting the agenda. Trap let-run: loses control of a time-boxed meeting. Trap ignore: makes the client feel unheard. Trap dismiss: bluntly calling it unimportant damages the relationship.",difficulty:"hard",topic:"Communication"},
  {q:"An executive summary slide currently has nine bullet points of detail. What best improves it?",options:["Keep all nine but use a smaller font","Convert all nine bullets into one paragraph","Reduce to the three points that drive the decision and move the rest to backup","Add a tenth bullet summarizing the other nine"],correct:2,explanation:"An executive summary should surface only the decision-relevant points and relegate detail to backup. Trap paragraph: dense prose is harder to scan than focused bullets. Trap smaller-font: that hides the overload rather than fixing it. Trap tenth-bullet: adds content instead of cutting it.",difficulty:"hard",topic:"Communication"},
  {q:"You want to convey that a $4M saving matters. Which framing lands best with an executive?",options:["The saving has seven figures","The saving is a large number","The saving is four million dollars","The $4M saving equals about 8% of last year's operating profit"],correct:3,explanation:"Anchoring a number to a familiar base, here as a share of profit, conveys significance. Trap raw-number: a figure with no reference point is hard to judge. Trap large-number: vague qualifier. Trap seven-figures: technically true but uninformative about impact.",difficulty:"hard",topic:"Communication"},
  {q:"A junior asks how to handle a data gap when the client expects an answer. What is the best guidance?",options:["Give a very wide range so you are never wrong","State the best current estimate, flag the gap, and give the range it could move","Present a single point estimate as if the gap did not exist","Refuse to give any number until the gap is closed"],correct:1,explanation:"Good practice gives a usable estimate, names the gap, and bounds the uncertainty. Trap hide-gap: false precision misleads the client. Trap refuse: leaves the client with nothing actionable. Trap very-wide: a uselessly wide range avoids accountability rather than informing.",difficulty:"hard",topic:"Communication"}
];

